-- Poems batch 163
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d2f74dd7-2f2f-40b9-bab4-ac5c71901c95','送鄭尚書守建安十首  其六','彭龜年','宋','宋诗','song-poetry','','[]','直節亭亭屹不流，沖然襟度更休休。',32,'全唐诗/poet.song.162000.json','["直節亭亭屹不流，沖然襟度更休休。", "世間多少難平事，可惜先生不少留。"]'),
('55df4664-5023-49cc-9455-a293a0c02348','送鄭尚書守建安十首  其七','彭龜年','宋','宋诗','song-poetry','','[]','東西一節大江邊，來往勤民亦有年。',32,'全唐诗/poet.song.162000.json','["東西一節大江邊，來往勤民亦有年。", "未必米鹽勞試守，更從根本得深研。"]'),
('b00acd63-4929-4ff4-8169-187008d2b71f','送鄭尚書守建安十首  其八','彭龜年','宋','宋诗','song-poetry','','[]','從此褰帷去帝鄉，閭閻辛苦足平章。',32,'全唐诗/poet.song.162000.json','["從此褰帷去帝鄉，閭閻辛苦足平章。", "皂囊若有新豐奏，纔過龍團第一綱。"]'),
('be5d23b3-9ed5-4365-b1d3-f75bc0789ce2','送鄭尚書守建安十首  其九','彭龜年','宋','宋诗','song-poetry','','[]','革履如今遠帝廬，眼前憂念總區區。',32,'全唐诗/poet.song.163000.json','["革履如今遠帝廬，眼前憂念總區區。", "黄鐘一氣元來在，安得先生起亞夫。"]'),
('fefffa39-c79a-46e4-a710-92a5985f24f3','送鄭尚書守建安十首  其一○','彭龜年','宋','宋诗','song-poetry','','[]','好風佳月滿襟懷，嘗到先生丈室來。',32,'全唐诗/poet.song.163000.json','["好風佳月滿襟懷，嘗到先生丈室來。", "今日忽爲江海別，此心肯逐晚潮回。"]'),
('4c0cde54-22be-435b-ab04-e722fa16d3e1','和張憲吳園山居二首  其一','彭龜年','宋','宋诗','song-poetry','','[]','輕辭綠野逐征夫，踏遍溪山總不如。',32,'全唐诗/poet.song.163000.json','["輕辭綠野逐征夫，踏遍溪山總不如。", "莫愛畫圖嘗在眼，渠儂還亦愛吾廬。"]'),
('79f7296f-5e5c-4900-9b28-ecb7f078eda8','和張憲吳園山居二首  其二','彭龜年','宋','宋诗','song-poetry','','[]','參天喬木鎮山川，栽種成陰知幾年。',32,'全唐诗/poet.song.163000.json','["參天喬木鎮山川，栽種成陰知幾年。", "仰止名園今老矣，卷舒畫軸思悠然。"]'),
('d7573ede-cf80-4e1a-a9cd-c5b799627e4c','和向大夫坐韻','彭龜年','宋','宋诗','song-poetry','','[]','道義交情不用盟，鳴謙肯作震雷驚。',32,'全唐诗/poet.song.163000.json','["道義交情不用盟，鳴謙肯作震雷驚。", "論功平勃非吾事，付與人間仔細評。"]'),
('09fbb051-c187-42d6-9ed7-fbb6eb32a216','謝劉大權爲壽','彭龜年','宋','宋诗','song-poetry','','[]','涼月紛紛弄綵衣，桑弧蓬矢拂庭闈。',32,'全唐诗/poet.song.163000.json','["涼月紛紛弄綵衣，桑弧蓬矢拂庭闈。", "不因妙語從君得，何事茅簷星斗稀。"]'),
('4e602f3a-24d1-4c76-88c8-ae606e12127e','壽張京尹十首  其一','彭龜年','宋','宋诗','song-poetry','','[]','岷山斗險介巴江，天地精神此晦藏。',32,'全唐诗/poet.song.163000.json','["岷山斗險介巴江，天地精神此晦藏。", "已發峨眉清一段，公家父子又相望。"]'),
('97389bdc-3a81-40c2-b8f0-badd4a9b99a3','壽張京尹十首  其二','彭龜年','宋','宋诗','song-poetry','','[]','盡心堂上得心傳，妙處機緘共一天。',32,'全唐诗/poet.song.163000.json','["盡心堂上得心傳，妙處機緘共一天。", "玉骨冰姿更相似，黑頭只欠著貂蟬。"]'),
('cdf3414c-27a9-4b68-82e1-e077cb97d8ec','壽張京尹十首  其三','彭龜年','宋','宋诗','song-poetry','','[]','四百山河朝帝京，紫巖有志未全伸。',32,'全唐诗/poet.song.163000.json','["四百山河朝帝京，紫巖有志未全伸。", "知公久抱中原略，日日搜羅度外人。"]'),
('7e603546-0af8-4f2a-a494-61ca7534f5a9','壽張京尹十首  其四','彭龜年','宋','宋诗','song-poetry','','[]','納湖千頃自源流，淡淡春風百尺樓。',32,'全唐诗/poet.song.163000.json','["納湖千頃自源流，淡淡春風百尺樓。", "盡出詩書到功業，只今天下矚君侯。"]'),
('f5e7a648-0c74-4a07-8cdc-6356d4e2f9f1','壽張京尹十首  其五','彭龜年','宋','宋诗','song-poetry','','[]','天府何爲屈我公，謾將煩處壓才雄。',32,'全唐诗/poet.song.163000.json','["天府何爲屈我公，謾將煩處壓才雄。", "若兼二輔亦可了，萬化斡旋猶有功。"]'),
('c67c0a3a-d363-4ba1-82f7-6987429b51fd','壽張京尹十首  其六','彭龜年','宋','宋诗','song-poetry','','[]','彈壓殊非翼翼商，藉公惠養破天荒。',32,'全唐诗/poet.song.163000.json','["彈壓殊非翼翼商，藉公惠養破天荒。", "從今若說京都政，不數前張數後張。"]'),
('3bfa30a7-004d-4d8c-a429-452c948f4772','壽張京尹十首  其七','彭龜年','宋','宋诗','song-poetry','','[]','湖面撥開雙眼翳，湖頭拔立一堤金。',32,'全唐诗/poet.song.163000.json','["湖面撥開雙眼翳，湖頭拔立一堤金。", "先生能事真如此，捍滌羣邪即此心。"]'),
('873f1c1c-7305-4ab2-8d21-611605909c32','壽張京尹十首  其八','彭龜年','宋','宋诗','song-poetry','','[]','翁兒一笑大歡足，雞犬不驚仁意多。',32,'全唐诗/poet.song.163000.json','["翁兒一笑大歡足，雞犬不驚仁意多。", "欲得使君真實諦，直須堂外識中和。"]'),
('79ab0530-dfee-4669-a622-da92edd46789','壽張京尹十首  其九','彭龜年','宋','宋诗','song-poetry','','[]','鯫生何幸倚門牆，千里崎嶇入帝鄉。',32,'全唐诗/poet.song.163000.json','["鯫生何幸倚門牆，千里崎嶇入帝鄉。", "贏得菊花𣂏壽酒，今年又近一重陽。"]'),
('409bb961-22c5-40ef-9f7d-aa0ac849a1e3','壽張京尹十首  其一○','彭龜年','宋','宋诗','song-poetry','','[]','欲頌公侯學魯人，怕衝大尹罷長吟。',32,'全唐诗/poet.song.163000.json','["欲頌公侯學魯人，怕衝大尹罷長吟。", "亦知已有長生訣，四益齋中四益箴。"]'),
('1667d598-d02f-43db-ba19-9f42b298d685','爲張氏題秀盤閣','彭龜年','宋','宋诗','song-poetry','','[]','扶輿磅礴滿清虛，未必山川獨有餘。',32,'全唐诗/poet.song.163000.json','["扶輿磅礴滿清虛，未必山川獨有餘。", "欲識秀盤無盡處，吟風弄月得吾初。"]'),
('599f90fd-d32c-4258-aa13-1a0cba14e85b','王文伯將校藝漕闈過我取別肯作一夕飲酒竟猶子留之西齋厥明文伯有詩敬賡原韻','彭龜年','宋','宋诗','song-poetry','','[]','已聞鼓篋無秦銳，肯爲論文學賈留。',32,'全唐诗/poet.song.163000.json','["已聞鼓篋無秦銳，肯爲論文學賈留。", "奪我清風俄頃爾，夢回真若隔三秋。"]'),
('1c26a1c0-88e6-4067-8dd6-fef2b8a84b4f','劉宗元索余賦愚谷古人以愚自命及命人者多矣余不暇辨姑以二絕言愚之理云  其一','彭龜年','宋','宋诗','song-poetry','','[]','以愚名谷意何如，肯以愚溪認作吾。',32,'全唐诗/poet.song.163000.json','["以愚名谷意何如，肯以愚溪認作吾。", "天地中間有真我，蕭然陋巷不關渠。"]'),
('1830ca26-19f3-4740-9aee-49b4b515501a','劉宗元索余賦愚谷古人以愚自命及命人者多矣余不暇辨姑以二絕言愚之理云  其二','彭龜年','宋','宋诗','song-poetry','','[]','命谷爲愚谷曰愚，人心難似谷心虛。',32,'全唐诗/poet.song.163000.json','["命谷爲愚谷曰愚，人心難似谷心虛。", "夫君若踏歸愚路，坐斷人間毀與譽。"]'),
('5eb72020-daf1-4b24-abb9-37bd75f4c8ee','送徐仲洪尉南安八首  其一','彭龜年','宋','宋诗','song-poetry','','[]','仲洪作尉南安縣，示我西園藥石辭。',32,'全唐诗/poet.song.163000.json','["仲洪作尉南安縣，示我西園藥石辭。", "莫道近民民易擾，官清民近更相宜。"]'),
('bb2f291a-aeae-4879-89c0-58b3ac95e03d','送徐仲洪尉南安八首  其二','彭龜年','宋','宋诗','song-poetry','','[]','聖朝寬令捷驚霆，尉不留心竟不行。',32,'全唐诗/poet.song.163000.json','["聖朝寬令捷驚霆，尉不留心竟不行。", "萬事闓端皆在我，安危便可到蒼生。"]'),
('f9d77d79-c515-4ef6-9057-8e274304eb9d','送徐仲洪尉南安八首  其三','彭龜年','宋','宋诗','song-poetry','','[]','催科莫作擾人看，趁此登場早了官。',32,'全唐诗/poet.song.163000.json','["催科莫作擾人看，趁此登場早了官。", "坐視貪殘敗吾子，不如自放一分寬。"]'),
('bbcebb79-f867-480e-9ff9-5df4b391d686','送徐仲洪尉南安八首  其四','彭龜年','宋','宋诗','song-poetry','','[]','若見村中小校師，教將義理訓童兒。',32,'全唐诗/poet.song.163000.json','["若見村中小校師，教將義理訓童兒。", "四端五品人人有，莫道冥頑不與知。"]'),
('fd0ce006-a04a-40a7-9d46-352f2b78a256','送徐仲洪尉南安八首  其五','彭龜年','宋','宋诗','song-poetry','','[]','椎牛酌酒是民頑，明約科條墟里間。',32,'全唐诗/poet.song.163000.json','["椎牛酌酒是民頑，明約科條墟里間。", "若更寬他衣食路，桑間陌上自閑閑。"]'),
('e06d78bf-36d6-4ba7-b602-d89d7d8ee1dc','送徐仲洪尉南安八首  其六','彭龜年','宋','宋诗','song-poetry','','[]','血氣誰無未免爭，腰牛公牘角蝸情。',32,'全唐诗/poet.song.163000.json','["血氣誰無未免爭，腰牛公牘角蝸情。", "半非半是先須識，但要吾心似水平。"]'),
('6758e6f6-038a-4b94-9eeb-2ce39e28913f','送徐仲洪尉南安八首  其七','彭龜年','宋','宋诗','song-poetry','','[]','作尉之難似胗尸，一生一死總吾爲。',32,'全唐诗/poet.song.163000.json','["作尉之難似胗尸，一生一死總吾爲。", "是心倘有分毫歉，脫手翻車悔莫追。"]'),
('7bac612d-5d03-4bc1-9550-7dd857dfc275','送徐仲洪尉南安八首  其八','彭龜年','宋','宋诗','song-poetry','','[]','手弓皆是虎狼才，巡徼寧無去復來。',32,'全唐诗/poet.song.163000.json','["手弓皆是虎狼才，巡徼寧無去復來。", "倏去倏來無滯迹，蝗螟雖過不爲災。"]'),
('f6acc552-0751-4f13-bb1c-9718b8550a8e','盆花示兒','彭龜年','宋','宋诗','song-poetry','','[]','群兒愛盆花，如我愛其子。',48,'全唐诗/poet.song.163000.json','["群兒愛盆花，如我愛其子。", "但將養花心，委曲求諸己。", "花不負人力，隨時深淺紅。", "種學得如此，豈不慰乃翁。"]'),
('4a5c49c6-1768-47ad-a19f-0bd9e838d7fd','紹興淳熙兩朝內禪頌','曾丰','宋','宋诗','song-poetry','','[]','維堯則天，與天同大。',240,'全唐诗/poet.song.163000.json','["維堯則天，與天同大。", "俯視九州，細於一芥。", "挈以畀舜，超然自邁。", "維舜則堯，與堯同高。", "俯視四海，細于一毫。", "挈以畀禹，熙然自陶。", "堯舜之禪，允矣嘉躅。", "若稽厥齡，或髦攸趣。", "洪惟高宗，纔五十六。", "遽行堯事，有斷於獨。", "洪惟壽皇，纔六十三。", "遽行舜事，不謀于僉。", "未倦于勤，先養其恬。", "功成身退，道與天參。", "聖人視天，遞進遞退。", "進退俱休，堯舜之運。", "於赫兩朝，德宏業峻。", "銖較寸量，寧啻堯舜。", "堯七十六，治水云初。", "咨岳試鯀，不遑寧居。", "高宗時則，斯慶壽餘。", "久與道息，心實若虛。", "舜六十三，即真云始。", "咨岳相禹，不遑寧止。"]'),
('c46822df-eb85-4295-b2ff-5bd56be19145','修文立武頌  其一','曾丰','宋','宋诗','song-poetry','','[]','斌哉公兮。',86,'全唐诗/poet.song.163000.json','["斌哉公兮。", "丁黎牾兮，反自捬兮。", "亶元后天覆無我若汝兮，董爾僚釐吾天序兮。", "九法茂茂勃其豎兮，誰又我𧣒兮。", "爾校傳相驩，勿闡而㿪兮，勿䦱而靬兮，勿闓而簍韔靫韊兮。", "逡其虎賁以自媻兮。"]'),
('0ea2d0f0-189a-462f-a451-bc733ecce4e1','修文立武頌  其二','曾丰','宋','宋诗','song-poetry','','[]','斌哉公兮。',92,'全唐诗/poet.song.163000.json','["斌哉公兮。", "丁黎狺兮，反自揗兮。", "亶元老地載無我若人兮，麾爾校迪吾天倫兮。", "三綱几几廩其敶兮，誰又我{門賓}兮。", "爾黎傳相告，勿攄而韣兮，勿抉而箙兮，勿掀而鞬䡬㣂{𥫗椂}兮。", "逶其螘潰以自宓兮。"]'),
('23388d81-0689-4930-a8ed-b5271ea63c10','修文立武頌  其三','曾丰','宋','宋诗','song-poetry','','[]','斌哉公兮。',86,'全唐诗/poet.song.163000.json','["斌哉公兮。", "丁黎䍴兮，反自揆兮，亶元戎海涵無我若爾兮，格爾黎寤吾天理兮。", "五常炳炳劼其履兮，誰又我觝兮。", "吾伍傳相號，勿袖而弢兮，勿繟而轑兮，勿紓而醫韘皾櫜兮。", "逛其虻附以自陶兮。"]'),
('bf17aacc-5402-48dc-b6ac-af1cda4d83ae','祀蠶先','曾丰','宋','宋诗','song-poetry','','[]','旦穀兮辰剛，聿蠲衷兮齋以莊。',320,'全唐诗/poet.song.163000.json','["旦穀兮辰剛，聿蠲衷兮齋以莊。", "孔傴兮再拜，擎厥拳兮三迎將。", "飛廉掃兮涴者以清，赤松灑兮溽者以凉。", "靈之來，嫖嫖兮若翔兮上。", "靈之下，婉婉兮若倚兮傍。", "靈之趨，躞躞兮若參兮前。", "靈之坐，盤盤兮若據兮中央。", "廼陳兮太牢，侑以兮糜餹。", "糕柔兮膋肉，腯鼠腦脆兮糜薌。", "靈其肸只，勿虛我佖只。", "世傳沙宅兮亥地，泥屋兮壬方。", "棗種兮南舍，風來兮東廂。", "夫是謂兮宜蠶徵，其如我教兮未詳。", "顧蠶兮消長，惟靈兮弛張。", "紛再登三熟與四出，信吉利而蓋故常。", "雅志兮蠶事，匪徒製兮已之裝。", "絲吾欲繫象兮俾不折，繭吾欲投火兮俾不傷。", "于以試兮允哉驗，殆將補兮舜裳。", "靈其烱只，勿虛我景只，蛹有種，蛾有秧。", "圓嶠兮色黑，寒國兮色蒼。", "絲一指兮大，繭一尺兮長。", "蠶有兮彼異，何當畀兮千斯箱。", "靈其攸只，勿虛我企只。"]'),
('4e3fc8f6-78f7-40c2-8fbd-71de548961e2','乞如願','曾丰','宋','宋诗','song-poetry','','[]','曰來紫姑，噦甘有兮松醽，糅以兮膠餳。',278,'全唐诗/poet.song.163000.json','["曰來紫姑，噦甘有兮松醽，糅以兮膠餳。", "紫姑來下肸余馨。", "噦辛有兮椒醁，糅以兮葱𩛺，紫姑來下肸余馥。", "噦淡有兮桃醾，糅以兮柏飴。", "紫姑來下肸予馡。", "噦三薰兮三酹，夫有懇兮其敢昧。", "久求如願兮，顧茲在幾爲余兮割愛。", "噦來紫姑，伊嫠且羣。", "噦凡借顔色，饒髭鬚。", "噦厥有李赤豫讓范雎。", "噦若迺鬼殘，彼非刑餘。", "噦彼所有若所無，緩急自可相須。", "噦詎必如願，而弗以乞余。", "噦羌紫姑，形不露脰而有影若拇，殆余授邪。", "噦羌如願，聲不露噣而有響若吽，殆余扣邪。", "公其願貴，或願富邪。", "貴豈能玉余骨使莫腐，富豈能冰余肉使莫臭邪。", "文章可傳，金石不朽。", "要責其精，須遲以久。", "余心所願，汝假之壽。", "應聲莽鹵，似曰有有。"]'),
('bb6cc390-9614-4030-a31a-da5fdd3f2afa','祀南海神','曾丰','宋','宋诗','song-poetry','','[]','赤精炎官兮，神一靈兮幻只。',201,'全唐诗/poet.song.163000.json','["赤精炎官兮，神一靈兮幻只。", "鴻澤厖施兮，神一念兮肧只。", "上清委照兮，神功行兮簡只。", "浩劫彌沙兮，神慶休兮綿只。", "太虛窈窕兮，神徜徉兮栖只。", "瀕海渺瀰兮，神漫浪兮僑只。", "沆瀣溟涬兮，神固自兮飫只。", "肥腯芬薌兮，神孰何兮肸只。", "昏頓顓冥兮，神惻怛兮矜只。", "顛連號呼兮，神恍惚兮聳只。", "焄蒿悽愴兮，神憑憑兮下只。", "狎猥媟嬻兮，神恢恢兮涵只。", "讄曰蒙以兮景只，有嘉斯肴兮羅只，有旨斯醑兮酹只。", "神兮歆只，有皎斯衷兮監只，有蹇斯數兮翊只。"]'),
('7f9c4fa2-1697-46dd-b7ce-2bdd950837c8','灕之水  其一','曾丰','宋','宋诗','song-poetry','','[]','灕之水浮兮，粗資以汰。',44,'全唐诗/poet.song.163000.json','["灕之水浮兮，粗資以汰。", "灕之水激兮，頑資以淬。", "灕之水清兮，垢資以灑。", "灕之水潤兮，槁資以溉。"]'),
('5e5f7ee0-76df-4bd3-ae96-9403f1301733','灕之水  其二','曾丰','宋','宋诗','song-poetry','','[]','灕者離也，胡離乎東而西其會。',39,'全唐诗/poet.song.163000.json','["灕者離也，胡離乎東而西其會。", "永言西大，不渤而匯。", "靡資弗沛，四有一逮。", "亦孔之快。"]'),
('306a0547-5a81-4701-8e8d-3229293aa416','灕之水  其三','曾丰','宋','宋诗','song-poetry','','[]','灕者離也，胡離乎西而東其邁。',39,'全唐诗/poet.song.163000.json','["灕者離也，胡離乎西而東其邁。", "永言西隘，不颶而瀨。", "靡資弗礙，四無一逮。", "亦孔之慨。"]'),
('ab9a60a7-fef7-4131-bca8-637151603886','灕之水  其四','曾丰','宋','宋诗','song-poetry','','[]','逮固罔功，不逮寧罔罪。',54,'全唐诗/poet.song.163000.json','["逮固罔功，不逮寧罔罪。", "誰謂匪詿，又誰謂無悔。", "離哉離哉，固云㣻哉，寧固云憝哉。", "離哉離哉，固云夬哉，寧固云駾哉。"]'),
('5cd3dfa2-f09e-41b2-b574-f2bcdb0b1413','我歸遭雨  其一','曾丰','宋','宋诗','song-poetry','','[]','莫予我食，食于公庾。',22,'全唐诗/poet.song.163000.json','["莫予我食，食于公庾。", "我歸遭雨，我不以爲苦也。"]'),
('54dca21f-631f-4323-a241-36068f1e9ec7','我歸遭雨  其二','曾丰','宋','宋诗','song-poetry','','[]','莫予我衣，衣于公府。',22,'全唐诗/poet.song.163000.json','["莫予我衣，衣于公府。", "我歸遭雨，我不以爲苦也。"]'),
('cab21e6e-9cd9-4ba0-b24e-ee4cf5073362','我歸遭雨  其三','曾丰','宋','宋诗','song-poetry','','[]','莫予我居，居于公宇。',22,'全唐诗/poet.song.163000.json','["莫予我居，居于公宇。", "我歸遭雨，我不以爲苦也。"]'),
('c33e2df5-b663-4dce-9e8c-bf70f21c267e','九月  其一','曾丰','宋','宋诗','song-poetry','','[]','九月庚庚，金風䬝䬝。',60,'全唐诗/poet.song.163000.json','["九月庚庚，金風䬝䬝。", "菊之有之，强名金精。", "九月庚庚，玉露泠泠。", "菊之有之，强名玉英。", "精英爲菊，薄畀其贏。", "公于精英，裒其大成。"]'),
('8fc072ae-6f3e-4f28-852e-5c72b54ac654','九月  其二','曾丰','宋','宋诗','song-poetry','','[]','精英攸結，霜莫之折。',82,'全唐诗/poet.song.163000.json','["精英攸結，霜莫之折。", "小字女節，公生烈烈。", "精英攸凝，霜莫之陵。", "小字女莖，公生亭亭。", "女莖曰咄，挺其自拔。", "涵濡天渥，吾不如女葉。", "女葉曰嗟，偃其自奢。", "漸寖天和，吾不如女華。"]'),
('5b0a013d-ccc8-423f-a77c-020837d88770','九月  其三','曾丰','宋','宋诗','song-poetry','','[]','彼女華者，有都其色。',60,'全唐诗/poet.song.163000.json','["彼女華者，有都其色。", "公所養兮，亦孔之澤。", "彼女華者，有都其香。", "公所立兮，亦孔之芳。", "彼女華者，有都其味。", "公所調兮，亦孔之旨。"]'),
('7f2cd9df-3a98-4e85-b12b-d7e1f5cc8273','九月  其四','曾丰','宋','宋诗','song-poetry','','[]','八月擷葵，十月擷梨。',70,'全唐诗/poet.song.163000.json','["八月擷葵，十月擷梨。", "匪蚤伊遲，菊在中兮，有神有奇。", "于以却艾，寧復云耆。", "八月擷棗，十月擷稻。", "匪遲伊蚤，菊在中兮，有化有造。", "于以却老，寧復云耄。"]'),
('72987bb2-458e-47ec-8255-c4350e8f0caa','九月  其五','曾丰','宋','宋诗','song-poetry','','[]','既浣之後，未望之先。',105,'全唐诗/poet.song.163000.json','["既浣之後，未望之先。", "有誕初辰，有秩初筵。", "公呼子孫，爾來吾前。", "有觴弗他酭，維菊可以酒，飲之長壽。", "有釜勿他烹，惟菊可以羹，餐之長生。", "飲少輒酣，餐少輒飫。", "公舉其步，謂殆神助。", "客攬其履，謂殆仙去。", "惠然肯留，永爲國之柱。"]'),
('4d06b23f-b187-4596-a589-dac23683dda1','有粲','曾丰','宋','宋诗','song-poetry','','[]','春風穆穆，有粲若鋈。',258,'全唐诗/poet.song.163000.json','["春風穆穆，有粲若鋈。", "獨出者英，既亭既矗。", "孰刻之玉，公旰翫兮忘𩛺。", "春雨涔涔，有粲若琳。", "八出者須，既挺既參，孰刻之金，公旰玩兮忘簪。", "八表一裏，蓋九疇云爾。", "英須如之，亦孔之𧁼。", "一中八邊，蓋九州云然。", "英須如之，亦孔之葏。", "九疇之中，屹其皇極。", "彼孔𧁼兮，中兮若屹。", "九州之中，巋其王畿。", "彼孔葏兮，中兮獨巋。", "中者得所，旁者得侶。", "主董其臣，臣扈其主。", "它華豈不須，莫如此都。", "與天地合，自然之符。", "它花豈不蕊，莫如此微。", "與天地合，自然之禮。", "游仙感止，心兮朝真。", "游貴感止，心兮拱辰。", "天予平園，仙愛之瑛。", "英左英右，幾須卓立。", "公豈不懷，嚮爲輔弼。"]'),
('933cdab7-584b-4a90-912d-81d1eb53272d','愛山堂','曾丰','宋','宋诗','song-poetry','','[]','芙蓉居右，華蓋居後。',167,'全唐诗/poet.song.163000.json','["芙蓉居右，華蓋居後。", "象居其間，不幾培塿。", "爰架余宮，爰栖余蹤。", "坐而睨之，主卑客崇。", "卑者當足，崇者當目。", "崇卑不同，余却得象之精，忘象之形。", "築堂對象，拔翠橫青。", "有粲兮色，有涵兮德。", "柳下之介，伯夷之特。", "顔之坐忘，孔之屏息。", "彼混莫倫，余配以仁。", "彼矯莫親，余交以神。", "無彼無此，孰主孰賓。", "余愛之溺，孰不云癖。", "象山難忘，道山可易。", "於彼游心，于此掃跡。"]'),
('21c39b54-dd64-4160-96ca-97bc6ae8f2f6','南有刺  其一','曾丰','宋','宋诗','song-poetry','','[]','南有刺蓐，又有刺竹。',80,'全唐诗/poet.song.163000.json','["南有刺蓐，又有刺竹。", "有刺竹矣，無刺蓐矣。", "彼竹何族，有刺如簇。", "蹴之者瘃，天委彼酷。", "誰使爾蹴，爾瘃誰讟。", "達者蹈足，恚者仄目。", "斧斤俶俶，自貽伊蝮。", "天道好復，况利于竹。"]'),
('f69bd9de-e901-41cb-a493-193e59385c42','南有刺  其二','曾丰','宋','宋诗','song-poetry','','[]','南有刺竹，又有刺木。',80,'全唐诗/poet.song.163000.json','["南有刺竹，又有刺木。", "有刺木矣，無刺竹矣。", "彼木何族，有刺如簇。", "觸之者衂，天委彼酷。", "誰使爾觸，爾衂誰讟。", "達者鼓腹，歜者裂肉。", "斧斤畟畟，自貽伊毒。", "天道好復，況利于木。"]'),
('fa3067eb-d652-4a8b-ae7e-954219e143cc','公之還  其一','曾丰','宋','宋诗','song-poetry','','[]','公之還，謂常還兮，獨不謂公害。',123,'全唐诗/poet.song.163000.json','["公之還，謂常還兮，獨不謂公害。", "著儒冠，學其籋矣，于聖之關。", "仕其簉矣，于鼂之耑。", "孰驅我牡，兀淛之湍。", "孰駕我熊，兀桂之岏。", "交中互外，迭來更繁。", "壹心苦力，幾暑且寒。", "于何景遠，于此懷安。", "四三皇王，效何當完。", "九八元凱，志若爲闌。", "斯夢斯環兮，隮我閶闔之間兮。"]'),
('22860377-e985-479b-a2a7-20f4767ae741','公之還  其二','曾丰','宋','宋诗','song-poetry','','[]','公之還，謂常還兮，獨不謂公害。',113,'全唐诗/poet.song.163000.json','["公之還，謂常還兮，獨不謂公害。", "峨粵冠，上意我東，南憂誰寬。", "伊素若赤，維翰維藩。", "校妥爾寢，甿恬爾餐。", "伊碧若朱，維幢維幡。", "外藻曾幾，中渠殆單。", "肆是蠻狃，申之瘴奸。", "裏之知之，寧是弗言。", "上之聽之，寧是弗嘆。", "斯賜斯環兮，𨔤我湘漓之干兮。"]'),
('87b486c7-6615-46d5-9cda-743164185769','公之還  其三','曾丰','宋','宋诗','song-poetry','','[]','公之還，謂常還兮，獨不謂公害。',137,'全唐诗/poet.song.163000.json','["公之還，謂常還兮，獨不謂公害。", "彈鼂冠，斯傳于馹，尚行于鵷。", "何以居之，宰臣曰囏。", "豈無雞舌，輔以麋丸。", "于逶于蛇，與鼂爲羽翰。", "豈無辟水，枕以橋門。", "于𩤛于卬，與士爲芝蘭。", "天子曰咈，唯才是論。", "胡爲乎天驥，而豢之闌。", "胡爲乎隋珠，而藉之彈。", "厥居惟閌，厥立惟胖。", "斯珮斯環兮，畢我鼎彝之殘兮。"]'),
('36eb9c21-6f5c-4851-a010-21788748cc7c','公邁何遄  其一','曾丰','宋','宋诗','song-poetry','','[]','公之西矣，蜀人是謠，都人是囂。',70,'全唐诗/poet.song.163000.json','["公之西矣，蜀人是謠，都人是囂。", "詔予華衮，亟哉來朝。", "彩熊既稅，彩鷁既發。", "月逗歲遛，竣其未達。", "都人曰嘻，吾國君師。", "欲猷欲爲，未得良毗。", "公歸何遲。"]'),
('471abb1a-1bc4-4100-ae30-b2332494410e','公邁何遄  其二','曾丰','宋','宋诗','song-poetry','','[]','公之東矣，蜀人是戀，潭人是羨。',70,'全唐诗/poet.song.163000.json','["公之東矣，蜀人是戀，潭人是羨。", "詔予油幢，亟哉往殿。", "列城既傾，列騎既迎。", "日裴月徊，倘其未行。", "潭人曰噢，吾家耋孺。", "不襦不袴，莫能略顧。", "公來何暮。"]'),
('9c8de238-d4b9-489d-aa60-b32a6110492a','公邁何遄  其三','曾丰','宋','宋诗','song-poetry','','[]','公之南矣，潭人是懷，洪人是留。',70,'全唐诗/poet.song.163000.json','["公之南矣，潭人是懷，洪人是留。", "議奪朱幡，亟哉還休。", "御者既靷，餞者既輓。", "俄馳頃驅，僄其未返。", "洪人曰嘕，吾土山川。", "有真有仙，可伴長年。", "公邁何遄。"]'),
('b0a99e4c-78ec-4153-9a09-3c29186d7aa5','彼蓮之美  其一','曾丰','宋','宋诗','song-poetry','','[]','彼蓮之美，心乎愛矣。',20,'全唐诗/poet.song.163000.json','["彼蓮之美，心乎愛矣。", "所愛與直，淵乎其似。"]'),
('906b1008-5954-429d-ae36-76535be10c37','彼蓮之美  其二','曾丰','宋','宋诗','song-poetry','','[]','厥根玲瓏，庶乎屢空。',20,'全唐诗/poet.song.163000.json','["厥根玲瓏，庶乎屢空。", "厥幹洞然，同乎大通。"]'),
('91ac1aab-c51a-44be-a448-25b16ae3226a','彼蓮之美  其三','曾丰','宋','宋诗','song-poetry','','[]','厥華尚赤，故爲火德。',20,'全唐诗/poet.song.163000.json','["厥華尚赤，故爲火德。", "厥德靡常，虛室生白。"]'),
('4c9e699a-37a0-4974-945f-cfe61ba4fc5a','彼蓮之美  其四','曾丰','宋','宋诗','song-poetry','','[]','受知濂溪，愛莫助之。',20,'全唐诗/poet.song.163000.json','["受知濂溪，愛莫助之。", "鄒子知之，久而敬之。"]'),
('07041b64-f257-40e0-b939-5d5c390ee43d','明日大夫  其一','曾丰','宋','宋诗','song-poetry','','[]','明日大夫，何嘉瑞兮。',40,'全唐诗/poet.song.163000.json','["明日大夫，何嘉瑞兮。", "秋金銳兮，凉風至兮。", "公生與□，澂骨氣兮。", "寖嶷嶷然，國之器兮。"]'),
('daabb9f8-d9ca-4a10-bf11-bca4c2663f60','明日大夫  其二','曾丰','宋','宋诗','song-poetry','','[]','明日大夫，何嘉貺兮。',40,'全唐诗/poet.song.163000.json','["明日大夫，何嘉貺兮。", "老火亢兮，白露降兮。", "公生與俱，凝骨相兮。", "寖藹藹然，朝之望兮。"]'),
('c9ea5af4-1bfa-4fba-9762-b6aa0108c674','明日大夫  其三','曾丰','宋','宋诗','song-poetry','','[]','明日大夫，何日侯兮。',40,'全唐诗/poet.song.163000.json','["明日大夫，何日侯兮。", "有白其苴，男爵優兮。", "匪朝伊夕，九冕旒兮。", "功崇業廣，亙千秋兮。"]'),
('ddc24e27-e7e8-4d5d-a236-e27e9f9d0d7d','明日大夫  其四','曾丰','宋','宋诗','song-poetry','','[]','明日大夫，何日卿兮。',40,'全唐诗/poet.song.163000.json','["明日大夫，何日卿兮。", "有蒼其佩，禮官清兮。", "匪朝伊夕，九繁纓兮。", "名遂身退，綿千齡兮。"]'),
('5febe7a0-fb7a-466b-a15e-2b5d2d967bf5','今日何夕  其一','曾丰','宋','宋诗','song-poetry','','[]','今夕何夕，粲者如許。',40,'全唐诗/poet.song.163000.json','["今夕何夕，粲者如許。", "日在於參，心在於戶。", "心與火俱，火爲心主。", "老人在南，蓋得其所。"]'),
('58a2ccaa-731f-49c9-ae6b-3912bc322de2','今日何夕  其二','曾丰','宋','宋诗','song-poetry','','[]','今夕何夕，粲者如許。',40,'全唐诗/poet.song.163000.json','["今夕何夕，粲者如許。", "其月蕤賓，其日甲午。", "午與火俱，火爲午主。", "老臣在南，蓋得其侶。"]'),
('f66cb1be-5228-4c7a-99a4-e96b5485e162','今日何夕  其三','曾丰','宋','宋诗','song-poetry','','[]','今夕何夕，綿雨其零。',35,'全唐诗/poet.song.163000.json','["今夕何夕，綿雨其零。", "于昨之日，維蜩始鳴。", "有祥其聲，我國無英，我公挺生。"]'),
('3e4e9b0a-01b8-44bb-8464-abce7360848c','今日何夕  其四','曾丰','宋','宋诗','song-poetry','','[]','今夕何夕，景風其颺。',35,'全唐诗/poet.song.163000.json','["今夕何夕，景風其颺。", "于明之朝，維月既望。", "有禎其象，我后無相，我公直上。"]'),
('5d2e8a49-42ad-4083-9418-ae2602ba573c','今日何夕  其五','曾丰','宋','宋诗','song-poetry','','[]','今夕何夕，袢暑其蒸。',65,'全唐诗/poet.song.163000.json','["今夕何夕，袢暑其蒸。", "于後之旦，維槿始榮。", "有綽其聲，我后中興。", "我公協成，有功有能。", "我后顯旌，不伐不矜。", "我氓盛稱，我氓盛稱，我公長生。"]'),
('56f1860e-9320-4798-9ead-fd789e7efbb5','初榮  其一','曾丰','宋','宋诗','song-poetry','','[]','𦴇𦴇者菊，九月初榮。',50,'全唐诗/poet.song.163000.json','["𦴇𦴇者菊，九月初榮。", "于家之庭，有旗有鈴。", "主文孔明，綽其能聲。", "之子初榮，與象爲聲。", "匪家之馨，維鄉之馨。"]'),
('9d2ef862-e101-48f9-8e5a-be859938ceec','初榮  其二','曾丰','宋','宋诗','song-poetry','','[]','𦱊𦱊者梅，十月初榮。',50,'全唐诗/poet.song.163000.json','["𦱊𦱊者梅，十月初榮。", "于郡之廳，有罍有觥。", "主禮孔誠，洽其歡聲。", "之子初榮，爲鄉爲馨。", "匪鄉之馨，維郡之馨。"]'),
('a2f92257-0066-403c-9da4-424db1b7ff43','初榮  其三','曾丰','宋','宋诗','song-poetry','','[]','艿艿者蘭，三月初榮。',50,'全唐诗/poet.song.163000.json','["艿艿者蘭，三月初榮。", "于王之庭，有穎有泓。", "主德孔宏，骾其直聲。", "之子初榮，與郡爲馨。", "匪郡之馨，惟國之馨。"]'),
('8465f454-fae2-4a08-bf41-903564f98a16','初榮  其四','曾丰','宋','宋诗','song-poetry','','[]','何當效能，宋緒丕興。',26,'全唐诗/poet.song.163000.json','["何當效能，宋緒丕興。", "之子中榮，匪國之馨，維天下之馨。"]'),
('edc2bb7b-ac19-41b7-b6b3-789449b48016','初榮  其五','曾丰','宋','宋诗','song-poetry','','[]','何當謁精，宋績丕成。',28,'全唐诗/poet.song.163000.json','["何當謁精，宋績丕成。", "之子終榮，匪一時之馨，維千百載之馨。"]'),
('c764fde6-196f-42cd-8cc6-69ee0a746787','上廣東漕使黄郎中  其一','曾丰','宋','宋诗','song-poetry','','[]','維春洩洩，維陽之氣，維和之至。',15,'全唐诗/poet.song.163000.json','["維春洩洩，維陽之氣，維和之至。"]'),
('5b728839-3de7-4b83-b9b0-93fcb10c7ffd','上廣東漕使黄郎中  其二','曾丰','宋','宋诗','song-poetry','','[]','維春茸茸，惟和之功，惟陽之中。',15,'全唐诗/poet.song.163000.json','["維春茸茸，惟和之功，惟陽之中。"]'),
('7d990798-9140-4aaa-ac0e-9580dc6ba3c4','上廣東漕使黄郎中  其三','曾丰','宋','宋诗','song-poetry','','[]','中兮和茇，和兮中之茁。',23,'全唐诗/poet.song.163000.json','["中兮和茇，和兮中之茁。", "潜鞠兮中和，篤生兮人物。"]'),
('c1b54b54-20ba-4db3-84e2-af708f3816c8','上廣東漕使黄郎中  其四','曾丰','宋','宋诗','song-poetry','','[]','三春弸兮，中氣彭兮。',40,'全唐诗/poet.song.163000.json','["三春弸兮，中氣彭兮。", "季于孟仲，和之精兮。", "至精收蒸，天相大明。", "公生京京，集春之成。"]'),
('d7790ef0-1bd5-4b99-a793-693b5c14ebd0','上廣東漕使黄郎中  其五','曾丰','宋','宋诗','song-poetry','','[]','三春彭兮，和氣弸兮。',40,'全唐诗/poet.song.163000.json','["三春彭兮，和氣弸兮。", "季于孟仲，和之英兮。", "至英收凝，天相丕乎。", "公生裕裕，集春之成。"]'),
('666eb060-f394-4981-9cb0-60f3e2e2d3d1','上廣東漕使黄郎中  其六','曾丰','宋','宋诗','song-poetry','','[]','天相公生，成春收集。',20,'全唐诗/poet.song.163000.json','["天相公生，成春收集。", "挺所鍾兮，醇乎成質。"]'),
('3a1888e9-9d1d-4dde-8dbe-01bd0ca852bf','上廣東漕使黄郎中  其七','曾丰','宋','宋诗','song-poetry','','[]','天相公生，成春收集。',20,'全唐诗/poet.song.163000.json','["天相公生，成春收集。", "充所養兮，粹乎成德。"]'),
('1a9bb843-c242-41da-96bb-0caf25db26b1','上廣東漕使黄郎中  其八','曾丰','宋','宋诗','song-poetry','','[]','公生京京，其器不盈。',70,'全唐诗/poet.song.163000.json','["公生京京，其器不盈。", "公生裕裕，其色不矜。", "不矜不盈，不與時爭。", "不盈不矜，不與物攖。", "不攖不爭，神觀天清。", "不爭不攖，體氣地寧。", "天清地寧，松算椿齡。"]'),
('985c3704-ea96-4706-951c-4b5c8028567f','賀劉倉使生朝  其一','曾丰','宋','宋诗','song-poetry','','[]','眷此良月，開此良辰。',55,'全唐诗/poet.song.163000.json','["眷此良月，開此良辰。", "水德奫奫，羽音詡詡。", "玉曜在戌，旁燭于寅。", "仁氣收薰，天地氤氳。", "武夷鞠淳，甫生及申，將秉周鈞。"]'),
('4679a836-c215-472c-83d3-fb6dea10a6a1','賀劉倉使生朝  其二','曾丰','宋','宋诗','song-poetry','','[]','眷此良月，協此良序。',55,'全唐诗/poet.song.163000.json','["眷此良月，協此良序。", "水德溥溥，羽音詡詡。", "金曜在鄭，對燭于魯。", "儒風妝鼓，乾坤煦嫗。", "武夷裒湑，生申及甫，且持漢斧。"]'),
('248e54d1-19be-4aa8-8db5-a3876ade570c','賀劉倉使生朝  其三','曾丰','宋','宋诗','song-poetry','','[]','眷此良月，生此良臣。',82,'全唐诗/poet.song.163000.json','["眷此良月，生此良臣。", "金礦玉璞，質氣天貞。", "靜以牧身，與吾德爲仁。", "動以牧人，與吾民爲春。", "彼蠢者民，視自吾身。", "彼穹者旻，聽自吾民。", "不求自應，不召自臻。", "乃齒乃髮，斯松斯椿。"]'),
('658aca7b-4de9-484f-94c2-d78e03412ef7','續南有嘉魚  其一','曾丰','宋','宋诗','song-poetry','','[]','維離之方，維丙之穴。',40,'全唐诗/poet.song.163000.json','["維離之方，維丙之穴。", "誰幽爾宅，自濡自沫。", "惟性是適，與汩俱入。", "莫厝其罬，亦孔之黠。"]'),
('53c5e555-d510-4278-b2cd-963ef6218b19','續南有嘉魚  其二','曾丰','宋','宋诗','song-poetry','','[]','維夏之時，維孟之月。',40,'全唐诗/poet.song.163000.json','["維夏之時，維孟之月。", "誰浪爾跡，于哺于歠。", "惟物是訹，與潏俱出。", "莫稅其罼，亦孔之拙。"]'),
('61558b48-cc7c-4a4a-b13d-9dca9e7c977c','續南有嘉魚  其三','曾丰','宋','宋诗','song-poetry','','[]','天予之骨，其鯁如鯪。',82,'全唐诗/poet.song.163000.json','["天予之骨，其鯁如鯪。", "道與之肉，其糜如鯹。", "非媺人口，可昌我齡。", "奈何薄味，從爾休聲。", "麴氏傾意，人動情。", "雖彼相欺以機械，亦由自暴其神靈。", "彼名有累兮彼生，吾生奚用兮吾名。"]'),
('7486e892-553a-4052-bf6a-c5ced7e5fa2d','續南有樛木  其一','曾丰','宋','宋诗','song-poetry','','[]','彼樛者木，輪囷其質。',47,'全唐诗/poet.song.163000.json','["彼樛者木，輪囷其質。", "既幹既跋，匪枉伊直。", "時乎倒植，自卑自抑。", "膠轕蟠屈，形詭貌譎，於時好乎弗適。"]'),
('68706cbf-be1e-48e7-a908-2834710307c7','續南有樛木  其二','曾丰','宋','宋诗','song-poetry','','[]','彼樛者木，擁腫其資。',47,'全唐诗/poet.song.163000.json','["彼樛者木，擁腫其資。", "既節既枝，匪正伊欹。", "時乎倒垂，自抑自卑。", "勃窣離奇，根恬蔕怡，於性元兮弗迷。"]'),
('3843d361-fa76-4a0a-a1eb-f495c61e9eb1','續南有樛木  其三','曾丰','宋','宋诗','song-poetry','','[]','弗適時好，暴客不到。',21,'全唐诗/poet.song.163000.json','["弗適時好，暴客不到。", "暴客不到，軼出乎危道。"]'),
('d402260e-4bb7-4f46-8a07-0e18fd627d22','續南有樛木  其四','曾丰','宋','宋诗','song-poetry','','[]','弗迷性元，靈主長存。',21,'全唐诗/poet.song.163000.json','["弗迷性元，靈主長存。", "靈主長存，馴入乎妙門。"]'),
('a9130fa1-543f-49a0-8f90-94aa8074d544','續南有樛木  其五','曾丰','宋','宋诗','song-poetry','','[]','危道我出，妙門我入。',30,'全唐诗/poet.song.163000.json','["危道我出，妙門我入。", "有謂我爲兮不才之物。", "不謂我得兮不才之物。"]'),
('f10cd6f3-9838-4abd-82c2-6cc0c4c1357e','續南有樛木  其六','曾丰','宋','宋诗','song-poetry','','[]','右二章章九句，二章章四句。',13,'全唐诗/poet.song.163000.json','["右二章章九句，二章章四句。"]'),
('ddf23b08-9404-4524-b697-302344337eea','自是妾之罪','曾丰','宋','宋诗','song-poetry','','[]','妾生昭君村，國色少所逮。',204,'全唐诗/poet.song.163000.json','["妾生昭君村，國色少所逮。", "固羞著紅紫，亦懶傅粉黛。", "少時姆教嚴，稍稍攻組繪。", "針機參太玄，綫道得三昧。", "坐貧姑貿遷，不就村市儈。", "朅去長安遊，幾入未央賣。", "其如主市司，所好與妾背。", "一金陽不酬，翻謂索價大。", "永言妾所挾，未道美無對。", "猶欺西蜀錦，豈數南海貝。", "厥價誠不廉，其理獨何怪。", "况妾所索價，似亦非分外。", "售否委自然，於妾無利害。", "古女不上工，肯犯出閫戒。", "追思妾初謀，輕發良獨悔。", "雅負傾城姿，來爲倚市態。", "人得賤視之，自是妾之罪。"]'),
('53c8367d-0f68-465d-bb60-f553d449bdf1','貞女篇','曾丰','宋','宋诗','song-poetry','','[]','女生願有家，奴嫁理所宜。',192,'全唐诗/poet.song.163000.json','["女生願有家，奴嫁理所宜。", "出自父母命，奴豈敢固違。", "既許吳氏子，又許蔡氏兒。", "但有一女嫁，乃受兩聘儀。", "爲奴父母者，不知意何斯。", "業已許吳氏，復許蔡已非。", "况卒蔡之棄，而復吳之歸。", "奴羞毅不行，父母固强之。", "勢不得自由，出門行遲遲。", "欲哭聲不出，欲語舌不隨。", "投江以自明，庶免世點嗤。", "寧作有行鬼，無爲不義妻。", "皇天上無極，后土深莫涯。", "區區奴之心，惟有此水知。", "劉歆空裹頭，馮道空捋髭。", "或以雌視汝，汝猶不知雌。"]'),
('1e049f67-4261-4bdf-a53c-65af95ed9187','倦客','曾丰','宋','宋诗','song-poetry','','[]','倦禽思夜林，倦客思夜衾。',60,'全唐诗/poet.song.163000.json','["倦禽思夜林，倦客思夜衾。", "夜衾良獨薄，夜林良獨深。", "林深暖氣聚，衾薄寒風侵。", "氣暖仍比翼，風寒更孤簪。", "猶敢謂倦客，曾不如倦禽。"]'),
('b44b0d0d-f523-459f-84da-5ef530941b89','奉解水石紛','曾丰','宋','宋诗','song-poetry','','[]','江深寂無聲，旁岸時㶁㶁。',84,'全唐诗/poet.song.163000.json','["江深寂無聲，旁岸時㶁㶁。", "推篷細聽之，迺是石間滴。", "固知水之鳴，多出石之激。", "如何厭喧人，罪水不罪石。", "吾在水石間，雅性雖嗜默。", "鳴非吾敢嫌，激非吾敢責。", "奉解水石紛，兩各適其適。"]'),
('76093686-0bc2-4c9d-b622-70978973c5ee','即席賦會昌章簿出示假梅','曾丰','宋','宋诗','song-poetry','','[]','早探梅春南俗慣，今年不料寒裂骭。',176,'全唐诗/poet.song.163000.json','["早探梅春南俗慣，今年不料寒裂骭。", "梅花索價似太高，雖現幽姿猶匿半。", "小小樽前白玉盤，忽移全樹教吾看。", "僅高一尺輒崢嶸，纔吐數枝如爛熳。", "遠觀不足近視之，始覺是真還似幻。", "笑問主人誰所爲，疑是女媧殘手段。", "鍛石所傳非有方，補天之妙人無間。", "滿堂坐客俱眼生，吾其付之一笑粲。", "大庾嶺頭春寒空，猶是陽和假相換。", "認假爲真世所同，莫怪此花渠改觀。", "吾將真假一樣看，豈爲造化小兒玩。"]'),
('08e6744b-1374-49a6-bdd8-cb425d6f3bfd','癸卯豫章貢闈酬贈教授張安叔','曾丰','宋','宋诗','song-poetry','','[]','吾與子所居，相去二百里。',204,'全唐诗/poet.song.163000.json','["吾與子所居，相去二百里。", "建昌吾之鄰，其實同郡耳。", "已久聞姓名，不專爲科第。", "論心雖所共，舉足若相避。", "只今緣檄來，車柄初各指。", "去矣信所之，偶然集於此。", "相聞始相逢，同調更同事。", "談諧出肺肝，議論到骨髓。", "首遺垂蓋篇，至以馬班比。", "愛我豈不深，恐非切磋意。", "麻姑山氣偏，土物半仙劑。", "枸杞雜黄精，猶未窮厥美。", "清淑之所鍾，一代文章士。", "翹翹南豐曾，挺挺旴江李。", "豈獨華江西，往往國之瑞。", "誰其繼此公，或者屬吾子。", "更傾胸次高，莫道華端是。"]'),
('a9723e6c-3ef4-4b36-9084-1545f03bb540','取清苦廉正爲韵課四古風呈漕使蘇叔子  其一','曾丰','宋','宋诗','song-poetry','','[]','元氣始北坎，入西爲至清。',48,'全唐诗/poet.song.163000.json','["元氣始北坎，入西爲至清。", "融之岷江中，凜欲成水晶。", "三蘇戲落筆，萬口爭嚼冰。", "天未喪斯文，流風在雲礽。"]'),
('2f51a0b4-31b7-4f02-9ec1-1e8aca29ebcf','取清苦廉正爲韵課四古風呈漕使蘇叔子  其二','曾丰','宋','宋诗','song-poetry','','[]','釋家吾業根，大者名曰苦。',48,'全唐诗/poet.song.163000.json','["釋家吾業根，大者名曰苦。", "吾儒視苦海，翻不翅樂土。", "毳行禹安之，瓢飲顔得所。", "三蘇窮始榮，更有孫似祖。"]'),
('19507810-1760-4b57-a811-b4df30235612','取清苦廉正爲韵課四古風呈漕使蘇叔子  其三','曾丰','宋','宋诗','song-poetry','','[]','夷齊餓至死，利固非所餂。',48,'全唐诗/poet.song.163000.json','["夷齊餓至死，利固非所餂。", "贏取萬世名，猶疑未爲廉。", "了無近名事，始不犯世嫌。", "貪廉公兩忘，退與大道潜。"]'),
('65f8bea2-5095-4e36-aae5-b3651437a741','取清苦廉正爲韵課四古風呈漕使蘇叔子  其四','曾丰','宋','宋诗','song-poetry','','[]','吾事寧天左，吾道勿小徑。',48,'全唐诗/poet.song.163000.json','["吾事寧天左，吾道勿小徑。", "窮通委自然，所以爲孔孟。", "本朝二百年，公傳得其正。", "肯與世頡頏，豈至今蹭蹬。"]'),
('6353e097-98e4-4ce6-b978-a588d87163bd','過太和赴主簿鄧楚材豫章貢闈之約','曾丰','宋','宋诗','song-poetry','','[]','福建人才古鄒魯，文章師匠道宗主。',128,'全唐诗/poet.song.163000.json','["福建人才古鄒魯，文章師匠道宗主。", "餘子姑作尋常看，此公僅能一二數。", "太學頡頏賦爭衡，凌雲之氣擲地聲。", "鯤鵬誰礙天南去，麒麟猶落地上行。", "南昌傾蓋恨不早，西昌扣門喜欲倒。", "風雨那容酒絕交，江山不許詩在告。", "宦途同調能幾人，相逢莫厭情相親。", "言下甘心聽苦口，鏡中白髮催青春。"]'),
('f072b9ee-7feb-45e8-a60e-9a5cb34dd88f','癸卯九月贛吉大水','曾丰','宋','宋诗','song-poetry','','[]','秋江次第落到底，夜半忽如潮湧起。',96,'全唐诗/poet.song.163000.json','["秋江次第落到底，夜半忽如潮湧起。", "方陵屋山遽城頭，已失沙背况沙嘴。", "五月小潦似未傷，九月大潦疑非常。", "感召之心上所謹，推原厥咎誰其當。", "一部麟經幾書異，敢用丁寧今執事。", "休責漢公賢不賢，且論堯具備未備。"]'),
('e72f030e-a6ed-4ec2-b9bb-55e80c1eb21b','謝新淦令徐信甫至贛相過','曾丰','宋','宋诗','song-poetry','','[]','永嘉之重自晉始，積至本朝始多士。',192,'全唐诗/poet.song.163000.json','["永嘉之重自晉始，積至本朝始多士。", "大科異等固其常，文章道德相角掎。", "淳熙癸卯徐令君，相逢欲執弟子禮。", "聊將舌本吐寸璣，輒自脚跟參萬里。", "藏中觸處隨光明，言下從誰得原委。", "國子博士陳先生，初受皮膚終骨髓。", "孤篷今轉大江西，猛象欲踏黄河底。", "但恐黄河深更深，水浮太空空浮水。", "裹糧學道僕馬疲，歸家落照在簾裏。", "自有餘師更求師，棒頭打出乃其理。", "况人胸中各法門，陳君韓子吾柳子。", "雖有心印不敢傳，恐君呵佛駡祖爾。"]'),
('1968125c-3983-48f0-b4d6-c73e800c133e','題會昌蕭帝巖','曾丰','宋','宋诗','song-poetry','','[]','出門疑浪游，轉眼逢傑觀。',288,'全唐诗/poet.song.163000.json','["出門疑浪游，轉眼逢傑觀。", "山斗路將窮，脚欹行小緩。", "信筇捫石根，恍若得一間。", "谽谺欲上吞，渾沌疑始判。", "豈其蛟擘開，或者雷劈斷。", "洞轉一曲關，磴道鬼爲棧。", "懸巖百仞餘，僧圬屋其半。", "其旁磊蒼崖，其下踏碧澗。", "峰迴若相朝，水㶁若相喚。", "蘿虯百年枝，松靷千尺幹。", "溜皮鱗逆生，蟄若相倒貫。", "三十六洞天，往往此其冠。", "或傳帝所栖，其說涉漫漶。", "意古隠者徒，僑家避秦亂。", "圍棋或著書，不覺歲月換。", "斷編何處藏，但有竹可汗。", "殘局何年終，但有柯欲爛。", "疑似姑置之，杯酒酬賞歎。", "移之家山旁，破甑視浮宦。", "歸老似未遲，欠此清一段。", "上疏乞鑑湖，故事吾可按。", "悠悠天聽高，此計卒未辦。", "意外今獲茲，巾幘可小岸。", "况在大化中，醜好俱是幻。"]'),
('007cce1a-4053-4829-aa7e-707d0a9910a0','題劉武翼息齋','曾丰','宋','宋诗','song-poetry','','[]','天地一從開闢始，左旋右轉長不已。',96,'全唐诗/poet.song.163000.json','["天地一從開闢始，左旋右轉長不已。", "詰所以然氣使之，君獨不爲氣所使。", "平生由氣今自由，三平二滿過即休。", "千里收回渥洼馬，十年養熟溈山牛。", "本來無動那得靜，關著一毫還似剩。", "雖任鵲安頭上巢，更防人打耳邊磬。"]'),
('07b4f5d1-7ea9-4625-99c6-5f7daaa0e715','送劉尚書再守贛之一年移帥豫章','曾丰','宋','宋诗','song-poetry','','[]','贛農雖懶連歲豊，贛囚雖黠連歲空。',192,'全唐诗/poet.song.163000.json','["贛農雖懶連歲豊，贛囚雖黠連歲空。", "農囚今昨性豈異，今守蓋與昨不同。", "鬼窺莫見活城手，酒澆不下憂民胸。", "十年五度看易守，萬口一詞獨歸公。", "公凡兩來亦兩去，前去殊邦今本路。", "德公吾與軍民同，軍民未解吾細諭。", "向汝思公公復來，今公去汝汝勿慮。", "僅隔一江千里間，豈忘三任五年處。", "軍民雖諾猶動情，不忍江頭送公行。", "淚隨贛石順流下，碑在巽門前面橫。", "千里和氣散萬里，一城春風分十城。", "但疑贛人送未了，洪人又送朝行京。"]'),
('2654c6be-3774-4f2a-81ab-9c44198ccf5b','送贛士劉虞卿赴省','曾丰','宋','宋诗','song-poetry','','[]','贛豈無傑才，少有中我律。',204,'全唐诗/poet.song.163000.json','["贛豈無傑才，少有中我律。", "君以謁求交，相見便相入。", "贛豈無傑觀，少有投我筆。", "君以題求詩，相許便相及。", "况加積業齋，亦入緣督集。", "豈其夤緣深，姑以臭味密。", "初知若久要，三歲如一日。", "質穩不受浮，疑非自贛出。", "辟雍諸偉人，大抵舊相識。", "其高固天資，所揉亦氣習。", "誰使地塊高，未放天馬逸。", "今聽鹿鳴歌，催赴蘭省急。", "行時梅欲華，到時梅欲實。", "願言子如梅，華實俱蔚蔚。", "筆頭驅六丁，榜首爭甲乙。", "青衫拜白頭，人子願始畢。", "修途莫之量，前輩顧所立。"]'),
('3492b5fd-a672-400f-a99a-6dfd010d2a79','送陳通卿赴省','曾丰','宋','宋诗','song-poetry','','[]','閩南江西人，蓬梗適相會。',156,'全唐诗/poet.song.163000.json','["閩南江西人，蓬梗適相會。", "妙齡華髮身，氣味適相愛。", "問其先世誰，意者了翁派。", "肯學喜文章，綽有風流在。", "自餘鍛鍊方，猶鼓我鑪鞴。", "自餘組織工，猶勘我機械。", "一投百無牾，始契終不外。", "漕臺開棘圍，非金必沙汰。", "也爲八韵諧，輒擅諸生最。", "明年動春官，再捷驚晚輩。", "御樓晝刻長，入赴集英對。", "危言攖龍鱗，穩步踏鵬背。", "倘來幸勿驕，歸學遠且大。"]'),
('1c6ed9de-18a9-4d2a-a36a-1669e036850a','送陳次畢劉德欽王才卿赴省','曾丰','宋','宋诗','song-poetry','','[]','梅花爭送君出鄉，蘭花爭迎君入場。',96,'全唐诗/poet.song.163000.json','["梅花爭送君出鄉，蘭花爭迎君入場。", "兩花之意豈不厚，非與喜機適相當。", "集英對罷燕聞喜，紅迎紫送餘桃李。", "問燕無恙相識初，與鶑莫逆半酣裏。", "中年得意非少同，未老更下不朽工。", "氣驅萬物挫于筆，舌挽三江吞以胸。"]'),
('1201d919-6446-42a3-b51f-12ac45944620','贛縣向宰座上見綠萼梅主簿程開老相勉賦詩','曾丰','宋','宋诗','song-poetry','','[]','素與百花少相諧，醉眼時爲梅一開。',96,'全唐诗/poet.song.163000.json','["素與百花少相諧，醉眼時爲梅一開。", "嶺南嶺北幾十種，人所常見非奇瑰。", "中有孤根別風骨，白金鏤盞玻璃臺。", "白華紅萼雖傾國，但恐紅非本來色。", "逃紅歸綠未到真，與真相近亦天德。", "化工厭駁會還純，華萼併教同一白。"]'),
('09ba7a10-99c3-411f-87dc-42d18350a44a','邂逅南昌簿孫正之劇談別後聊以記所期者','曾丰','宋','宋诗','song-poetry','','[]','三秦擅淮右，三孔專江西。',192,'全唐诗/poet.song.163000.json','["三秦擅淮右，三孔專江西。", "鼎足立世穩，文匠詩宗師。", "吾生亦太晚，流風殆誰歸。", "龍泉劍之精，夜氣貫斗箕。", "今其爲三孫，鋒芒不能輝。", "大孫學如鍼，鑽到罅隙微。", "小孫筆如雷，挾雨驅虹蜺。", "弟兄時輩中，群雄望風雌。", "我新幸且識，其仲字正之。", "才調驥歷塊，襟懷鷗忘機。", "每見必樽酒，謾延率移時。", "劇醉尚正色，太平輒愁眉。", "萬事談未了，心隨白雲飛。", "其如總是客，而更遽語離。", "各著古人鞭，滿意酬所期。", "離合有自然，姑置天一涯。"]'),
('8cf0d805-1230-4086-a180-3edb19b781da','吉之南門外見木芙蓉爛開','曾丰','宋','宋诗','song-poetry','','[]','小春催出傾城色，笑倚牆頭若招客。',64,'全唐诗/poet.song.163000.json','["小春催出傾城色，笑倚牆頭若招客。", "芬芳猶帯秋風殘，婀娜豈宜江路側。", "詩眼驚紅狂欲呼，熟看似細又似粗。", "花神留爲菊後乘，天意遣作梅先驅。"]'),
('5248bd09-bd27-416c-ac18-2769d83110b5','同張隨州賦會稽朱子榮席上丹桂','曾丰','宋','宋诗','song-poetry','','[]','月娥施朱小留殘，天風吹上桂樹端。',128,'全唐诗/poet.song.163000.json','["月娥施朱小留殘，天風吹上桂樹端。", "葉猶强項護故綠，花獨多情染餘丹。", "夜來誰借修月斧，和根剟與凡世看。", "世人不識天上種，醉眼恍惚魂溟漫。", "我嘗浪作折桂客，驚見似與丹窟般。", "主人眠花熟風韻，等是姓朱俱可觀。", "况逢問字載酒客，不妨爲花理杯盤。", "賞者莫憚腕欲脫，花到夜深不禁寒。"]'),
('4aa191a2-7953-4eb7-97ce-80cf0a154e07','題公安宰黄叔萬魯齋  其一','曾丰','宋','宋诗','song-poetry','','[]','淵中見潜魚，床下聞鬭蟻。',96,'全唐诗/poet.song.163000.json','["淵中見潜魚，床下聞鬭蟻。", "從知聰和明，反累目與耳。", "孔門三千人，十資九其慧。", "竟失道之歸，端爲慧所使。", "回以愚故專，首得一宗旨。", "其次參好修，與回亦無異。", "受裁魯有餘，學道心不貳。", "頓悟聖授機，萬理付一唯。"]'),
('80968230-bb58-4b9a-8bbb-1f026a81d94b','題公安宰黄叔萬魯齋  其二','曾丰','宋','宋诗','song-poetry','','[]','試推學之功，但自好而始。',180,'全唐诗/poet.song.163000.json','["試推學之功，但自好而始。", "設令太聰明，視孝緒餘爾。", "公安黄令君，少鈍壯而銳。", "不受青雲吞，猶坐黄卷累。", "開囊包物初，落筆灑胸次。", "鋒芒莫敢攖，古劍發新礪。", "駸駸進未休，冉冉老將至。", "以魯揭其齋，蓋是少時事。", "云胡不輒更，無乃有所爲。", "新收汗馬心，蚤作蟄雷計。", "音容成老翁，情性復孩稚。", "其友曾撙齋，適是參苗裔。", "家學世相傳，魯者鈍之謂。", "生平事事遲，大抵與君似。", "雖遲幸勿嫌，正以鈍爲利。"]'),
('11195f2e-1b9a-48db-bda9-569aece0a99a','題張德清悅齋','曾丰','宋','宋诗','song-poetry','','[]','君不見胸中義利交戰初，勝負未分子夏臞。',198,'全唐诗/poet.song.163000.json','["君不見胸中義利交戰初，勝負未分子夏臞。", "又不見胸中義利交戰餘，勝負已决子夏腴。", "臞腴之變何須臾，一忻一戚相乘除。", "初枉德清來致敬，盛年已有臞之證。", "况年不似舊時盛，爲若面上腴生瑩。", "紛華淡泊交相競，利攻莫入義還勝。", "小齋容膝祇數椽，焚香坐對古聖賢。", "關鑰勘到羲皇前，肉融形釋心悠然。", "非金非石非管絃，抵掌頓足喜欲顛。", "楊墨申韓初立說，其心亦爲道而設。", "差以毫厘繆燕越，更于真似細區別。", "萬一悅非吾所悅，恐乾孟子韓公舌。"]'),
('4e34a31c-b8cf-4b6d-8695-b692a845366b','題陳晉卿頤齋','曾丰','宋','宋诗','song-poetry','','[]','鯤鵬振翼初九萬，楩楠歸根終數寸。',96,'全唐诗/poet.song.163000.json','["鯤鵬振翼初九萬，楩楠歸根終數寸。", "穉須有發老有收，養之各要適其分。", "三兒讀書翁卧聽，生涯固有何所營。", "功名羞從奇道取，文學厭與今人爭。", "誰揭此齋函二意，翁養其恬兒養銳。", "今雖異養後同功，一本莊椿三郄桂。"]'),
('c3a29a7d-8871-4d77-871d-12292b654627','題饒德裕三益軒','曾丰','宋','宋诗','song-poetry','','[]','過從義要如膠漆，琢磨功要如金石。',192,'全唐诗/poet.song.163000.json','["過從義要如膠漆，琢磨功要如金石。", "二者於茲有一偏，雖過聖門未之入。", "德裕躭儒今二毛，一軒灑落僅容膝。", "詩書執禮不放閑，直諒多聞誰較密。", "仲修國老曾鼎臣，各於三者得其一。", "曳躧相迎下榻留，冒雲蒙霧不知濕。", "松梅竹裏不知凋，形影神中冥莫逆。", "問答小參文字禪，賈誼升堂馬入室。", "更能尚友古聖賢，蘭移其氣金移質。", "一線溜作吞天濤，十丈花成盈掬實。", "擴充未下反約功，軒今所揭乃其適。", "顔淵復禮老歸根，今揭吾知猶欠易。"]'),
('f838fe70-f95e-4cfd-883d-5469cdb4f3c8','題曾見卓此君軒','曾丰','宋','宋诗','song-poetry','','[]','衣冠濟濟友若昆，詩書纚纚子若孫。',184,'全唐诗/poet.song.163000.json','["衣冠濟濟友若昆，詩書纚纚子若孫。", "容有玉立人照門，得無玉立物照軒。", "軒外清凉別乾坤，一點塵俗不得干。", "其間蓋有此君存，此君根性抱歲寒。", "初交可作久要看，主人對之忘朝昏。", "茶鼎烟中鑪薰燔，酒尊陰裏書帙翻。", "坐探物初窮道原，中有所得不自尊。", "與此君結終身歡，莫逆之意寓不言。", "行藏相約無背轅，數猶未偶姑屈蟠。", "峻節孤標老丘園，天假其時忽騰掀，鳳鳴龍化駭聽觀。", "功成不受聲利吞，白雲深處同歸根。"]'),
('c335d4d6-4ce8-4cef-b7a9-2667b7936047','梅隠','曾丰','宋','宋诗','song-poetry','','[]','君不見岷峨春雷江發源，又不見楩楠秋風葉歸根。',134,'全唐诗/poet.song.163000.json','["君不見岷峨春雷江發源，又不見楩楠秋風葉歸根。", "時中兩字萬物具，他說不出吾聖門。", "挾書來就辟雍試，堯舜君民得無意。", "鳳山梅隠屋數椽，區區無乃太早計。", "淵明出辦三徑資，初不害結松菊知。", "君今意與梅莫逆，豈梅亦具幽獨姿。", "梅雖花早實亦早，早恐少年遲恐老。", "青春誓不易歲寒，歸伴梅遲梅却掃。"]'),
('cc3e3b49-d89c-4b45-8c3f-e82a5cd80dbd','入廣豊倉領米書所遇','曾丰','宋','宋诗','song-poetry','','[]','創意入倉稽斗斛，乃逢兩鶴三頭鹿。',128,'全唐诗/poet.song.163000.json','["創意入倉稽斗斛，乃逢兩鶴三頭鹿。", "意者殆天假其衷，憐我清高墮于俗。", "翛翛兩鶴雄與雌，三鹿雄雌連一兒。", "本生自有山林在，安用來游城市爲。", "出山入市已失脚，况傍官倉疑更錯。", "口與身爲沒齒讎，心因腹作終日惡。", "我歸徑欲追喬松，爾鶴爾鹿來相從。", "一爲先驅一後從，共馭元氣騎清風。"]'),
('cf3341de-a3ec-485f-b51c-6cd3ee945f89','萬安簿吳公誼實浙餘杭人今書滿最歸歟欲竟投老未决于其間而贊之','曾丰','宋','宋诗','song-poetry','','[]','錢唐之墟故吳地，子孫復以吳爲民。',128,'全唐诗/poet.song.163000.json','["錢唐之墟故吳地，子孫復以吳爲民。", "百世不有雲來興，高者道德次文藝。", "萬安主簿今詩雄，終未得力翻得窮。", "猶餘妻子眼未白，不有江山囊幾空。", "歸歟已動投簪興，公自規模吾印證。", "鬻餘豈不得一丘，耕罷猶堪理三徑。", "陶潜張翰雖風流，彼歸有激公無求。", "浙江兀炎古箕潁，吳公徜徉今巢由。"]'),
('9bdf96b4-25da-450a-a2e0-cb7ed9fa0efe','上左丞相王國公','曾丰','宋','宋诗','song-poetry','','[]','張公筆與造化爭，壁上蟠屈蒼龍形。',112,'全唐诗/poet.song.163000.json','["張公筆與造化爭，壁上蟠屈蒼龍形。", "爪牙鱗角俱崢嶸，苦猶未點雙眼睛。", "旁人駭見疑其故，古鑰神機公自露。", "龍眼已空睛更具，吐霧噴雲恐飛去。", "人初不以公爲然，嘗試點之龍形全，疾雷破壁龍上天。", "吾骨雅似龍偃蹇，眼高已去天不遠，變化猶須公一點。"]'),
('c010ab88-96dd-47ce-854b-77ccc31c018f','上右丞相梁國公','曾丰','宋','宋诗','song-poetry','','[]','三月桃花水發洪，游魚挾雨乘長風。',112,'全唐诗/poet.song.163000.json','["三月桃花水發洪，游魚挾雨乘長風。", "去折禹門浪三重，滿意須臾蛻爲龍。", "門道潭潭石齒齒，魚初踴躍中委靡。", "豈後有輓前有柅，雷猶未與火其尾。", "破山霹靂放焰燒，平睨浪花輕一跳。", "拏雲攫霧撲九霄。", "吾骨雅似龍坎坷，已搭龍門猶隔鎖，化龍莫惜五雷火。"]'),
('4c174d2f-527d-4327-a7e8-e48fd38bfacc','壽周樞密四首  其一','曾丰','宋','宋诗','song-poetry','','[]','元氣自子始，入申爲至清。',48,'全唐诗/poet.song.163000.json','["元氣自子始，入申爲至清。", "况在申中央，其氣尤粹精。", "金風冷颼颼，玉寒露泠泠。", "人間物莫當，夜墮文昌星。"]'),
('631b172f-2199-4532-ad86-d7a92626ed43','壽周樞密四首  其二','曾丰','宋','宋诗','song-poetry','','[]','一氣清絕處，坤元直西方。',48,'全唐诗/poet.song.163000.json','["一氣清絕處，坤元直西方。", "公生受西氣，戲筆俱文章。", "北門逼西清，金仙侍玉皇。", "凡遺不朽蹤，便是難老方。"]'),
('e573ea7a-7f06-48cf-b6d3-397562a7f92c','壽周樞密四首  其三','曾丰','宋','宋诗','song-poetry','','[]','四時秋爲陰，凜凜兵氣衝。',48,'全唐诗/poet.song.163000.json','["四時秋爲陰，凜凜兵氣衝。", "公始稟此生，今坐制百戎。", "雖握生殺柄，以不殺爲功。", "長爾塞草青，自然臉霞紅。"]'),
('1f116db5-0e9b-42bf-9869-f1ba6d754d8c','壽周樞密四首  其四','曾丰','宋','宋诗','song-poetry','','[]','一元發于春，萬物收以秋。',48,'全唐诗/poet.song.163000.json','["一元發于春，萬物收以秋。", "公轉播物鈞，元氣在筆頭。", "頤指役漢將，願言似留侯。", "功成早辟穀，壽與喬松侔。"]'),
('e84f79a9-8875-4793-ba98-e72c83fb432a','小立贛灘崖石','曾丰','宋','宋诗','song-poetry','','[]','崖谷崔巍千萬狀，舟人來往篙其上。',64,'全唐诗/poet.song.163000.json','["崖谷崔巍千萬狀，舟人來往篙其上。", "數十年間人已非，百千劫後石無恙。", "吾生修短不自由，短中自有可以修。", "五言七言句外意，千古萬古江東流。"]'),
('d28397b3-c957-4682-8358-03d886af74e6','舟中書懷','曾丰','宋','宋诗','song-poetry','','[]','孤篷轉徙空隨牒，一出侵尋費三月。',64,'全唐诗/poet.song.163000.json','["孤篷轉徙空隨牒，一出侵尋費三月。", "厭從夢境作寄居，欲赴鷗羣填見闕。", "我且戒塗兒挽之，裹糧又趁蒲帆西。", "初心猶幸江神信，後計不教兒女知。"]'),
('3a4e00b5-38ad-4ca3-a917-769b37a8cbc6','乙巳正月過英州買得石山','曾丰','宋','宋诗','song-poetry','','[]','吾之好石如好色，要須肌理膩且澤，真成入眼輕連璧。',120,'全唐诗/poet.song.163000.json','["吾之好石如好色，要須肌理膩且澤，真成入眼輕連璧。", "吾之好石如好聲，要須節奏婉且清，真成入耳輕連城。", "閩浙江淮隨牒去，豈無一二石佳處，終之難得聲色具。", "飛篷今始轉廣東，英石不與他石同。", "其色燦爛聲玲瓏，小山突兀百千重。", "萬錢得之歸自奉，稍閑更爲山作頌。"]'),
('8571bf83-55ab-4acf-945b-eaf25a2c6402','五羊食荔枝龍眼','曾丰','宋','宋诗','song-poetry','','[]','素聞嶺南風，今假嶺南館。',168,'全唐诗/poet.song.163000.json','["素聞嶺南風，今假嶺南館。", "窮秋餘夏蒸，初臘借春暖。", "披衣汗流衣，握簡汗流簡。", "似登頭痛山，而坐身熱坂。", "誰其善解紛，荔枝雜龍眼。", "滿盤隨情堆，入手信意揀。", "强餐飽爲期，一澡得三浣。", "疑吞玄冰丸，復嚥飛雪散。", "猗歟兩清姿，南多北何罕。", "天曾無全功，地固有偏産。", "猶記初客閩，厭飫腹頻坦。", "一離餘十年，口與南味斷。", "渴者易爲飲，志得而意滿。", "兒輩舌太饒，平章味長短。"]'),
('480d897c-0af7-4a6c-b192-74c659bdfa1f','題葉英州清白亭','曾丰','宋','宋诗','song-poetry','','[]','一元之氣天得清，推爲覆幬萬物生。',152,'全唐诗/poet.song.163000.json','["一元之氣天得清，推爲覆幬萬物生。", "四時之氣秋得白，推爲揫歛萬物成。", "清白爲德蓋如此，我公何獨取于水。", "水生于天落于秋，妙與萬物爲終始。", "公家清白世所無，俸餘僅有數卷書。", "歸與宴坐故溪上，此心洞與溪水俱。", "取譬于水公之迹，胸中公固有虛室。", "清白一自虛中出，清至表表白畫畫。", "上少能容下多嫉，更居以濁守以黑，始與造化相出入。"]'),
('273c2bdd-bcf1-4f46-923c-374c4a3d66b7','爲增城丞張元輔賦博見亭','曾丰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','東山未爲高，坐覺魯之小。',204,'全唐诗/poet.song.163000.json','["東山未爲高，坐覺魯之小。", "更上泰山巔，天下不勝眇。", "公作如是觀，所學胡可料。", "父兄自磨磋，師友相揉矯。", "猶恐眼未高，著脚江湖渺。", "纔疑輒遍參，一悟百高了。", "今簸增城糠，冗不廢舒嘯。", "數椽立江頭，萬象生木杪。", "揆之高了機，撫掌成獨笑。", "或指羅浮尖，又出鳳凰表。", "嘗試登羅浮，鳳凰僅毫秒。", "洙泗聖人門，等級蓋不少。", "抬頭空仰高，瞑目誰見曉。", "能拍十哲肩，不失速而肖。", "要策參之勳，守約始爲妙。", "更與約相忘，混沌安得竅。", "公餘勿哦松，回光返自照。"]'),
('f1f26354-fa91-47a1-b349-a340b7b77b80','題通州通判陳日華二友齋','曾丰','宋','宋诗','song-poetry','','[]','吾初丞小邑，誓與松竹爲膠漆。',172,'全唐诗/poet.song.163000.json','["吾初丞小邑，誓與松竹爲膠漆。", "今公丞大藩，誓與松竹爲金蘭。", "維松若竹有何德，和公玉立成三益。", "矯矯摩雲性天高，亭亭傲雪心地直。", "風月外吾吾强哦，其如松竹偃蹇何。", "橫江太守風月主，公與平分無乃多。", "况胸有眼筆有口，大與松竹相諧偶。", "張陳漫浪耳熱初，管鮑綢繆歲寒後。", "三友莫逆俱歲寒，猶遺其一非簡驩。", "四科參偶不與班，孔子無容心其間。", "愛參初不異顔閔，寄與梅仙勿銜冤。"]'),
('443df4d1-ea47-4d7c-ac03-e9d3c44c8089','題三衢汪學士聽雨軒','曾丰','宋','宋诗','song-poetry','','[]','公家如許好昆仲，不數河東舊三鳳。',64,'全唐诗/poet.song.163000.json','["公家如許好昆仲，不數河東舊三鳳。", "床敷對語無限春，簷滴關愁不成夢。", "馬援看鳶始回頭，知機恐不似少游。", "看鳶機落聽雨下，雖悟已輸公一籌。"]'),
('c6889992-3246-4ff3-a777-966f16a4dd64','載欣','曾丰','宋','宋诗','song-poetry','','[]','伯牙家有焦尾琴，朱絃長掛窗壁陰。',208,'全唐诗/poet.song.163000.json','["伯牙家有焦尾琴，朱絃長掛窗壁陰。", "出大都邑初何心，直爲鍾期舊知音。", "玉軫調罷不自禁，聲諧匏土革木金。", "試彈一曲萬籟瘖，動盪南風鼓精祲。", "長養餘恩到魚禽，齊娥趙女秋夜砧。", "怨入離鸞別鶴聲，轉調忽落思歸吟。", "元亮歸歟故丘林，粉黛候門玉差參。", "卓氏心挑淚空淫，鐵脚豈受魔女侵。", "撫玩無絃喜不任，羲皇遺意絃外尋。", "阿舒阿宣立森森，大孫倚膝小捉衿。", "上百千壽酒再斟，爛醉欲眠不脫簪。", "大槐宮裏無升沉，醒浮烟浦登雲岑。", "高山流水弔古今，墨子從今突長黔。"]'),
('39daa442-b7a6-4f27-920f-4f5978c75e9a','壽廣東帥潘直閣','曾丰','宋','宋诗','song-poetry','','[]','太初談赤松，中古說黄石。',288,'全唐诗/poet.song.163000.json','["太初談赤松，中古說黄石。", "笑策導引勳，鬚鬢白成黑。", "金華得道人，綴自仙之籍。", "雖因習墮緣，久悟空爲色。", "泥丸至丹田，蓋著半生力。", "若爲鬢與鬚，白者日加益。", "陸展餘染方，豈固未全得。", "老聃生世初，鬅鬙頭已白。", "公白纔十年，視聃遲半百。", "紙帳掛齋中，竹奴欹枕側。", "染亦無所施，元方不須覓。", "或疑白之根，勃窣蟠胸臆。", "太白緣搜詩，少陵爲憂國。", "根未能中芟，華寧不外茁。", "根華理固然，抑復容有說。", "春淺未多溫，臘頹有餘冽。", "紛紛破萼梅，衮衮放花雪。", "融結上鬢鬚，愈白愈清絕。", "少於仁用功，晚以靜爲德。", "厭坐廣平堂，歸住子雲宅。", "卧聽兒吟哦，起視孫戲劇。", "頤間瑩生朱，眼底光盎墨。", "鬢鬚從白盡，不失壽箕翼。", "切毋痛著梳，更勿閑事鑷。"]'),
('2b3245e3-8157-4edd-981a-d7e746beb703','壽廣東提舉韓判院','曾丰','宋','宋诗','song-poetry','','[]','君不見天上之老人，夜夜增芒爛如銀。',178,'全唐诗/poet.song.163000.json','["君不見天上之老人，夜夜增芒爛如銀。", "又不見柱下之老子，年年換骨輕如紙。", "辟穀餐霞得長生，老子前生老人星。", "我疑公亦星之精，精神雖是肉枯槁。", "老子區區似徒老，公生富貴老更好。", "初隨鵷鷺班中都，一麾一節今南驅。", "爲溟渤中有蓬壺，雅懷信在蓬壺島。", "非要瓊芝與瑶草，公元自有長生道。", "藤床紙帳二十年，上至泥丸下丹田。", "孰非可爲地行仙，十月十日祥雲凍。", "賀客休投龜鶴頌，倚吟自伴寒禽哢。"]'),
('8d39a04a-7d47-4256-ba99-cec94ca148d5','送梁藤州廣譽解組還朝兼簡葛子章盧伯真','曾丰','宋','宋诗','song-poetry','','[]','乾道淳熙間，隨牒公之邑。',276,'全唐诗/poet.song.163000.json','["乾道淳熙間，隨牒公之邑。", "我閑時曳裾，公喜常折屐。", "過從未多時，情好已相得。", "功名打門催，馬首遽湖北。", "一爲盧溪留，便作弱水隔。", "解后五羊城，恍如不相識。", "初驚面顔蒼，徐視髭鬢黑。", "款曲遍諮諏，交游半悽惻。", "一別十五年，種種事非昔。", "更著一回別，又豈勝嘆息。", "梅雨逗談機，槐風速行色。", "愁邊更添愁，客裏仍送客。", "笑騎五馬歸，郎省平步入。", "天南九萬里，誰得礙鵬翼。", "語離當有詩，頌德似無益。", "清暉百尺虹，方廣千丈碧。", "高蓋山下松，極樂巖裏石。", "一切奇傑觀，無不入我集。", "轉眼雖寥寥，捫胸猶歷歷。", "公歸爲致言，久疎頗關憶。", "老葛年少盧，亦有風月癖。", "唱酬舊知音，來往今掃迹。", "相逢問撙齋，依舊四立壁。"]'),
('0ed2baa9-73f8-4a47-9172-80668b2d9753','遊三洲巖','曾丰','宋','宋诗','song-poetry','','[]','南中豈無巖，三洲蓋其傑。',288,'全唐诗/poet.song.163000.json','["南中豈無巖，三洲蓋其傑。", "朅來五羊初，滿聽行人說。", "今乘急雨遊，吾屐不遑蠟。", "遥觀似舜峰，迫視疑禹穴。", "數畝腹空洞，十丈口谺豁。", "恍焉入其間，眼亂欲生纈。", "寬處晃如堂，狹處黝如闥。", "彎跧角門隈，屈曲磴道劣。", "土膏兀參差，形象鬼塑湼。", "人立雙足欹，獸卧半身沒。", "斑爛旋洑文，鈎鎖玲瓏骨。", "伏撐突如櫨，斜拄岌如梲。", "倒懸雲乳凝，上溜井花冽。", "地空聲殷雷，石鹵色蒸鐵。", "暗中漏微明，圓處留小缺。", "倒指數不勝，百怪千萬譎。", "遊人得娛嬉，造物費曲折。", "靜言萬物初，含氣如聚沫。", "流者氣之融，峙者氣之結。", "時于融結間，故故出奇絕。", "巨靈盤古機，雖妙不容測。", "要之幻虛空，無乃等戲劇。", "居人玩視之，過客三歎息。", "濂溪艤行舟，眉山稅歸轍。"]'),
('fac81e74-3a7c-4eef-8f0b-c44b1713459f','遊三乳洞','曾丰','宋','宋诗','song-poetry','','[]','海上有三山，嶺南有三洞。',264,'全唐诗/poet.song.163000.json','["海上有三山，嶺南有三洞。", "洞中天下奇，少有相伯仲。", "探原冥莫涯，窺底窈無縫。", "流泉沆瀣融，滴乳氤氳凍。", "譎姿互形容，駁理交錯綜。", "推原開闢初，造化窮妙用。", "瓊田鬼爲耕，芝草天爲種。", "初爲仙界包，後與妙門共。", "我生嗜娛嬉，茲賞乘倥傯。", "幽跡重窮探，古碑難疾誦。", "玩心猶未厭，行色已先動。", "山容笑相留，水聲泣相送。", "后土不愛珍，入眼亦云衆。", "形模怪莫名，留作諸天供。", "琤然鐘磬聲，獨與雅意中。", "重價酬良工，採歸以自奉。", "列箱妻兒爭，堆案賓客弄。", "那知含韶音，未與登禹貢。", "清廟千載勳，鈞天一場夢。", "何如卧巖間，天性得自縱。", "物情我平章，我事誰折衷。", "物我兩忘懷，宴坐聽禽哢。"]'),
('c8ce67c9-36ca-416e-b49c-799f1181e350','遊香山寺','曾丰','宋','宋诗','song-poetry','','[]','二年官番禺，簿領未嘗隙。',288,'全唐诗/poet.song.163000.json','["二年官番禺，簿領未嘗隙。", "一月客晉康，偷閑得兩日。", "太守宣公孫，雅有好客癖。", "相邀乘午陰，共往叩禪寂。", "前驅破暝烟，磴道十餘折。", "草蒙百年街，屋倚千仞壁。", "扳捫到上頭，兩眼眇萬物。", "賓主小夷猶，盃盤大狼藉。", "毋多酌我醇，我渴咽泉瀝。", "毋多食我肥，我饑啗芝茁。", "邇來傷南烹，頗復費北藥。", "坐客笑欲顛，詩人命能薄。", "勸酬互諠譁，問答交戲謔。", "車騎林間馳，衙官松下喝。", "使君倡茲遊，風景業已煞。", "何當學謝安，更有携妓樂。", "流水誰與彈，行雲誰與遏。", "雨來風薄之，其勢飄以忽。", "籃輿不及乘，急著下山屐。", "林梢溜滴巾，石罅泥涴襪。", "皂黥效殷勤，破袖爭拂拭。", "我叱皂黥休，襪巾豈所惜。", "泥非世間污，溜是塵外汁。", "點涴不厭多，愈多愈清絕。"]'),
('1c4f3f3b-65a6-4434-aff2-3d1bd2fe3f4c','寄題左叔寶昆仲松竹書院','曾丰','宋','宋诗','song-poetry','','[]','南窗晃朗宜春夏，松竹與君爲大雅。',160,'全唐诗/poet.song.163000.json','["南窗晃朗宜春夏，松竹與君爲大雅。", "雨雜吾伊聲灑灑，勸君讀書無苟且。", "北窗窈窕宜秋冬，松竹與君爲大忠。", "風雜吾伊聲渢渢，戒君讀書無雷同。", "竹生受虛松受實，根器性天道之質。", "他人見疎君見密，一薰舊染百俱失。", "風雨不移君讀書，由松之實悟竹虛。", "回首書皆糟粕餘，一真超然萬物初。", "松竹於學機相觸，學成終不負松竹。", "拔地摩天立於獨，逃獨歸群成更熟。"]'),
('243f4568-5ac0-4733-bc90-f761e589f30a','歧竹','曾丰','宋','宋诗','song-poetry','','[]','漢關之茅茅之英，豐城之劍劍之精。',195,'全唐诗/poet.song.163000.json','["漢關之茅茅之英，豐城之劍劍之精。", "雙茅雙劍龍變化，一陰一陽數生成。", "我家穉竹老龍殻，中而歧之相掎角。", "玉爪虬爲夭矯枝，金鱗蛻作斕斑籜。", "豈無他處生乾宮，震象爲竹乾爲龍。", "震吾知是乾之變，竹誰謂非龍所鍾。", "瀟瀟聲韻蒼蒼色，余褒二主殘精魄。", "不受冰摧直養剛，無容塵入虛生白。", "夷齊坐看萬物流，不負知音王子猷。", "半夜葛陂雷雨作，二疏欲去終難留。", "君不見震爲龍，又爲竹，竹又爲龍幾翻覆。", "學人笑問玉版師，孰是本來真面目。"]'),
('af09074d-4412-42a1-a873-210e74870460','謝葉英州惠石山更託尋置絕品者','曾丰','宋','宋诗','song-poetry','','[]','梅雨酣夜眠，槐風豁朝起。',288,'全唐诗/poet.song.163000.json','["梅雨酣夜眠，槐風豁朝起。", "應門絕傳聲，外有夸娥氏。", "背負小崢嶸，云自西北至。", "浣櫛出問誰，迺拜公所餽。", "太行王屋山，轉徙到窗几。", "冥莖根倒盤，混沌竅中啟。", "歸墟孔道谺，神瀵留痕泚。", "兩生大丈夫，二老古君子。", "識面喟無從，豈料不我彼。", "一見三扣之，琤若相諾唯。", "燕閒與之俱，庸洗吝與鄙。", "相愛至忘形，相期至沒齒。", "山容若巽詞，猶有勝于己。", "瀟灑舊主人，雅惟無所嗜。", "隕星拾宋都，浮磬收泗水。", "尺寸靡不珍，要作補天計。", "適分上帝符，來守真陽壘。", "山使聽指揮，石侯具供擬。", "三間敞鈴齋，四壁羅玉峙。", "况纔下車初，貢者來未已。", "新傳渤海東，五山失其二。", "神牛驅六丁，挾送函丈裏。", "風骨天下奇，非直我輩比。", "聞之喜欲狂，悵莫立自致。"]'),
('87d97ffe-921c-4098-8f85-d04872a326e8','謝廣東經略潘直閣席間分貺李濟墨','曾丰','宋','宋诗','song-poetry','','[]','竈煤不忌遠，膠汁寧傷清。',288,'全唐诗/poet.song.163000.json','["竈煤不忌遠，膠汁寧傷清。", "永言李廷珪，墨法能爾精。", "滴瀝甚點漆，錙銖輕連城。", "胡陳梁蒲張，俊出聲錚錚。", "敢與相頡頏，江西老潘衡。", "李家颯以頹，中興有雲礽。", "未空天下伎，已擅湖南聲。", "公重與物交，所厚墨客卿。", "摩頂相許意，垂髫久要情。", "信手暗摸索，心已權重輕。", "乃言濟妙處，而有祖典型。", "端如坡借力，獨爲衡主盟。", "笑捐數寸玉，增我雙眼明。", "呼童詔羅文，折簡延陶泓。", "來陪客卿遊，欣然兩相迎。", "涓涓井花落，靉靉江烟生。", "始堅苦莫揉，俄熟恬無爭。", "更請毛錐子，三益相友朋。", "丙吉魏弱翁，姚崇宋廣平。", "剛柔各自稟，勳業交相成。", "我無換鵝手，初不工草行。", "僅能蚯蚓勢，强學蝌蚪形。", "暗投謾費璧，誤點難成蠅。", "不若舊主人，八法俱縱橫。"]'),
('a528bd0a-52e8-463b-993f-05b07140a87e','遞呈餘干郭主簿子敬','曾丰','宋','宋诗','song-poetry','','[]','謂吾多可失之雜，與人連甍或莫識。',216,'全唐诗/poet.song.163000.json','["謂吾多可失之雜，與人連甍或莫識。", "謂吾寡合失之孤，與人傾蓋或莫逆。", "南來豈是無過從，一見如故髯簿公。", "文章未始要著語，造化莫能與爭工。", "半生蓬首黄卷裏，不如略款習鑿齒。", "須臾已幸復期年，咫尺猶思况千里。", "羊城虎城任仃伶，梅嶺不遮夢逢迎。", "隴頭明月向人色，戶外清風敲竹聲。", "漢廷用少公垂老，在我者大官無小。", "餘干縣古簿書少，赤子被聖廝兒擾。", "餘功始可到魚鳥，了事猶癡仍不了。", "笑人莫更爲人笑，我住巴山木之杪。", "急足往來數晡曉，貽詩勿憚相揉矯，吾人能有幾同調。"]'),
('a781adde-b56a-4f22-b122-175eb35dc4e8','贈別曲江貢士李安之五羊相訪','曾丰','宋','宋诗','song-poetry','','[]','南中今士風，似不如古厚。',288,'全唐诗/poet.song.163000.json','["南中今士風，似不如古厚。", "我來長杜門，無日無人扣。", "蠅頭利相關，繭足爭屑就。", "夫君何爲哉，所見乃獨否。", "曳裾投長箋，過眼驚大手。", "晴窗一鑪薰，細與勘關鈕。", "鋒芒已經磨，筋骨猶欠揉。", "舜峰久裒精，韶石俄茁秀。", "蔚爲曲江公，未有繼其後。", "君姑事文章，亦可傳不朽。", "小徒爲秦張，大止到韓柳。", "緬焉洙泗間，道統相授受。", "點破舌頭機，塞斷天下口。", "三傳至孟軻，軻死寂寥久。", "我少有志焉，老未脫芻狗。", "回頭萬物初，著脚諸子右。", "乾坤化氣形，火者水之婦。", "語孟發乾坤，鑰者關之牡。", "鑰通關自開，火徹水自透。", "要令方寸間，可與太虛偶。", "事業出箇中，始得免于陋。", "聖門二三子，十僅能八九。", "儻更出一塵，是爲吾儒首。", "古人責善心，敢以謝吾友。"]'),
('fd75ccc3-20e0-460e-9ad8-7d529e8d4063','邀肇慶府卓司法','曾丰','宋','宋诗','song-poetry','','[]','吾性太率故多可，吾調太僻故寡和。',272,'全唐诗/poet.song.163000.json','["吾性太率故多可，吾調太僻故寡和。", "門前蒲屨率所招，榻上塵生僻之過。", "生平交際二者間，燕處官居長若箇。", "斗升新幸飽自聊，朱墨素慵閑亦頗。", "客來未始不相迎，問無恙外徒默坐。", "與君傾蓋輒破愁，終日對談至忘饑。", "驪龍頷下無數珠，僅容竊拾一二顆。", "江山句裏眼何高，金玉性中天已大。", "雅挾承明金馬資，來爲郡掾得無左。", "蒼梧水口綠一灣，紫石巖前青數朶。", "其間風月分外清，公餘足以供閑課。", "萬古一語思無邪，道盡詩家大關鎖。", "大川三百小三千，源委吾須俱勘破。", "下從樂職泝商那，上自國風沿楚些。", "江西社冷况嶺南，喜得君來與磨磋。", "謝安不笑貧家風，相過當更具茶果。", "話到更闌不欲歸，德公德操同床卧。"]'),
('8ea46f56-697c-489e-a2ec-3c31ed122763','贈別石首尉胡廷直','曾丰','宋','宋诗','song-poetry','','[]','士之所忌忌無末，吾已與交不輕絕。',320,'全唐诗/poet.song.163000.json','["士之所忌忌無末，吾已與交不輕絕。", "士之所貴貴有初，吾未與交不輕結。", "歲在戊申五月間，中都始識胡廷直。", "經史子集蟠屈胸，甲兵錢穀瀾翻舌。", "好賢先主未顧廬，負氣買臣猶詣闕。", "姑調南昌一尉歸，斗升可養子真節。", "功名奮意筆硯間，解后撙齋談不輟。", "烹茶略與論源流，秦未焚書道先裂。", "學統况承八代衰，向之裂者殆磨滅。", "紛紛唐士學古文，僅僅韓公得真訣。", "口傳心授門人誰，劉叉皇甫湜張籍。", "十人摹倣九失真，訣中妙處容有說。", "射御書數學發蒙，忠孝友悌士歸潔。", "探微尤要善擴充，持滿不妨徐發越。", "江出岷山根本殊，風行水上波瀾別。", "茲其爲訣不亦真，韓公所秘吾其抉。", "君歸紬繹細自參，閉門造車出合轍。", "更省蘭臺大聲華，何如麟閣小勳烈。", "衛霍倘能恢土疆，淵雲當爲勒碑碣。", "時有衛霍無淵雲，於漢往往未爲缺。"]'),
('36d86cd9-346d-40b0-9930-7116fdca3c0b','贈豫章來子儀言詩','曾丰','宋','宋诗','song-poetry','','[]','少年氣宇要自恢，見人賦詩謂爲才，出入常將筆裝懷。',240,'全唐诗/poet.song.163000.json','["少年氣宇要自恢，見人賦詩謂爲才，出入常將筆裝懷。", "中年心地要自息，見人哦詩謂爲癖，起居常把口掛壁。", "子儀昌誦得意詩，句中勾我已嬾機。", "多年抱渴滿意沃，半世稱雄望風雌。", "詩源始自葛天氏，三人投足歌牛尾。", "萬象包羅八曲間，國風雅頌其流爾。", "八曲不幸世不傳，傳世僅餘三百篇。", "漢唐作者代角立，庶幾老杜氣渾全。", "本朝詩數江西派，黄公太史爲之最。", "大成未集夷惠行，具體猶微顔孟輩。", "派流到今嗣者誰，青出于藍吾子儀。", "拄杖初擔教門出，便敢呵佛駡祖師。", "我當拗折君拄杖，大家俱以背爲向。", "能出二十四人前，更超三百五篇上。"]'),
('30a148f1-ebf0-4e12-b9aa-7a59dc7a65a6','贈江西瑞上人至南海袖詩相過','曾丰','宋','宋诗','song-poetry','','[]','六祖求衣從嶺出，六祖得衣從嶺入。',272,'全唐诗/poet.song.163000.json','["六祖求衣從嶺出，六祖得衣從嶺入。", "半夜抽身不露機，凹頭解擔猶留跡。", "上人家住江之西，僕僕而南何所覓。", "雅意真誠爲衣求，衣已不傳那可得。", "假令爲法不爲衣，江西自是大法窟。", "挑動上人熟機關，潮音激越箭鋒疾。", "空還即色色即空，佛便是心心是佛。", "心源一了千佛空，底用區區祖衣鉢。", "達摩大鑑無兩身，震旦天竺非異國。", "眼高海僅小泡浮，道大嶺纔微沫結。", "往還始不計西東，入出今何問南北。", "要知飛舄杖筇因，直爲玩山觀水設。", "玄鑰無一勘不同，觀玩之中容有說。", "山數須彌水西江，須口能吸芥能納。", "吸猶不盡納猶餘，未足與談上乘法。", "南海水况多于江，上人無口若爲吸。", "萬一猶有口可開，我先剉斷上人舌。"]'),
('8f7909e9-265b-478b-8aef-99652e5bc1cf','餞司理李季牖','曾丰','宋','宋诗','song-poetry','','[]','天下萬谿山，天上萬星宿。',288,'全唐诗/poet.song.163000.json','["天下萬谿山，天上萬星宿。", "摸索君胸中，往往無不有。", "中原染腥羶，歲月亦云久。", "匪伊丁未年，迺我舊陽九。", "天運窮斯通，國數奇且偶。", "吾皇豈不思，一掃虜之醜。", "金甌玉帳人，未問姓名某。", "天家地理家，新代無老手。", "君才挾兩長，白髮尚藍綬。", "高山有誰知，奇貨難自售。", "鐘鼎頗灰心，斗升容餬口。", "來參清海軍，圜扉草長茂。", "諸公類知音，列剡爭上奏。", "老驥時所須，那復留上廄。", "上穹意難量，往歲機已漏。", "星流爛亙長，地震危裂厚。", "君嘗步且占，憂盛夷衰候。", "虜囚竄歸巢，凶兩迄戡首。", "言之若神然，識者其信否。", "廟堂二三公，寧不欲相叩。", "時哉似難逢，往矣其勿逗。", "道合一談間，功成幾年後。", "乾坤日月新，郡縣版圖舊。", "或遇墳而歸，卷藏白雲竇。"]'),
('3f9db073-46dc-4703-9385-16fa5b048489','瑞芝堂','曾丰','宋','宋诗','song-poetry','','[]','太空生兩儀，羣有函一氣。',228,'全唐诗/poet.song.163000.json','["太空生兩儀，羣有函一氣。", "飛走動植中，往往有常類。", "凡與常類殊，疑類復疑異。", "縉雲開國公，來攝飛輓事。", "乘閑携家人，縱步至臺治。", "三杯晚酣風，一笑春盎地。", "夜闌堂左楹，蒸出芝茁蒂。", "人不慣見芝，疑信初異議。", "詔除九天來，郵傳三日至。", "笑開芝函看，默與芝事契。", "始攝今即真，雖疑亦云瑞。", "那知瑞在人，小物未爲貴。", "我公胸次寬，始與天地似。", "所臨和氣俱，萬彙一一遂。", "江湖淮浙閩，兩稻多不穟。", "廣東十四州，樂國逢稔歲。", "䆉䅉萬里黄，厥瑞吾駭視。", "煌煌楹上芝，茲特瑞之細。", "貽書彭元忠，好作瑞芝記。"]'),
('836d9bb4-ed4b-4473-8c90-e1cd58514d3a','賦馬漕桂巖','曾丰','宋','宋诗','song-poetry','','[]','岱輿山峩東海頭，招摇山峩西海陬。',232,'全唐诗/poet.song.163000.json','["岱輿山峩東海頭，招摇山峩西海陬。", "兩山相望幾萬里，月桂滿巔花長秋。", "羅浮山峩南海岸，道取東西蓋其半。", "銜種非資化鶴功，誰其有力移此粲。", "廣東使者富民侯，函丈雖褊餘清幽。", "眼前開闢一混沌，牆角崢嶸小羅浮。", "侯睨羅浮吞八九，摩挲縮地挾山手。", "雷霆驟下震以驚，贔屭爭前負而走。", "羅浮故與蓬萊連，蓬萊新與羅浮遷。", "瓊瑶古木葉覆地，玗珠老樹枝參天。", "花環實娜涵沆瀣，天上那知在鼇背。", "炎州寖作廣寒宮，鮑肆薰爲香積界。", "元戎大字蟠蛟虯，扁槧爲侯揭殊尤。", "一麗山氏一蒼頡，幸自同與造化遊，何當同與造物休。"]'),
('e20343d1-7f21-47b0-b5e8-b2dea9fc6d0f','送馬少卿自廣東漕易江西憲','曾丰','宋','宋诗','song-poetry','','[]','湖南嶺南迎復送，車上馬上覺復夢。',256,'全唐诗/poet.song.163000.json','["湖南嶺南迎復送，車上馬上覺復夢。", "夜來夢入大江西，山見崆峒水章貢。", "身爲使者似光華，眼厭視之徒倥傯。", "人貪公厭非矯情，外物皆輕吾道重。", "小行吾道幸吾民，楚越已休虞芮訟。", "粵人歡喜未飽間，又覺喜氣吳人共。", "萬牛爭挽楩楠入，初疑選作明堂棟。", "郎星氣焰萬丈長，丞相大嗔凝不動。", "秀才崢嶸風必摧，大材盤礴古難用。", "衮舄尋公公却之，傍人乃獻繡衣頌。", "賓屨今滿河陽門，意其所拔石若溫。", "浴沂豈料先與點，送客有時獨留髠。", "推心置我等子弟，誓報從今到兒孫。", "離情欲噎難忘言，補天自有妙手存。", "區區易節未足論，虎頭不戴貂蟬冠。", "邦人勿癡空攀轅，門人勿癡空戀軒。"]'),
('c808fa75-31b8-4d68-91c8-b89ae8221f8e','託射賦古風獻馬先生','曾丰','宋','宋诗','song-poetry','','[]','淳風轉澆俗，名路成戰場。',192,'全唐诗/poet.song.163000.json','["淳風轉澆俗，名路成戰場。", "所爭劣毛髮，操兵肆相戕。", "兵一出於正，豈不猶可防。", "往往奇與伏，弦控弓斯張。", "况彼射者徒，苟非羿則逢。", "栝釋蓋有度，矢來曾無鄉。", "公以身爲鵠，其鋒若爲當。", "彼初奠而發，所圖中膏肓。", "幸有物相之，僅此皮膚傷。", "新作扶傷歸，痛定不成創。", "梟盧可一笑，勝負已兩忘。", "羿射幾何人，反中砉欲僵。", "引手拔毒矢，終身成沸瘡。", "施報不旋踵，誰謂無彼蒼。", "天下非一羿，願公謹其將。", "毋謂吾有命，更遊彀中央。"]'),
('1d63b5ae-1ee8-411e-bf9f-49e56d197f75','鏡香','曾丰','宋','宋诗','song-poetry','','[]','凌波仙子濃淡粧，六月鑑湖夜乘凉。',160,'全唐诗/poet.song.163000.json','["凌波仙子濃淡粧，六月鑑湖夜乘凉。", "低頭貪照廣寒影，開口失噴清凈香。", "花縣草池漪且淥，疑自鑑湖分一曲。", "若爲仙子不呈身，無乃主人猶負俗。", "新逢好事公子來，十年水鬰一旦開。", "動摇倒影弄金彩，勾引回風生麝煤。", "傑題所扁危亭峙，仙子涵恩勿私喜。", "百里黔甿屈者伸，非徒恩汝數仙子。", "長安得暇遊昆明，紫橐初開有餘馨。", "主人顧影頭尚黑，仙子聞香眼重青。"]'),
('0854cd26-d2ee-443e-a1f5-6985b224ee65','題吳季章挹秀堂','曾丰','宋','宋诗','song-poetry','','[]','造物鼎新開畫圖，江蟠前後山負隅。',128,'全唐诗/poet.song.163000.json','["造物鼎新開畫圖，江蟠前後山負隅。", "一塵不動鷗出沒，萬變無心雲卷舒。", "主人倚坐扶欄立，太清之氣交相襲。", "風烟席上骨毛醒，文字場中星斗濕。", "說詩遷史功日新，江山怪見無精神。", "筆頭收拾珠玉去，夔爲酸鼻河伯顰。", "填胸自有真瀟灑，沃眼更何須外假。", "景饒眼飽欲著書，書成勿示斲輪者。"]'),
('99eaa579-4b71-4e27-9d73-5d01404c9695','贈江宰彥通','曾丰','宋','宋诗','song-poetry','','[]','富沙耆舊江先生，方冊之中久聞名。',288,'全唐诗/poet.song.163000.json','["富沙耆舊江先生，方冊之中久聞名。", "今識其子長安城，中年狀貌老典刑。", "居官不翅冰玉清，未嘗一出清之聲。", "臨事不翅水鑒明，未嘗一示明之形。", "牛刀初割琴初鳴，市稀善獲鮮善烹。", "江華百里農桑甿，陰受令尹生與成。", "尚不能窺豈能評，兩部使者識理精。", "循吏政出吾六經，一元動盪萬彙亨。", "不以能稱乃真能，交章疾置聞朝廷。", "明公歸重蓋如此，素履復修想俱偉。", "立朝致主從今始，廊廟規摹寧出是。", "貞觀三錢一斗米，房杜傳中無可紀。", "事業文章非異軌，誰云解此不解彼。", "學詩反幾我開啟，生平言行詩之理。", "游泳於詩未知爾，國風雅頌興賦比。", "類發於情止於禮，六義同歸一宗旨。", "包涵萬象無涯涘，騎馿覓馿殆忘己。", "子歸反聽收初視，三百篇中參到髓。"]'),
('761919c9-b816-4e4f-8c84-f24dcaa68b5e','書嚴子陵釣臺','曾丰','宋','宋诗','song-poetry','','[]','周家刑不上大夫，法固不足禮有餘。',272,'全唐诗/poet.song.163000.json','["周家刑不上大夫，法固不足禮有餘。", "有才畢願進朝路，非老誰忍迴田廬。", "秦坑學士置勿道，漢嫚大臣視如奴。", "逸民不出朝士去，前有兩生後二疏。", "世祖聰明失之察，待臣少禮多以法。", "尚書曾不免牽曳，御史或猶遭扑撻。", "尚書御史未足論，位至三公危一髮。", "侯霸朱浮僅免歸，韓歆戴涉終見殺。", "先生識帝貧賤時，富貴共之理所宜。", "云胡召至留不住，無乃平日窺其微。", "龍顔之疎顧豈忍，鳥喙所伏那可知。", "當初高蹈疑矯世，落後逆觀信知機。", "退身不勇公孫賀，明泣危機終自墮。", "先生明甚勇如之，天地萬物莫吾挫。", "將星群立客星孤，群恐難調孤易禍。", "帝坐邊頭睡熟間，夢魂已在桐江卧。", "將星炯炯亙今明，不似客星明更大。"]'),
('da54eca8-4f19-4d9b-ad7f-2adf3739107e','題浯溪','曾丰','宋','宋诗','song-poetry','','[]','千古一碑得人愛，來書碑後幾前輩。',208,'全唐诗/poet.song.163000.json','["千古一碑得人愛，來書碑後幾前輩。", "相頡頏甚曾不饒，自混融之了無礙。", "太平天子狃開元，馴致馬嵬悔何逮。", "桑陰未徙宗廟安，儲皇功豈不云倍。", "君父恩重臣子輕，功至彌天皆分內。", "靈武猶言權濟經，京師何忍小間大。", "南內起居不遑安，西宮晨夕無聊頼。", "不沒其實豫章公，言者無罪聞足戒。", "元結但持歸美心，爲尊者諱誰獨怪。", "歸美爲頌刺爲雅，四詩義各有攸在。", "一出春秋雅頌中，兩忘人我是非外。", "朅來獨招莫逆魂，尊中有酒聊一酹。", "垂去更解未艾紛，石上有壁聊一疥。"]'),
('dc60b3ea-6454-4971-9156-40cb37a966af','題丫頭巖','曾丰','宋','宋诗','song-poetry','','[]','婀娜江南大小姑，大姑從兒小從夫。',144,'全唐诗/poet.song.163000.json','["婀娜江南大小姑，大姑從兒小從夫。", "丫頭如許尚從母，學綰雲鬟撩月梳。", "諺謂女生俱外向，丫頭非有難婚相。", "來婿曰贅嫁曰歸，固不敢請豈無望。", "雲鬟久綰行且笄，長成不似從母時。", "擬學小姑嫁夫去，又恐夫蕩去不歸。", "夫去不歸安所仰，終日望夫更惆悵。", "不如老死作丫頭，庶免春閨惡情况。", "丫頭休强笑望夫，世間夢想俱是妄。"]'),
('1c12efa3-cb2c-42ca-b38a-339384897f5a','改秩注縣西歸過上饒見太守同年莫郎中','曾丰','宋','宋诗','song-poetry','','[]','集英殿前始相識，公已策名上通籍。',160,'全唐诗/poet.song.163000.json','["集英殿前始相識，公已策名上通籍。", "銀章朱紱爛映身，鑠我青衫黯無色。", "上饒城裏重相望，公已厭直辭周行。", "皂蓋朱幡炯當眼，鑠我墨綬昏無光。", "浪說同年兄若弟，升沉不翅雲泥異。", "分疎胡越敢尋盟，義重丘山肯忘勢。", "一麾初守虎頭州，差池不及從之遊。", "僅收劉公一尺紙，堪比漢家千戶侯。", "鴉青今襲陳腐語，持以掃門應勿阻。", "遠圖要覓進德方，近效仍求爲縣譜。"]'),
('cfa7054c-3d8e-4f27-b92e-0d1b521e0f6f','寄內','曾丰','宋','宋诗','song-poetry','','[]','已復山上山，何當口中口。',24,'全唐诗/poet.song.163000.json','["已復山上山，何當口中口。", "寫茲秋下心，寄我女邊帚。"]'),
('ea7543cb-b5e6-4ac2-96ac-f7e9e11d001c','送廣西經略應寺丞被命改除歸朝奏對','曾丰','宋','宋诗','song-poetry','','[]','蔚林妖血掃已除，桂林剜肉補未蘇。',192,'全唐诗/poet.song.163000.json','["蔚林妖血掃已除，桂林剜肉補未蘇。", "玉清玄帝右是顧，金華散仙南其驅。", "下車首問民所苦，踴躍近前爭告語。", "醋緡苛歛重傷農，醝鈔抑敷良困賈。", "小斷於獨大叫閽，一呼痛拔百蠹根。", "連營坐卧老將校，萬里耕桑長兒孫。", "足醉於濕殊未醒，奏函頻以中州請。", "十行灑渥下九天，兩踵騰輝輕五嶺。", "五更黄道煙霏霏，追隨列宿朝紫微。", "三寸舌沃萬乘渴，一丸藥起四海痿。", "君臣道合有餘美，乞以屬之門弟子。", "區區撫字得閑功，一一編摩爲野史。"]'),
('68c4e677-6a75-4ad8-b5d7-d5245c4ccfed','長至壽廣西提刑吳大卿','曾丰','宋','宋诗','song-poetry','','[]','無量壽佛今壽皇，家傳室授不老方。',262,'全唐诗/poet.song.163000.json','["無量壽佛今壽皇，家傳室授不老方。", "九轉丹砂一仁念，函四大海爲壽鄉。", "仁氣所覃莫非壽，椿松龜鶴不足當。", "三公九卿百執事，一時幸會俱遐昌。", "公於九卿蓋其傑，向獨年少今未蒼。", "嵩嶽尼山吐符日，長虹失色歸文章。", "骨相巖巖松梅竹，精神凜凜冰雪霜。", "黑精青女殺氣重，終握斗柄持天綱。", "十年伏驥起北漠，萬里飛鸞度南湘。", "掌中名是風憲筆，實與萬物爲春陽。", "二十五州人所禱，萬口一詞壽而康。", "君不見夜來南極星轉芒，又不見朝來南極日轉光。", "日星所會有所應，西州耆舊循南荒。", "百神奔走翊誕慶，萬象森羅印徵祥。", "南人耳目習南事，壽公之意何以將。", "南極從古星不老，南極從今日初長。"]'),
('6c75fc4b-4d7e-487c-ace2-491758808612','勉王堯章歸','曾丰','宋','宋诗','song-poetry','','[]','君氣如鵰不受韝，君才如駿不受輈。',128,'全唐诗/poet.song.163000.json','["君氣如鵰不受韝，君才如駿不受輈。", "摩天歷塊少自許，臣視文潜雌少游。", "場屋小銛大還鈍，掇第未酬方叔願。", "二炊無日足斗升，一擲有時輕百萬。", "買臣一出今幾時，非取富貴誓不歸。", "倚廬固禿孟母髮，織錦更顰文君眉。", "鳳雛知我君之友，相屬逢君試相叩。", "豈有五年山上山，未嘗一日口中口。"]'),
('f3da925e-11e5-4d50-a155-703d556582ab','題胡邦仲霜節堂','曾丰','宋','宋诗','song-poetry','','[]','此君胸固有虛室，六氣薰酣無不適，所稟寧非道之質。',176,'全唐诗/poet.song.163000.json','["此君胸固有虛室，六氣薰酣無不適，所稟寧非道之質。", "此君貌固能圓機，四季變更無不宜，所立寧非聖之時。", "其表無方裏無物，妙與大通相出入。", "清節凌霜特其一，秋風夜雨君曰噫。", "名我字我敢問誰，無乃未爲大相知。", "守節雖賢一於正，聖人達節百其應。", "君亦能賢亦能聖，姑以節論猶失訂。", "標致孤高所持勁，伯夷獨立君制行。", "主人加愛又加敬，根器渾涵所成迥。", "顔子屢空君盡性，客子三嘆更三詠。"]'),
('71df8e42-4b59-482d-b923-c43c66f451d8','題陳宗元立齋','曾丰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','人言禮起於太一，吾言禮止於皇極。',160,'全唐诗/poet.song.163000.json','["人言禮起於太一，吾言禮止於皇極。", "强名皇極體何如，卓然萬象中間立。", "流年鼎鼎三十餘，古人有立君可無。", "克己未追顔所復，過庭猶學鯉之趨。", "五禮同歸一中爾，何當中立而不倚。", "膰肉無來孔子行，皮冠不設虞人止。", "區區行止未足輕，擴充更可輕死生。", "黄壚在前始易簀，白刃垂下猶結纓。", "一有所立百無抗，砥柱中當拍天浪。", "千古不磨立齋名，泰山北斗在頭上。"]'),
('a7f92670-f763-4ff1-b595-83acd3d2734a','題鄔季文送清軒','曾丰','宋','宋诗','song-poetry','','[]','主人胸次風韻勝，萬象皆傾如聽命。',64,'全唐诗/poet.song.163000.json','["主人胸次風韻勝，萬象皆傾如聽命。", "開窗凝目立相招，霽月影從溪響應。", "神迎氣送煩此君，拜嘉有何答殷勤。", "棐几蒲團千兔穎，茶甌酒椀一爐薰。"]'),
('aa4dc704-2615-416f-bc25-2a74afde55e4','寄題夏椿年賞桂樓','曾丰','宋','宋诗','song-poetry','','[]','廣寒韻度中央質，故侍仙娥新見黜。',64,'全唐诗/poet.song.163000.json','["廣寒韻度中央質，故侍仙娥新見黜。", "高天委氣得金行，平地拔身成玉立。", "月下風前爲誰香，諸郎一詠翁一觴。", "功成寄語邵氏子，有西樓後無東堂。"]'),
('53fdcbfa-b4c4-4e7e-9a6e-92e9b68edfb1','題譚氏榮壽堂','曾丰','宋','宋诗','song-poetry','','[]','少年大抵不分老，往往頭白常諱早。',144,'全唐诗/poet.song.163000.json','["少年大抵不分老，往往頭白常諱早。", "千齡一際慶壽恩，白之早者尤其好。", "廬陵太守以名聞，君家堂前翁若□。", "縕之檢渥封倉皇，藍袍霞帔著顛倒。", "捫心歡喜何以加，教子辛勤此其報。", "家人羅拜笑持盃，賀猶未了申以禱。", "數從今始更百年，十年一度迎新誥。", "鄉鄰來致贊喜詞，歸歎鬢髭徒欲皓。", "養子當如譚家郎，吾兒豚犬不足道。"]'),
('ab44b9d6-6731-49c8-9eda-77500d6d5e01','寄題黄舜卿雙溪閣','曾丰','宋','宋诗','song-poetry','','[]','山無背宅宅何勝，門未納溪溪是剩。',136,'全唐诗/poet.song.163000.json','["山無背宅宅何勝，門未納溪溪是剩。", "一閣翬飛若見招，雙溪蟠屈如回應。", "有酒不容閣生塵，無詩莫與溪寫真。", "秋碧澄寒石齒齒，春黄漲暖風鱗鱗。", "有如此水皆詩思，半酣還癢客之技。", "氣之濁者客勿諱，主人胸中有涇渭。", "味之美者客勿矜，主人胸中有淄澠。", "辨入涓滴太分明，醉遊汗漫真混成，客與主人俱忘形。"]'),
('b9869233-76a2-4f2d-a02c-c7aa19c38a5d','用山谷新詩徒拜嘉之句爲韻賦五篇報尹直卿  其一','曾丰','宋','宋诗','song-poetry','','[]','吾土歐陽公，一代不數人。',48,'全唐诗/poet.song.163000.json','["吾土歐陽公，一代不數人。", "文星蜚上天，山川效其珍。", "劉郭相望出，才藻豈不新。", "所恨狃時態，未躡公後塵。"]'),
('2c295d1c-704f-494a-90c9-3ef6f2a0f809','用山谷新詩徒拜嘉之句爲韻賦五篇報尹直卿  其二','曾丰','宋','宋诗','song-poetry','','[]','自唐大曆後，二百年無詩。',48,'全唐诗/poet.song.163000.json','["自唐大曆後，二百年無詩。", "太史豫章公，崛起江之西。", "雖葩卒以正，况淡時乎奇。", "織錦良獨難，但要得錦機。"]'),
('3fb7e6fe-0d4c-46a8-819f-3838b2982927','用山谷新詩徒拜嘉之句爲韻賦五篇報尹直卿  其三','曾丰','宋','宋诗','song-poetry','','[]','名以懶故無，業以病故疎。',48,'全唐诗/poet.song.163000.json','["名以懶故無，業以病故疎。", "但夢華胥國，而友無懷徒。", "百詩一不補，十口九欲癯。", "人所共棄者，子獨何取歟。"]'),
('5175179c-204e-465d-84c9-1e6c9c93500e','用山谷新詩徒拜嘉之句爲韻賦五篇報尹直卿  其四','曾丰','宋','宋诗','song-poetry','','[]','天下文章家，吾州兩前輩。',48,'全唐诗/poet.song.163000.json','["天下文章家，吾州兩前輩。", "內翰擅其宗，大監爲之最。", "更有龍圖公，氣節蓋新代。", "請從舌端參，去作卧下拜。"]'),
('ee29413d-a677-47a3-b054-3329d80e9763','用山谷新詩徒拜嘉之句爲韻賦五篇報尹直卿  其五','曾丰','宋','宋诗','song-poetry','','[]','藍田丞姓崔，華陰丞諱嘉。',48,'全唐诗/poet.song.163000.json','["藍田丞姓崔，華陰丞諱嘉。", "二子不擇祿，雖陋看作華。", "我但欲藏拙，享此亦已奢。", "所期謹回旋，老騻避少騧。"]'),
('1a4e63cf-a6cf-4258-ab9c-533352c5a4ee','寄題張子登遂勤齋','曾丰','宋','宋诗','song-poetry','','[]','一字於吾補不曾，詩書况味冷如冰。',64,'全唐诗/poet.song.163000.json','["一字於吾補不曾，詩書况味冷如冰。", "誰家以此爲長策，不把其它易短檠。", "鍾鼎軒裳眼應白，餘猶要得聖賢力。", "意誠身正一家齊，門中自有華胥國。"]'),
('74868675-36d1-47ed-a7a4-34acffbddb0f','寄題閣皂陳元禮蒼玉軒','曾丰','宋','宋诗','song-poetry','','[]','道山飛落江之瀕，山中草木海上春。',192,'全唐诗/poet.song.163000.json','["道山飛落江之瀕，山中草木海上春。", "鴻濛盤成碧樹勢，沆瀣蒸出瓊芝津。", "辟塵有許猶未愜，更著千百青嶙峋。", "兩三也足况千百，后土不自珍其珍。", "從坤受質外負直，與乾同體中含純。", "表裏灑然相肖似，亭亭物外佳主人。", "鳴珮琅琅夜步斗，握圭挺挺晨朝真。", "音韻危梢壓霰砉，威儀峻節排風竣。", "卷班歸洞門不鑰，世間望之自逡巡。", "遼城翛翛鶴有道，葛陂矯矯龍何神。", "主人與客俱變化，同爲玉皇案頭臣。", "猶餘栖鳳未僊去，不有冥鴻孰情親。"]'),
('d284d259-fc6f-4e39-9a43-1da7e2211723','次黄巖老贈戴昭袒韻','曾丰','宋','宋诗','song-poetry','','[]','太初寂無聞，其中涵大音。',132,'全唐诗/poet.song.163000.json','["太初寂無聞，其中涵大音。", "淵明竊知之，寫以無絃琴。", "曾何入乎耳，無乃聽以心。", "子新嗜聲詩，失寢夜廢衾。", "九死厚所養，五窮發其吟。", "去年抱膏肓，朅來求我鍼。", "機緘與相勘，脈絡歸自尋。", "得之三百篇，喜至不自任。", "詩亡道何之，碔砆亂球琳。", "春秋一中和，異者向與歌。", "詔勿攟芻狗，其傍有師金。"]'),
('e1d2258a-d927-4149-8893-6060ac3ca942','送陳待制自富沙移守京口','曾丰','宋','宋诗','song-poetry','','[]','殿上舊開醫國口，閩中新出活人手。',144,'全唐诗/poet.song.163000.json','["殿上舊開醫國口，閩中新出活人手。", "亙野桑麻水旱餘，連村煙火兵戈後。", "饑得以食寒得衣，召爲之父杜爲母。", "公爲民賦閔雨詩，民爲公立遺愛碑。", "古人祈天翦爪爾，今守禱佛燃臂誰。", "充其不忍寖以大，德之難忘特其微。", "東閩人怪去何遽，南徐人怪來何暮。", "油然無心出岫雲，去來遲速隨所寓。", "漢相無人不曰歸，韋賢未老何時去。"]'),
('afc02e7b-5e25-42cb-8469-7a3538d1cc48','題李克明依綠園','曾丰','宋','宋诗','song-poetry','','[]','主人不制眼之欲，買斷江天猶未足。',96,'全唐诗/poet.song.163000.json','["主人不制眼之欲，買斷江天猶未足。", "更開兩岸小乾坤，而種十洲靈草木。", "江中照出花木真，詩中傳出花木神。", "片言隻字略點化，四時六氣長含春。", "夢草未終俄夢蝶，栩栩羲皇上頭客。", "未覺身居安樂窩，那知園是華胥國。"]'),
('563a13cb-0379-454f-a7f3-e6588b081fab','寄題全國輔竹溪清寓','曾丰','宋','宋诗','song-poetry','','[]','亭前軋軋日百輿，橋上剝剝日萬屨。',128,'全唐诗/poet.song.163000.json','["亭前軋軋日百輿，橋上剝剝日萬屨。", "莫非失脚聲利然，誰復回頭情性故。", "子雲一區二者間，講玄之外何所關。", "江山有我目迎送，魚鳥無他心往還。", "玻璃橫眠蒼玉立，開關不信塵敢入。", "太無在上吞以胸，羣有來前挫於筆。", "筆端胸次患不清，一過於清天所憎。", "推歸玉笋頭邊立，送去金鰲背上行。"]'),
('375d20f5-7b75-4a57-96fd-278dadf9ecc8','遊桃花臺寺僧指似葛仙翁煉丹處','曾丰','宋','宋诗','song-poetry','','[]','昔爲仙翁宅，今作梵氏家。',132,'全唐诗/poet.song.163000.json','["昔爲仙翁宅，今作梵氏家。", "桃花太俗生，釋老安取耶。", "物原出平等，人自分品差。", "我來與時違，有桃却無花。", "舊來花片紅，散落爲流霞。", "中有結實者，往往成丹砂。", "仙人食之餘，雞犬輒爭譁。", "翔鸞久霄漢，廢竈空塵沙。", "殆欲從之遊，龍髯不容拏。", "擬作武陵記，恐謂漁父夸。", "坐陪老上人，晚烟煮春芽。"]'),
('0db9c47c-82fe-472c-bd8e-2026a23e0101','小憩月華寺問智葯眉山兩公遺跡','曾丰','宋','宋诗','song-poetry','','[]','韶溪經其前，曹溪緯其背。',192,'全唐诗/poet.song.163000.json','["韶溪經其前，曹溪緯其背。", "崢嶸兩溪間，月華得吾愛。", "開山不知誰，立屋已忘代。", "寺碑兵火餘，斷石猶未廢。", "始淂智葯公，與法作無礙。", "梁題烟煤中，殘墨猶未敗。", "始得眉山公，與寺爲不壞。", "餘詩謾贅疣，滿壁空癬疥。", "我生遲百年，生與眉山背。", "鳥爲嬌人聲，山作傲物態。", "老大堂頭僧，曾受智葯戒。", "試從言下挑，要看急中對。", "寺以月華名，中包法沙界。", "方當月未生，敢問華安在。", "得月而忘華，堂頭大機械。", "更和月也忘，始出機械外。"]'),
('3cbea181-9dfa-467d-bea5-03c750012bcf','道人彭永年來番禺過訪相約歸日遊閣皂','曾丰','宋','宋诗','song-poetry','','[]','雅性苦無他嗜好，山之佳處吾皆到。',256,'全唐诗/poet.song.163000.json','["雅性苦無他嗜好，山之佳處吾皆到。", "江西山半入詩中，點檢怪猶無閣皂。", "吾家十世江西居，南來始得閣皂圖。", "堊文橫斜水曲直，煤汁濃淡山榮枯。", "燕閒指顧圖之上，神遊滿意酬心賞。", "已空沙界無大千，那信滄溟有方丈。", "詩仙來往白雲鄉，惟沈廷瑞伊用昌。", "畫簾捲舒納夜月，金鼎開闔吞朝陽。", "兩篇之外有餘景，孟陽摹寫得要領。", "或云圖是無聲詩，猶將幻夢對泡影。", "撙齋或是武夷曾，道人未必非老彭。", "相逢恍惚似前世，一笑舂容話長生。", "大道一成百無恐，仙家猶被死生動。", "逃劫莫如徐佐卿，山行未免飛矢中。", "道人詞詘不敢爭，殷勤約我遊青城。", "橫江孤雁飛且鳴，便是道人出相迎。"]'),
('b728898a-ce53-4a76-a3bf-ae6558250ea0','苫廬','曾丰','宋','宋诗','song-poetry','','[]','吾息乾坤之委氣，吾身父母之委蛻。',176,'全唐诗/poet.song.163000.json','["吾息乾坤之委氣，吾身父母之委蛻。", "乾坤父母不易酬，身體髮膚可輕棄。", "文學恨不隨父終，視七尺軀鴻毛同。", "未容忘形禮制外，猶復假息苫廬中。", "萬物莫移三載志，屋上有漏中無愧。", "蛇容有識寧受欺，鶴固非凡豈容僞。", "蛇爲仰向鶴俯臨，吾鄉人始知吾心。", "朝譽未如鄉譽重，人知不似天知深。", "外臺樂爲上其事，吾君吾相相與記。", "非渥其恩奚以厲，占鵲卜燈言喜至。", "兒孫殊不解吾意，以榮爲孝孝之細。"]'),
('443e7997-d1c6-42ff-92ad-ad0d76137060','寄題劉漢英雙清亭','曾丰','宋','宋诗','song-poetry','','[]','渾淪一段輕清氣，天收不盡歸於地。',64,'全唐诗/poet.song.163000.json','["渾淪一段輕清氣，天收不盡歸於地。", "凝者爲山融者溪，攬之可使凡骨蛻。", "主人著亭溪山間，心與溪山相往還。", "市朝有欲叩以事，魚鳥不容入其關。"]'),
('6d77dc22-5fdb-4299-bb64-13a566d9bf44','送汪永豐被薦解組還朝','曾丰','宋','宋诗','song-poetry','','[]','等之土蒲同，他豈不云便。',288,'全唐诗/poet.song.163000.json','["等之土蒲同，他豈不云便。", "顧寧圖此君，曾不鄙吾縣。", "小折彭澤腰，仰看督郵面。", "何以剸爾繁，胸次剛百練。", "何以活爾癃，筆下丹九轉。", "堂上琴晝彈，境中枕宵奠。", "那知彼魏相，不謂吾宓賤。", "物議任物情，處之以無辯。", "吾事盡吾心，持之以無倦。", "木秀風必摧，水清石自見。", "論定無後言，政成有公薦。", "萬萬字民心，聊復書四卷。", "概之六經然，意視文更善。", "掇置黄麻中，專美學士院。", "萬萬字民功，聊復碑一片。", "概之輿議然，實視聲更羨。", "掇置青編中，專美循吏傳。", "行車氣駸駸，卧轍心戀戀。", "中牟滿考回，太傅獨班見。", "採珠有相酬，懷玉毋自衒。", "我以無聊歸，茲其不勝羨。", "已已長杜門，行行穩乘傳。", "相望道何脩，相送足何殿。", "缺然物將誠，聊爾詩當餞。"]'),
('e64b5782-862e-41a7-92fd-4edaa8528961','贈相者趙椿年','曾丰','宋','宋诗','song-poetry','','[]','胸次無諸塵垢障，眼中有爾光明藏。',64,'全唐诗/poet.song.163000.json','["胸次無諸塵垢障，眼中有爾光明藏。", "云何不策反照動，小而用之風鑒上。", "伎倆君參不二門，形骸我入無色相。", "相逢尊酒更杯茶，其它口耳從俱喪。"]'),
('d1489982-ca69-435b-9526-3cfce65d9ef4','寄題劉永年桂堂','曾丰','宋','宋诗','song-poetry','','[]','四時之氣秋氣清，月之掬之水中精。',152,'全唐诗/poet.song.163000.json','["四時之氣秋氣清，月之掬之水中精。", "四時之月秋月明，桂之掬之木中英。", "沆瀣蒸開黄爛熳，分似群仙清鼻觀。", "君家誰會術之幻，乘夜入月移此粲。", "微風透簾日透窗，老葉弄縹花弄緗。", "翁在中央季在旁，讀萬卷書字字香。", "顫閼四開香入髓，薰融人欲發天理。", "鯉伋點參賢父子，傳芳後葉殊未已。", "一枝五枝聊自詭，郄家竇家勿相侈，劉家正恐不免耳。"]'),
('3b0a8c1e-389c-4a88-9ac8-083fc35b883d','題馮行之雙溪書房','曾丰','宋','宋诗','song-poetry','','[]','鴈峰之水蒸若湘，虎城之水貢若章。',96,'全唐诗/poet.song.163000.json','["鴈峰之水蒸若湘，虎城之水貢若章。", "雙水朝宗氣浩浩，諸生讀書聲琅琅。", "葛溪支派小雙水，馮君領會水之理。", "東西决流二本非，左右逢原兩端是。", "開窗觀瀾參浴沂，涵泳無往非聖涯。", "水哉水哉不盡意，歸歟歸歟有餘師。"]'),
('742e6f59-feb7-47c1-9548-8c14eea5e4d0','題宜黄鄒聖言宜雨亭','曾丰','宋','宋诗','song-poetry','','[]','佳人一代傾城色，和氣醺酣更塗澤。',64,'全唐诗/poet.song.163000.json','["佳人一代傾城色，和氣醺酣更塗澤。", "臙脂凝汁覺差濃，頤頰盎光疑太赤。", "水沉浴罷餘精神，蕩去人僞還天真。", "東風吹開巫峽雨，西子化作陽臺春。"]'),
('73d2af51-dfa4-4499-b6ad-c225d280aeb0','贈相士陳道人','曾丰','宋','宋诗','song-poetry','','[]','道人滿藏是光明，况問麻衣乞得靈。',64,'全唐诗/poet.song.163000.json','["道人滿藏是光明，况問麻衣乞得靈。", "眸子外無餘造化，士人中有幾公卿。", "愛名者十忌者百，逢人言失物言得。", "試指一賢眉裏黄，管招群枉眼中白。"]'),
('6472ba91-a3f3-4490-8a48-26b8a46ac4cd','題永豐鄭丞梅澗','曾丰','宋','宋诗','song-poetry','','[]','分陰分陽天得清，生水生木清降精。',195,'全唐诗/poet.song.163000.json','["分陰分陽天得清，生水生木清降精。", "懸知梅與澗爲一，交涵互養清難名。", "客來强立痛題目，擬之萬物無一足。", "巢許立身今古高，夷齊受命乾坤獨。", "主人氣與梅俱移，平淡之中餘崛奇。", "藍田松竹須品題，今年隨牒梅勿疑。", "主人心與梅俱化，高潔之中餘藴藉。", "瀛洲風月須摹寫，明年入朝梅勿訝。", "獨不見淇竹主人衛武公，出相周家了勳庸。", "老矣歸與奉從容，主人與竹俱高風。", "武公與竹爲不朽，萬古淇奧詩一首。", "主人有以爲梅壽，我請置之淇奧後。"]'),
('77e25853-4a28-40eb-842c-e90fde45fe20','題永豐吳尉當山亭','曾丰','宋','宋诗','song-poetry','','[]','家居所至與山對，官居所至與山背。',96,'全唐诗/poet.song.163000.json','["家居所至與山對，官居所至與山背。", "眼中悔失真崢嶸，得其似者宜加愛。", "尉僊三令姦膽寒，突兀數椽答清閒。", "誰橫荒壘簷以外，自覺幽趣山之間。", "有一段清無點俗，當山也是清題目。", "不道尉僊心更清，杖屨當車蔬當肉。"]'),
('3a682e2b-7bef-4af1-a9d7-6ddb4ddd5da9','題張仲寅甘老堂','曾丰','宋','宋诗','song-poetry','','[]','功名鏡裏猶黑頭，誰子速之營菟裘。',152,'全唐诗/poet.song.163000.json','["功名鏡裏猶黑頭，誰子速之營菟裘。", "四朝元老人姓周，掃三大字蟠蛟虬。", "元老之門幾從遊，天上公子第一流。", "十論較之過秦優，記室有勞無束脩。", "郊霈異恩小相酬，過而睨之海中漚。", "從渠進進吾休休，胸中一壑復一丘。", "酒發詩豪不宜搜，風月自與毫端謀。", "木奴竹君歲所收，不翅漢家千戶侯。", "歸哉老矣餘何求，舐蜜啖蔗味悠悠，孤松野鶴無春秋。"]'),
('dff6ad50-7636-4b9b-8a16-6f80b378f263','賀廣東漕使黄郎中生朝','曾丰','宋','宋诗','song-poetry','','[]','紫石仙翁骨道清，丹成往往步步輕。',144,'全唐诗/poet.song.163000.json','["紫石仙翁骨道清，丹成往往步步輕。", "黄石仙翁道眼明，書成往往字字精。", "丹成書成俱是實，猶墮於偏非至道。", "二者兼之白石□，先生渠謂天草草。", "天皇案前黄老君，輟與人皇爲老臣。", "老郎老君之後身，收拾乾坤平月春。", "春吾身外春吾民，四民無一不春者。", "與士爲春頌風雅，書於白石其土苴。", "白石肉飛不尸假，弟功書在丹之下。"]'),
('aa6a8353-1e67-4eb7-9f4b-15c001fc5904','曾德禮墨梅竹篆隸皆精歲在己未示似墨梅酬價固非所吝會即赴官嶺表度難自隨還以授之副之古風','曾丰','宋','宋诗','song-poetry','','[]','北枝頑頓如不仁，南枝警敏如有神。',128,'全唐诗/poet.song.163000.json','["北枝頑頓如不仁，南枝警敏如有神。", "方當群有急歸宿，忽自太無偷發春。", "畫畫清脩枝拔萃，點點精明花引類。", "幻盡歲寒姿者天，吾宗所幻天相似。", "溪邊照水周逸民，簷下橫窗晉詩人。", "胸次還餘墨外墨，筆端更寫真中真。", "把南金報猶輕議，舉趙璧歸非厭嗜。", "只今隨牒廣之南，彼大庾山吾畫笥。"]'),
('b3cd8352-8bdb-4c7f-b37f-5d964cf7890d','贈南豐胡國華','曾丰','宋','宋诗','song-poetry','','[]','軍山未信旴水屈，清淑之氣相盤鬰。',64,'全唐诗/poet.song.163000.json','["軍山未信旴水屈，清淑之氣相盤鬰。", "天地有時不關防，古今何代無人物。", "道德大成文小成，君小成者成者精。", "逢人問我江西派，從此南豐不是曾。"]'),
('57057c66-1587-4c81-a0a7-5a1b88bcce5a','過滕弔秦','曾丰','宋','宋诗','song-poetry','','[]','潯流容派兩江口，中有一城大如斗。',128,'全唐诗/poet.song.163000.json','["潯流容派兩江口，中有一城大如斗。", "埤堞甎抏土藉隍，樓臺瓦潰泥漫霤。", "入言淮海初到時，江獻其清山獻奇。", "彼私得之既以去，今幸存者皆其遺。", "古藤陰下非眠處，肆言成讖終還悟。", "末禍休冤黄綬欺，初謀已被儒冠誤。", "眉山處喪與得坎，朱崖儋耳全吾身。", "孰知淮海造三昧，猶與眉山隔一塵。"]'),
('f7daff80-46e1-4d74-8fb5-0f854f39f69e','陳刪定日華除廣東憲取告中志深考古之語扁齋曰考古齋','曾丰','宋','宋诗','song-poetry','','[]','東都有人持漢斧，南國無人繫周圄。',160,'全唐诗/poet.song.163000.json','["東都有人持漢斧，南國無人繫周圄。", "未從刀鋸宥者三，先即桁楊聽之五。", "五三異念同一仁，聖賢典故公日新。", "心從仁上勘得道，筆與民間點爲春。", "百未試一刑幾厝，忘其勞績况恩數。", "天語疑由公出然，公心默與天通故。", "持平已遂留何須，責難未了歸可圖。", "課效九章三章外，游心千古萬古初。", "剖斗折衡還未可，非綿蕞莫矯叢脞。", "結繩之外畫冠餘，作古幸無嫌自我。"]'),
('d08b60b9-0595-4ad1-bc86-dc6d78bee836','南康劉尉於廳事之東開軒曰清瀨蓋取其前松聲然也','曾丰','宋','宋诗','song-poetry','','[]','坐曹在西退食東，一間然爾萬不同。',176,'全唐诗/poet.song.163000.json','["坐曹在西退食東，一間然爾萬不同。", "彼無乃俗飽吾聒，此不勝幽醒我聰。", "不律不呂自中節，非夔非襄誰傳宗。", "意其金沙澒磅礴，否則銀漢鍧穹窿。", "開窗即之辨所以，老松不受風所攻。", "松莫之禦非自虣，風無所爭不相容。", "二者無心一有感，自然成聲關大通。", "混沌之竅君之耳，松風觸處天機融。", "聲之真者非固有，况復流歸形似中。", "潺潺㶁㶁蓋其似，得真忘似君新功。", "更收吾耳聽以氣，一掃從前真似空。"]'),
('3344dae9-c9ed-4d6b-bd7f-38a9a40cd4fb','郭熙畫圖四詠 冬雲密雪','曾丰','宋','宋诗','song-poetry','','[]','湖玉幻山濁界，羞將遮肉眼，清都贏得破天顔。',53,'全唐诗/poet.song.163000.json','["湖玉幻山濁界，羞將遮肉眼，清都贏得破天顔。", "公收點墨輕丸玫，燠館凉臺侑詩酒。", "肆觀群有抱寒根，似我身心退閑後。"]'),
('d2cc3d54-5251-477b-a2a9-dbfcdd4d652d','代人題瓊守歸疆堂','曾丰','宋','宋诗','song-poetry','','[]','前朝列聖規模大，雨露涵濡山海外。',160,'全唐诗/poet.song.163000.json','["前朝列聖規模大，雨露涵濡山海外。", "椎卉之民半冠带，恬不復它餘百載。", "前守諸公方畧偏，藩籬漫浪耳目前。", "版圖之地半腥羶，恬不復誰餘百年。", "白囊新報潢池弄，詔公借我海南重。", "金鼓戒嚴曾未動，汶陽田已歸禹貢。", "功成不居頌者誰，樂石雖堅有泐時。", "亙千餘里兒童知，牢不可解去後思。", "歸歟更了中原事，抵掌挈還河朔地。", "竹書不盡帛相繼，回頭今刻公之細。"]'),
('0ed366b1-f3dd-45fe-a605-6d24ce5aaa47','過南安接孟使君辭警策多矣復承遣詩追惠遂足度嶺所賦梅還謝萬一','曾丰','宋','宋诗','song-poetry','','[]','坤元分氣謂無間，南崖北崖纔尺寸。',144,'全唐诗/poet.song.163000.json','["坤元分氣謂無間，南崖北崖纔尺寸。", "地寒地暖差之半，乾元分氣謂無頗。", "南枝北枝能幾何，春早春遲差爾多。", "我來幸未全失策，南枝早退不留跡。", "北枝晚出猶弄色，驚見北枝問南枝。", "寒香羞受時輩知，隨清風入孟郊詩。", "詩之視梅類高致，孟之視詩渾細事。", "至大至剛浩然氣，其詩拔我塵埃餘。", "其氣充我情性初，吾自覺吾非故吾。"]'),
('16544083-a73a-448e-8621-97743ac6cebe','題致政李子立問月臺','曾丰','宋','宋诗','song-poetry','','[]','主人詩豪寄於酒，萬象無非酒之友。',144,'全唐诗/poet.song.163000.json','["主人詩豪寄於酒，萬象無非酒之友。", "主人酒豪寄於詩，萬象無非詩之題。", "若爲詩酒興俱發，平時泛愛今一割。", "不問其他偏問月，月不長如日星然。", "乍望乍朔乍晦弦，要之缺者多於圓。", "主人乘風踏鵬背，方在急流俄勇退。", "似月之明居以晦，舉酒相邀傾酒醉。", "問耶對耶此其概，收光反耀照其內。", "妙與道俱不容喙，主人無問月無對。"]'),
('4abe0e90-5d9f-41f2-bcfb-b27ccff7c7e0','壬戌仲春隆慶因老留上藍與璉老往還余續至相過浹旬言別','曾丰','宋','宋诗','song-poetry','','[]','山立堂堂古白眉，一龍一象殿江西。',96,'全唐诗/poet.song.163000.json','["山立堂堂古白眉，一龍一象殿江西。", "春秋多寡弟兄是，朝暮往還賓主誰。", "籐坐蒲團邀二妙，其間著我成三笑。", "無夏無夷跡自融，不儒不釋心相照。", "遠公送出如欲留，陶令辭行如欲休。", "殊覺上藍今勝踐，少分前輩舊風流。"]'),
('687eb3e3-bc5b-4663-af78-3a63f68ec1d7','豫章上游生米市前江中洲上至德觀側柏樹甚老','曾丰','宋','宋诗','song-poetry','','[]','何命之薄彼哉柏，豈無生處生於石。',96,'全唐诗/poet.song.163000.json','["何命之薄彼哉柏，豈無生處生於石。", "老去根猶强自爭，春來石豈能相戹。", "蛟龍拔入盤重淵，雪霜放出參九天。", "至大至剛劫火後，彌高彌邵妖風前。", "道人澹嚥得吾味，久馭清風騎紫氣。", "吾骨到今猶未蛻，庭前自適西來意。"]'),
('cc11d5bd-15c0-4edf-8fe0-ce4eea795878','正月雨雪','曾丰','宋','宋诗','song-poetry','','[]','少陽當進猶自抑，老陰當退猶自激。',64,'全唐诗/poet.song.163000.json','["少陽當進猶自抑，老陰當退猶自激。", "煦煦纔融地出青，颼颼又肅天生白。", "一曝十寒權在天，春行冬令風弄權。", "我欲問天去天遠，懶能更上訟風篇。"]'),
('85391d4b-c128-4843-8436-720435ccceb1','龍州書院','曾丰','宋','宋诗','song-poetry','','[]','西昌有洲龍屈蟠，爪牙潤澤鱗甲寒。',128,'全唐诗/poet.song.163000.json','["西昌有洲龍屈蟠，爪牙潤澤鱗甲寒。", "桃花水肥意騰躍，似欲上與青天干。", "西昌有士龍變化，雲可以乘泥可謝。", "臚傳未放雷嗚春，弦誦猶挑燈破夜。", "作成况遇今趙侯，螢窗開處吞龍洲。", "儒風相高踏鵬背，士氣自敢騎鰲頭。", "縣前洲觜年年長，圖讖會當應如響。", "鴈塔固無過我前，雲臺更要在人上。"]'),
('c383c57b-f468-4617-9de1-72e74f902c15','舟行過龍騖洲舟人指似桃花林滿山爛漫','曾丰','宋','宋诗','song-poetry','','[]','一團烟火百十家，一叢林木千萬花。',96,'全唐诗/poet.song.163000.json','["一團烟火百十家，一叢林木千萬花。", "浪遊那料有奇遇，似入武陵眼生霞。", "詩人多愛疑可賞，舟人多忌戒無往。", "中途還未免迷行，初意得無成妄想。", "漁翁禪伯花所私，成仙成佛未可知。", "花今於我有大造，六幅歸帆春水肥。"]'),
('605eb603-8b6c-4e18-9fb1-35594c1497ac','題王欽州子澤雙清閣','曾丰','宋','宋诗','song-poetry','','[]','馬蹏車轍前門外，江聲山色後堂背。',96,'全唐诗/poet.song.163000.json','["馬蹏車轍前門外，江聲山色後堂背。", "左手持盤右把杯，家人怪問翁何在。", "小閣崢嶸負後堂，圖書左右翁中央。", "一塵不容犯眼界，萬象無計逃詩囊。", "蚤作從渠醉名利，夜卧從渠夢朝市。", "一詠之餘更一觴，翁兮醉夢華胥氏。"]'),
('ba9c37b0-8182-4691-ac40-04a11b884dba','遊曾無慍園可賦者十餘處其大莫如樂山次莫如滄洲畫趣先課二古風 樂山','曾丰','宋','宋诗','song-poetry','','[]','至靜之體首歸坤，自乾德外坤爲尊，吾宗有志未敢言。',136,'全唐诗/poet.song.163000.json','["至靜之體首歸坤，自乾德外坤爲尊，吾宗有志未敢言。", "至靜之體次歸艮，自坤德外艮爲近，吾宗有志不容遜。", "磊隗胸中自□山，外觀更具山之間。", "表裏相融艮機關，彼萬泪隨吾屹立。", "堂中人與山爲一，雖介于石不終日。", "無心聊與雲俱出，傅巖沃雨商郊乾。", "林然蠢爾涵殊恩，老後閑身霽後雲，㟏岈深處歸根□。"]'),
('e8e9ea6d-76d2-41ed-9886-0f7111c15c05','遊曾無慍園可賦者十餘處其大莫如樂山次莫如滄洲畫趣先課二古風 滄洲畫趣','曾丰','宋','宋诗','song-poetry','','[]','一身超忽白雲表，雙眼低回白蘋杪。',112,'全唐诗/poet.song.163000.json','["一身超忽白雲表，雙眼低回白蘋杪。", "沙隨風捲黄莫涯，草與天連青未了。", "摩詰胸中幾麋丸，詩寫其真更留殘。", "破除桑落斗升後，收入鵝溪尺寸間。", "想象訾家聊寓目，指顧瀛洲方策足。", "中人宜在瀛洲宿，中宵夢在滄洲浴。", "覺寫兩洲爲一軸，馳譽丹青從謂俗。"]'),
('ab3e5a6e-b395-4132-bf7e-8416194707b7','題蕭叔原江山圖畫','曾丰','宋','宋诗','song-poetry','','[]','玻璃橫眠蒼玉立，一段清姿天幻出。',152,'全唐诗/poet.song.163000.json','["玻璃橫眠蒼玉立，一段清姿天幻出。", "霞作丹漿雲墨汁，恢張太素以爲質。", "一時盤古縱橫筆，萬古玄冥濃淡色。", "乾坤兩間一亭中，立人自下酬答功。", "酒盞碁枰意氣充，薰爐茗椀情性融。", "耳閼目閼還大道，聲塵色塵入長空。", "客來且伴主人醉，機械客猶梏仁智。", "未知二者一之贅，休言一者贅之細。", "上人已悟細之至，何當更悟也無細，若至之謂□□□。"]'),
('c686cee8-66e2-410b-9586-4483dcaae4b4','陳良臣之子正功肯學能文求余印可','曾丰','宋','宋诗','song-poetry','','[]','學探玉甃千仞井，筆扛龍文百斛鼎。',64,'全唐诗/poet.song.163000.json','["學探玉甃千仞井，筆扛龍文百斛鼎。", "歸根可以後冥莖，發刃難於先肯綮。", "點鐵要之便成金，即心是道道是心。", "一案孔門重勘結，小圓爲賜大爲參。"]'),
('d33cdfb3-a651-45eb-882a-ad7d25a65ae3','儒家子劉文叔詩見贈回贈一篇','曾丰','宋','宋诗','song-poetry','','[]','我詩求我混沌初，君詩求我糟粕餘。',64,'全唐诗/poet.song.163000.json','["我詩求我混沌初，君詩求我糟粕餘。", "低頭小參有頓漸，撫掌大笑無精粗。", "誰收六律入三籟，更歛八風歸一噫。", "四詩元自五聲生，無聲敢問詩安在。"]'),
('e2e1fa58-d7c6-4565-b3c6-8d1ef34a2b31','寄題雙清亭','曾丰','宋','宋诗','song-poetry','','[]','玻璃橫眠蒼玉立，不容朝市一塵入。',96,'全唐诗/poet.song.163000.json','["玻璃橫眠蒼玉立，不容朝市一塵入。", "魚泳鳥飛自薦揚，舟來車往誰收拾。", "主人瀟灑宅一區，子弟何師受何書。", "馬遷史裏萬古具，張說詩中四時俱。", "詩編史帙一關目，姑掇餘清清冰肉。", "床頭拈出周易讀，更悟太清清蛻骨。"]'),
('a89ac8e5-d8a9-4e0c-9641-8e9cf75437f6','壽錢樞密','曾丰','宋','宋诗','song-poetry','','[]','長至之前風飋䫻，斗初建亥扃群物。',144,'全唐诗/poet.song.163000.json','["長至之前風飋䫻，斗初建亥扃群物。", "從春至冬推歲律，十二月中一良月。", "既望之餘氣氤氳，月初生魄鍾異人。", "從武至文數朝紳，三千臣中一良臣。", "誕彌先後僅三日，明主良臣豈徒出。", "虜舊陸梁新勃窣，廟算宸謨關宥密。", "帷幄精神運籌餘，門闌氣燄懸弧初。", "壽觚有量吞江湖，壽詞無技雕瓊琚。", "姑容夷夏一家日，更□君臣千載圖。"]'),
('e567e488-7ca0-4052-800e-2fa825e46079','敬賦黄萬安肅父五雲閣','曾丰','宋','宋诗','song-poetry','','[]','一合乾坤羅萬象，中有連天雲錦帳。',128,'全唐诗/poet.song.163000.json','["一合乾坤羅萬象，中有連天雲錦帳。", "分光日月兩輪間，聚蔭神仙十洲上。", "盤緗錯縹天上無，若爲雲錦如許都。", "媧皇鍊石補天了，倥傯不及收其餘。", "織女得之資以幻，手與目謀生燦爛。", "使君寄下召還祥，令尹收爲公退翫。", "登臨輒翫罷輒忘，令尹胸中自含章。", "製錦猶餘五色綫，歸朝可補堯衣裳。"]'),
('a664c6fa-9884-473f-92dc-1ed992d2df74','題李師儒上舍稽古堂','曾丰','宋','宋诗','song-poetry','','[]','今人不足與之謀，心向三都以上遊。',96,'全唐诗/poet.song.163000.json','["今人不足與之謀，心向三都以上遊。", "有集可明經子史，無秦那別夏商周。", "心融口笑先儒泥，一萬餘言解三字。", "粹精還我聞未聞，糟粕從渠味無味。", "懸知書者古之餘，稷契臯夔讀何書。", "猶期立脚群賢上，更請回頭萬物初。"]'),
('c41ae92d-708c-4c86-ab00-997144b37d8e','壽富陽宰','曾丰','宋','宋诗','song-poetry','','[]','秋途琴劍留東坰，午夜齋房發西櫺。',234,'全唐诗/poet.song.163000.json','["秋途琴劍留東坰，午夜齋房發西櫺。", "協氣橫流太白嶺，祥光上屬長庚星。", "詰朝廉訪太丘長，三千珠履羅芝庭。", "誕彌厥月衆所賀，止或尼之豈忘情。", "飲君以蜀州竹葉之酒，食君以酈縣菊花之英。", "採英探酒非俗事，敢煩素素相卿卿。", "既多且旨奉以進，乃賡載歌坐而聽。", "酒有香于以却君之宣髮，英有味于以制君之頹齡。", "爬搔黑頭戴大豸，磨切齠齒吞長鯨。", "二十四考相唐國，一百六歲侯羅城。", "貂蟬何加外望重，鍾鼎不屑初心輕。", "拔脚歸尋耕釣盟，割棕爲笠藜爲羹。", "一洗重蓋兼珍腥，吾身吾口已中清。", "露頂灑風漱泠泠，更與赤松俱長生。"]'),
('e67c3b49-a09e-46b7-8ba8-67e54d2bda25','應童子科歐陽文成覓詩漫以塞責','曾丰','宋','宋诗','song-poetry','','[]','廬陵童子謂姓李，臨川童子謂姓王。',184,'全唐诗/poet.song.163000.json','["廬陵童子謂姓李，臨川童子謂姓王。", "二子讀書選德殿，氣吐虹蜺口翻漿。", "六經諸子成串落，天子喜之移御床。", "奏對首肯去目送，青衫黄牒恩異常。", "江西得此二童子，後生氣倍聲名場。", "前聞但有晏元獻，今繼者誰其歐陽。", "身軀眇小膽氣大，齒髮幼艾言語蒼。", "况能大書開龍蛇，一字欲作千尺强。", "明年試罷春晝長，低頭拾官回未忙。", "馬蹄輕踏百草香，鶑花助喜酒助狂。", "長裾短刺傾侯王，早著歸鞭榮故鄉，我其俟之螺水傍。"]'),
('f7106289-1031-4989-82b9-262597dbe89d','題顔慶遠三友亭','曾丰','宋','宋诗','song-poetry','','[]','天一生水清之精，天三生木清之英。',104,'全唐诗/poet.song.163000.json','["天一生水清之精，天三生木清之英。", "他清可備吾題名，不得精英未爲清。", "顔子園中亭突兀，遠橫一水近三木。", "取其近者供所欲，太清也自生毛骨。", "餘豈無友非歲寒，歲寒之友天數三。", "主人更與三者參，天合人合清相涵，四清之清俱不凡。"]'),
('35d2f42b-40f6-4456-a0d6-50dade4ee5a2','題歐陽君舉進修堂','曾丰','宋','宋诗','song-poetry','','[]','輕一尺璧重寸陰，白千丈髮丹寸心。',64,'全唐诗/poet.song.163000.json','["輕一尺璧重寸陰，白千丈髮丹寸心。", "假途游夏時汲汲，歸宿淵騫日駸駸。", "速肖無拘渠七十，近取莫過吾六一。", "氣節追還慶曆風，文章增廣廬陵集。"]'),
('082d23c9-2b68-4dc2-b679-d2c752b9183c','題黄萬安治東樓詩','曾丰','宋','宋诗','song-poetry','','[]','樓面自東如擇對，景隨樓面若相會。',64,'全唐诗/poet.song.163000.json','["樓面自東如擇對，景隨樓面若相會。", "眼前獻狀有龍頭，脚底乘機可鵬背。", "坐躋百里東風中，起望長安馬首東。", "府寺有人能北事，乾坤無處不東風。"]'),
('ab6ff64c-e456-4d26-b8b2-aec2f47caa4c','寄題項聖予盧溪書院','曾丰','宋','宋诗','song-poetry','','[]','中興天子旌義門，榮光猶足昌弟昆。',112,'全唐诗/poet.song.163000.json','["中興天子旌義門，榮光猶足昌弟昆。", "家庭衮衮義子孫，下相郎君開義塾。", "美意非徒淑姻族，鄉里烝烝義風俗。", "廼翁固喜兒讀書，更喜它人與兒俱。", "兒今不替翁之初，人人忠孝書緒餘。", "初唐元勳幾卿相，游學豈無他絳帳。", "姓名半出多顯揚，河汾便是盧溪樣。"]'),
('9d648817-9d74-478f-a62a-25b617d31f8d','題項聖尹竹齋','曾丰','宋','宋诗','song-poetry','','[]','之君命屯有孤辰，之子德孤無同人。',112,'全唐诗/poet.song.163000.json','["之君命屯有孤辰，之子德孤無同人。", "天遣之君友之子，賓主相忘無彼此。", "出牆春梢道骨輕，侵書晚色天姿清。", "客來面目挾塵土，對君有頭不敢舉。", "客來言語挾塵埃，對君有口不敢開。", "坐聽一賓陪一主，夜雨秋風相爾汝。", "主人養高賓養虛，九天上與神龍俱。"]'),
('4b88f5ec-781f-42db-9e42-d238516ef10d','題吉州聶倅談風月軒','曾丰','宋','宋诗','song-poetry','','[]','黄堂指顧了凡最，紅幕奔馳了苛碎。',176,'全唐诗/poet.song.163000.json','["黄堂指顧了凡最，紅幕奔馳了苛碎。", "更無可了別駕翁，贏得徜徉是非外。", "未有可偷風月天，崢嶸新起東偏廢。", "風含渾沌竅裏音，月弄光明藏中態。", "吹開雲雨天益高，照破山河地加大。", "兼之足以答公餘，妙處何人同領會。", "無酒客有詩相酬，有酒可無客相對。", "主酣客醉舌俱饒，說到無聲無色界。", "髮難恃細併毛融，骨不禁清連肉蛻。", "目不信爲山河影，耳豈信爲天地籟。", "主困欲眠客且歸，不容耳目寧容喙。"]'),
('b1611a38-27b0-471d-9b9c-02dc39d0f42b','題游德昭壽藏名曰復庵','曾丰','宋','宋诗','song-poetry','','[]','劉伶未死先荷鍤，自負上超無礙法。',80,'全唐诗/poet.song.163000.json','["劉伶未死先荷鍤，自負上超無礙法。", "死則已焉埋謂何，東坡猶笑未爲達。", "之君之學齊死生，穴其吾屋屋吾穴。", "嚥日餐霞容有功，馭風騎氣得無訣。", "歸歟歸歟彼大通，復哉復哉此虛設。"]'),
('9779a438-284f-4b06-be49-2e3c76e750f1','免解進士應致遠過晉康見謂以上文字而忤權要聽讀藤州十餘年得旨自便賦詩贈行','曾丰','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江湧千萬奇，收爲詞氣吞虹蜺，敢與九關虎豹違。',142,'全唐诗/poet.song.163000.json','["錢塘江湧千萬奇，收爲詞氣吞虹蜺，敢與九關虎豹違。", "蜂芒蠆刺攢一時，或疑宜州城上人不歸。", "桂林山羅千萬怪，收爲詩膽吞渤澥，敢與九疑魑魅對。", "瘴雨蠻煙鏖十載，誰料儋州海上人猶在。", "一尊三酹古藤陰，少游陳矣君日新。", "還過韶石聞舜琴，混融奇怪入古音。", "韓子老來潮陽歸後固自文章功更深，何當道德終不負初心。"]'),
('2b166544-531a-463c-be60-fc85df5d98b0','題安子承讀易堂','曾丰','宋','宋诗','song-poetry','','[]','卦辭爻辭易之註，孔子讀之悟其故。',128,'全唐诗/poet.song.163000.json','["卦辭爻辭易之註，孔子讀之悟其故。", "彖辭象辭易之疏，孔子作之志其悟。", "懸知孔子大悟時，太虛中不掛一絲。", "與易爲一自不知，奚以卦辭爻辭爲。", "渠無孔子大機械，所恃囁嚅三尺喙。", "象彖爻辭從領會，其如猶有卦辭在。", "誠使時習能絕編，安知日新不忘筌。", "著脚還超九師先，回頭更勘三畫前。"]'),
('fc832f1b-4bc6-46c8-8fc3-8ab4c162996a','送鍾上舍應禧','曾丰','宋','宋诗','song-poetry','','[]','向上機關口掛壁，一言且蔽詩三百。',64,'全唐诗/poet.song.163000.json','["向上機關口掛壁，一言且蔽詩三百。", "胸次融成安樂窩，筆頭點出華胥國。", "誠然甚正□而葩，要會百家歸一家。", "從建極來都有準，出遊塵外始無瑕。"]'),
('478bedc1-dce0-4723-b02e-79148288299e','賀德慶陳倅生朝','曾丰','宋','宋诗','song-poetry','','[]','無伏無臘壺中天，不煙不火壺中仙。',144,'全唐诗/poet.song.163000.json','["無伏無臘壺中天，不煙不火壺中仙。", "壺天固自遠世界，壺仙還自結世緣。", "昨夜壺公山外望，壺公駕鶴隨仙仗。", "逃身下降唐謫仙，襲姓前生漢丞相。", "四時之氣春爲沖，誕彌况在春之中。", "一段乾坤奇特意，三朝文學老成風。", "通守通班蓋其寓，澤民致主酬吾素。", "收拾平生塵外遊，追尋疇昔壺中去。", "春秋過隙了不知，甲子循環浩無數。"]'),
('75a558c4-0ec4-4689-9750-92040f95de5f','寄題仰止亭','曾丰','宋','宋诗','song-poetry','','[]','廬陵江滸路窮處，舟子不容仙子渡。',176,'全唐诗/poet.song.163000.json','["廬陵江滸路窮處，舟子不容仙子渡。", "豈意一篙落手來，而資雙足凌波去。", "睥睨大海如江然，杯渡佛輕篙渡仙。", "休負知津惟我是，且從登岸看誰先。", "杯渡之杯人所怪，大塊中含幾沙界。", "或云芥納須彌山，細視芥焉杯則大。", "彼細莫細于一芥，一芥要之猶有內。", "彼大莫大于兩塊，兩塊要之猶有外。", "內外相形費融會，未忘所仰亭勿壞。", "吾細無內莫能碎，吾大無外莫能載。", "細大相融亡掛礙，何仰之有亭可廢。"]'),
('32221cf2-1dde-4f16-9a47-c63bf1f59fc9','吾郡之望羅彥方過聽以予有詩癖古風特枉傑作之貺不可虛辱賦一篇謝之','曾丰','宋','宋诗','song-poetry','','[]','聲生于氣詩之體，于氣要窮所從起。',96,'全唐诗/poet.song.163000.json','["聲生于氣詩之體，于氣要窮所從起。", "事制于義詩之理，于義要窮所從止。", "一元開闢三才矣，萬世綱維十倫爾。", "我初傳此無上宗，君今下我未到工。", "胸中周召次畢公，筆端雅頌餘國風。", "不容陰陽作窮通，可與天地爲始終。"]'),
('fe5dd2b2-4431-4f9d-a0ca-8aedd152b9bf','寄題劉淵甫可齋','曾丰','宋','宋诗','song-poetry','','[]','君子無莫也無適，聖人毋固也毋必。',96,'全唐诗/poet.song.163000.json','["君子無莫也無適，聖人毋固也毋必。", "行藏視彼時所宜，去就惟吾義之適。", "吾道難莫難于權，其惟孔子爲能然。", "胸中還未有孔子，寧墮于偏勿求全。", "願爲孔子可齋志，四可猶須省三未。", "孟子何當周文王，魯男善學柳下惠。"]'),
('3c96995a-d8bb-46f5-808a-dca7342d7685','廣東黄漕改除廣西帥過郡送行','曾丰','宋','宋诗','song-poetry','','[]','眼醒蓬島飽瀛洲，他水他山何足遊。',192,'全唐诗/poet.song.163000.json','["眼醒蓬島飽瀛洲，他水他山何足遊。", "郎宿自闌朝北極，使車誰枉指南州。", "浩浩湯湯廣諸海，無人能與相融會。", "天遣公開東計臺，融會諸海新詩內。", "奇奇怪怪桂諸峯，無人能與相會融。", "天遣公開西帥府，會融諸峯古文中。", "進衣怱遽吾民事，退食從容吾道許。", "詩文平淡潮柳州，公則視之爲末藝。", "包籠天地孟軻篇，收管山川馬遷記。", "仰觀俯察易象真，更勘畫前精入神。", "未爲三公效燮理，先與萬物歸彌綸。", "事非戰國而來事，人是羲皇以上人。"]'),
('e808dc9b-a6b4-4786-93c5-06fbe8053a96','參政瞿公之孫東廣機宜德遠惠書若詩以能問于不能久之愧虛盛意敬賦古風謝塞','曾丰','宋','宋诗','song-poetry','','[]','高廟中興初十年，大參內制餘百篇。',160,'全唐诗/poet.song.163000.json','["高廟中興初十年，大參內制餘百篇。", "心聲之發動夷夏，手澤所存傳子孫。", "得其傳者孫之嫡，參自道根至枝葉。", "一元生二二生三，萬特取千千取百。", "詩書其髓易其精，左右逢原筆縱橫。", "公先聞道非後進，我後獲仁豈先生。", "知津問津蓋有得，教玉琢玉其何名。", "玉雖不以石作使，以磨易磋亦其理。", "春秋以來有師承，博約之外無宗旨。", "風行水上舊爲文，雷在地中新復理。"]'),
('282164d3-9662-4aea-ab1f-c9e3fbd7d394','前高凉推官陳漢臣惠佳什索俚編不可虛辱授之後集古律矣復課數韵語謝之','曾丰','宋','宋诗','song-poetry','','[]','太虛生氣氣生風，風又生聲詩在中。',96,'全唐诗/poet.song.163000.json','["太虛生氣氣生風，風又生聲詩在中。", "固是性情元具足，何當學問更加充。", "形容草木魚蟲意，雖妙猶爲墮于藝。", "雅頌聲音召陰陽，聖賢道義包天地。", "句拙莫謝來章工，尚深自養細自融。", "和順積中鬼不見，英華發外天無功。"]'),
('2d549cb2-95fc-4b3d-8ed9-0dda435c406f','張行甫許舍五羊館俸之厚俯而就薄來晉康相親爲學生師遣介迎候賦詩速行','曾丰','宋','宋诗','song-poetry','','[]','出入交戰以義肥，卜商先覺後勿違。',128,'全唐诗/poet.song.163000.json','["出入交戰以義肥，卜商先覺後勿違。", "上下交征以利危，惠王後悔終何追。", "義利之差一毫爾，其繆遂至于千里。", "不差不繆今誰氏，嶺外眼中有之子。", "彼門如市挽不留，吾心如水從之遊。", "自能下學學箕裘，相期上對對冕旒。", "挑兮撻兮小豚犬，匡之直之古墳典。", "鑄鐵肯捐丹九轉，化龍寧吝墨一點。"]'),
('400c3bc8-85f4-41ae-9a16-6c2e1f7583f2','王元賓之子經紆道過我晉康臨行贈別','曾丰','宋','宋诗','song-poetry','','[]','乃翁于我松梅竹，之子于翁芝蘭玉。',96,'全唐诗/poet.song.163000.json','["乃翁于我松梅竹，之子于翁芝蘭玉。", "薰薰藹藹仁義容，便便坦坦詩書腹。", "向來相訪魯東家，今來相訪洛南涯。", "飽參禪覺一宿別，精進射功三年差。", "家傳自許已跨竈，庭對相期毋媚奧。", "馬蹄歷塊且徐行，鵬背負天終遠到。"]'),
('07ed7792-02c4-4334-ac43-683af194b2dc','清江何子發自荆湖宣撫幕客罷歸過我晉康投詩索報勉意塞請','曾丰','宋','宋诗','song-poetry','','[]','南北新來尋舊盟，江淮襄漢又休兵。',103,'全唐诗/poet.song.163000.json','["南北新來尋舊盟，江淮襄漢又休兵。", "召還開府諸元帥，謝遣游談幾老生。", "背上琴聲忠憤激，腰間劍氣血冤腥。", "君不見老范相知小相沮，橫渠自反高自許。", "三略六韜付擲捐，中庸大學歸含咀。", "未遑盡發千古聖道機，猶不失爲一代士宗主。"]'),
('5dae0917-40c9-4989-8d19-e34258819961','上浙東帥王尚書','曾丰','宋','宋诗','song-poetry','','[]','太古犧媧氏，創爲琴與笙。',288,'全唐诗/poet.song.163000.json','["太古犧媧氏，創爲琴與笙。", "氤氳弸混沌，噢咻擘冥莖。", "合氣歸三律，分音麗五行。", "未歌先協律，無韻不成聲。", "曲度初焉刌，詩機寖以萌。", "朝廷風化洽，里巷頌聲盈。", "玄鳥三夫倡，卿雲百辟賡。", "口姑隨所發，心自得其平。", "三代德爲政，四詩詞見情。", "揫收歸禮義，點檢中章程。", "傳久寧無雜，刪多亦已精。", "王通續似贅，束皙補疑贏。", "聖事難爲僭，時名可與爭。", "遒人中曠絕，樂府四紛更。", "體變從蘇李，枝分入遜鏗。", "舂容七字律，挺拔五言城。", "老杜收全氣，新功集大成。", "統經唐末亂，派轉國初清。", "歐定聖俞價，蘇成山谷名。", "江西容入社，天下指爲榮。", "顧我耽餘習，如今費半生。", "閑中無益作，醉裏不平鳴。", "改罷令兒誦，吟成喚客評。", "槁肝隨血嘔，枵腹欠書撐。"]'),
('641bafc4-3a5d-4d96-826d-25f513ea4e08','別陸德隆黄叔萬','曾丰','宋','宋诗','song-poetry','','[]','辛丑隨浮梗，鍾陵得盍簪。',288,'全唐诗/poet.song.163000.json','["辛丑隨浮梗，鍾陵得盍簪。", "潛藩門若市，歛板客如林。", "氣宇黄陂闊，詞源陸海深。", "二豪談正劇，一坐口俱瘖。", "詩社初容入，交盟後失尋。", "雲山千里眼，夢寐八年心。", "九陌迎連璧，孤燈話斷金。", "始猶疑面目，徐復記聲音。", "蝦菜隨宜簇，茅柴取意斟。", "行藏更見告，文行互相箴。", "憤敵常旁午，憂時半孔壬。", "清風晨揖袂，明月夕離襟。", "發纜東流岸，迴檣倒景岑。", "荆江隨地卷，蜀道與天侵。", "通守諸侯土，專彈百里琴。", "長才優拊字，暇日少登臨。", "隠士隆中卧，羈臣澤畔吟。", "青城山鬰積，赤壁樹陰森。", "哀樂歸巴曲，興亡入楚砧。", "把盃空弔古，搔首重傷今。", "擁戶鋒車急，開緘詔墨淋。", "抬頭高拱斗，引手上捫參。", "可畫安邊策，無韜活國鍼。", "寸心丹未了，雙鬢白那禁。"]'),
('ce6e936f-5de1-4988-9c03-82c89021eb29','章貢解舟雨作江漲','曾丰','宋','宋诗','song-poetry','','[]','風伯始惡發，雷師隨怒張。',48,'全唐诗/poet.song.163000.json','["風伯始惡發，雷師隨怒張。", "雨從來處黑，江到漲時黄。", "穩穩過皇恐，徐徐下豫章。", "不逢天借力，安敢夜乘航。"]'),
('50ac18a8-8d0f-4c02-97da-8e44e573ab8e','隆興貢院呈彭國壽','曾丰','宋','宋诗','song-poetry','','[]','名士江西少，廣文胸次高。',48,'全唐诗/poet.song.163000.json','["名士江西少，廣文胸次高。", "欠人扶此道，得子慰吾曹。", "學問揉圭角，功名添二毛。", "宜春文藝傳，它日蜀王褒。"]'),
('b6c69dcf-f712-41d5-a1ba-855080400c76','自豫章還贛至萬安始得風','曾丰','宋','宋诗','song-poetry','','[]','解纜將逾月，歸帆始遇風。',48,'全唐诗/poet.song.163000.json','["解纜將逾月，歸帆始遇風。", "只消三數日，能得幾何功。", "天意非相簡，詩人固自窮。", "江山清絕處，吾亨亦吾通。"]'),
('d62e153d-64c5-4afd-8228-b7f8bb0e0fb2','會昌號湘江岸有小峴亭癸卯六月與瑞金吳丞飲其上  其一','曾丰','宋','宋诗','song-poetry','','[]','湘水欠湘竹，峴亭非峴山。',48,'全唐诗/poet.song.163000.json','["湘水欠湘竹，峴亭非峴山。", "休論真勝假，且幸冗偷閑。", "眼底方塵外，欄干更樹間。", "哢禽如語我，劇暑未能還。"]'),
('3256b5fa-7f00-4d9e-83d5-4b51898817b7','會昌號湘江岸有小峴亭癸卯六月與瑞金吳丞飲其上  其二','曾丰','宋','宋诗','song-poetry','','[]','占斷江西景，臨川擬峴臺。',48,'全唐诗/poet.song.163000.json','["占斷江西景，臨川擬峴臺。", "今猶千里隔，我更幾時回。", "幸此亭相似，非公坐莫陪。", "古今隨水去，風月送詩來。"]'),
('8d0dfa32-39db-44df-af36-14322f1aa7a8','表兄峽山蕭伯鈞至會昌久之以歸歟字韻丐詩爲別  其一','曾丰','宋','宋诗','song-poetry','','[]','久離空嚮往，重見少相依。',48,'全唐诗/poet.song.163000.json','["久離空嚮往，重見少相依。", "款曲論心約，因循與願違。", "今逢聲氣是，但覺鬢毛非。", "禍患今相問，幾從死處歸。"]'),
('3ebc80e1-e3e9-453f-9cb3-0b3a62c31dc2','表兄峽山蕭伯鈞至會昌久之以歸歟字韻丐詩爲別  其二','曾丰','宋','宋诗','song-poetry','','[]','握手兩旬許，歸途千里餘。',48,'全唐诗/poet.song.163000.json','["握手兩旬許，歸途千里餘。", "繼今難得便，及早發回書。", "父祖初深契，兒孫久漸疏。", "朱陳婚嫁約，還可繼之歟。"]'),
('c56b98bb-7b40-495d-9e32-0c45bd0f4297','向察推檄至會昌賦所懷呈似  其一','曾丰','宋','宋诗','song-poetry','','[]','文簡家風淡，薌林句法清。',48,'全唐诗/poet.song.163000.json','["文簡家風淡，薌林句法清。", "今能傳幾世，君復擁全名。", "猶及識前輩，未嘗輕後生。", "崆峒風月裏，許我共詩盟。"]'),
('b1037472-c14a-4016-826c-b0b9182ce590','向察推檄至會昌賦所懷呈似  其二','曾丰','宋','宋诗','song-poetry','','[]','惟此溪山惡，其它州縣無。',48,'全唐诗/poet.song.163000.json','["惟此溪山惡，其它州縣無。", "豈期公骯髒，而爲我馳驅。", "錢穀豈餘事，音容非故吾。", "史君如問細，爲道費枝梧。"]'),
('dd316324-a4bb-40b8-adbe-a73c73ac1f0e','出會昌峽','曾丰','宋','宋诗','song-poetry','','[]','石峽侵尋過，江流次第平。',48,'全唐诗/poet.song.163000.json','["石峽侵尋過，江流次第平。", "篙人輕去住，船勢任縱橫。", "穩不妨危坐，忙猶得意行。", "明朝從起晚，但要到州城。"]'),
('f6ae20a2-efac-4db2-9d97-7d35a0a7cc4b','舟宿會昌十里間','曾丰','宋','宋诗','song-poetry','','[]','石是漥樽樣，山如土鼓然。',48,'全唐诗/poet.song.163000.json','["石是漥樽樣，山如土鼓然。", "空猶餘樹木，了不見人烟。", "辦治豈容緩，拊摩那得專。", "意中無限事，夜半不成眠。"]'),
('d0af7cf3-ef7f-4f75-90d9-2bb8f40332d6','贛東江','曾丰','宋','宋诗','song-poetry','','[]','兀坐順流中，吾歸與便逢。',48,'全唐诗/poet.song.163000.json','["兀坐順流中，吾歸與便逢。", "窑家俱瓦汲，灘戶半機舂。", "艣作傷春響，山爲媚客容。", "江鷗凝不動，識我舊行蹤。"]'),
('d6185edc-a9f5-470b-92f5-fb92f5068f74','幼立弟死後簡寄幼能','曾丰','宋','宋诗','song-poetry','','[]','動足燕巢幕，投身羝觸藩。',48,'全唐诗/poet.song.163000.json','["動足燕巢幕，投身羝觸藩。", "驚風傷斷鴈，落葉悟飛鳶。", "汝子頗難教，吾兒全未婚。", "重陽歸省罷，猶得對床論。"]'),
('5c003a0d-c01f-410a-9b11-12d6a1401df0','臘月被檄下豫章至南安簡曹宰  其一','曾丰','宋','宋诗','song-poetry','','[]','擁卧聽衙鼓，傳呼輟坐曹。',48,'全唐诗/poet.song.163000.json','["擁卧聽衙鼓，傳呼輟坐曹。", "庭前人跡掃，門外市聲鏖。", "餒立雁行少，寒欹馬骨高。", "寧教循吏傳，書拙不書勞。"]'),
('ce0ae57f-58fd-460b-8644-b12ef2628326','臘月被檄下豫章至南安簡曹宰  其二','曾丰','宋','宋诗','song-poetry','','[]','日月迎春急，江山送臘愁。',48,'全唐诗/poet.song.163000.json','["日月迎春急，江山送臘愁。", "歲窮猶被檄，途遠更乘舟。", "家累已相逼，官身那自由。", "欲從公款愬，公自鬰眉頭。"]'),
('57599da7-4cc2-40a7-ad1e-74df49116bb5','豫章舟中夜坐自遣','曾丰','宋','宋诗','song-poetry','','[]','初月多情出，西山故意遮。',48,'全唐诗/poet.song.163000.json','["初月多情出，西山故意遮。", "更遭風激水，而亂客吹笳。", "夢入翩翩蝶，驚聞閣閣蛙。", "違多諧偶少，物理固然邪。"]'),
('6016e120-8ec1-4a56-bd70-eba895ebff22','十六日立春舟中晚眺','曾丰','宋','宋诗','song-poetry','','[]','風住帆維軟，人齊艣響勻。',48,'全唐诗/poet.song.163000.json','["風住帆維軟，人齊艣響勻。", "津橋橫汲具，岸樹掛酤巾。", "亂石知何處，孤篷任此身。", "三歎謝陳歲，一笑接新春。"]'),
('d9b7243e-e3cf-4f9d-9a9a-e982957109a0','再自隆興還遊至德觀','曾丰','宋','宋诗','song-poetry','','[]','水眼通三島，波心湧一峯。',48,'全唐诗/poet.song.163000.json','["水眼通三島，波心湧一峯。", "兩岸懸石穩，千古怒濤樁。", "呵劍敺游蜃，鞭雷起蟄龍。", "僊人有餘量，事了豈留蹤。"]'),
('ad570452-6742-4f04-a985-c22900396a78','自省','曾丰','宋','宋诗','song-poetry','','[]','肺肝供物態，鬚鬢管年華。',48,'全唐诗/poet.song.163000.json','["肺肝供物態，鬚鬢管年華。", "眼閲世更變，口談時過差。", "眉因公道蹙，手爲貴人叉。", "點檢通身事，都無益自家。"]'),
('5238d0c0-c7f5-4142-9ee4-602ba229dffb','潘宰見余三生圖詩廣一篇見示再賦謝之','曾丰','宋','宋诗','song-poetry','','[]','擔水誰家渡，牧牛何處村。',48,'全唐诗/poet.song.163000.json','["擔水誰家渡，牧牛何處村。", "未能逃劫數，猶是弄精魂。", "毛穎含雲凍，鵝溪带雨昏。", "强從泡影裏，摹模去來痕。"]'),
('46ecd241-5423-4c1b-91a4-81ea6b127c81','梅雨示何柯','曾丰','宋','宋诗','song-poetry','','[]','屋漏床俱濕，牆頹土半乾。',48,'全唐诗/poet.song.163000.json','["屋漏床俱濕，牆頹土半乾。", "管蟲淫兔穎，箱漆浥龍團。", "著火薰仍焙，教兒覆更翻。", "好收書冊在，念我置時難。"]'),
('4ea107e1-2923-4890-8361-b075ffdbeef6','管文徹通易學自冠入場屋垂老未諧文公詩人品題至成軸','曾丰','宋','宋诗','song-poetry','','[]','世業餘方冊，生涯只短檠。',48,'全唐诗/poet.song.163000.json','["世業餘方冊，生涯只短檠。", "韋編閑裏絕，髀肉暗中生。", "憎達終難免，憂貧似不情。", "諸公題品價，自可比連城。"]'),
('0ee72a48-23f9-486c-b2eb-369db34c1b2f','臨安主人出冰塊佐飲曾簿嚴宰同賦','曾丰','宋','宋诗','song-poetry','','[]','久在京塵裏，仍當伏暑中。',48,'全唐诗/poet.song.163000.json','["久在京塵裏，仍當伏暑中。", "眼逢銀色界，身落水晶宮。", "有客清相似，無人白與同。", "雪兒不可作，隨意酒杯空。"]'),
('95b07b56-9386-44df-bcf2-8f533986f959','甲辰婺女道中過重九','曾丰','宋','宋诗','song-poetry','','[]','節到重陽日，身爲千里人。',48,'全唐诗/poet.song.163000.json','["節到重陽日，身爲千里人。", "半癡黄口子，多病白頭親。", "熟浸菊英嫩，輕挼茱糝勻。", "旋沽深巷酒，强飲不成春。"]'),
('3d9cf49b-e37b-4d8a-a080-4d03622df485','赴廣東漕屬有感','曾丰','宋','宋诗','song-poetry','','[]','草木歸根穩，昆蟲入蟄深。',48,'全唐诗/poet.song.163000.json','["草木歸根穩，昆蟲入蟄深。", "若爲吾自覺，猶與世相尋。", "江月幽人態，松風大雅音。", "紅塵任相衮，終不點初心。"]'),
('8d2afbc7-5988-4345-8e22-fa305cf5f3a6','大庾北崖梅晚發','曾丰','宋','宋诗','song-poetry','','[]','中州梅較晚，大庾合先之。',48,'全唐诗/poet.song.163000.json','["中州梅較晚，大庾合先之。", "已似得南氣，不應留北枝。", "天工新坐懶，春事故教遲。", "蜂蝶若知道，恬然不怨時。"]'),
('18f798c6-370f-4f4f-b567-a85c7be621d4','曉行','曾丰','宋','宋诗','song-poetry','','[]','已離南康縣，不知何處村。',48,'全唐诗/poet.song.163000.json','["已離南康縣，不知何處村。", "荒郊霜灑道，野店犬應門。", "市尾人聲閙，津頭水氣昏。", "雲開雙髻出，髣髴月梳痕。"]'),
('97f2b55c-3a2a-40c2-926a-9d8a390d012f','靜坐','曾丰','宋','宋诗','song-poetry','','[]','履歲投正月，携家到五羊。',48,'全唐诗/poet.song.163000.json','["履歲投正月，携家到五羊。", "清明郊外好，朱墨幕中忙。", "得病疑風土，逢人問藥方。", "所傳非所信，靜坐得心凉。"]'),
('e8d2afe7-b0dd-424f-baeb-15a84f9d8dee','頹臘獻歲之交出贛向韶緬懷偏親簡介弟幼能','曾丰','宋','宋诗','song-poetry','','[]','水出猶諳贛，車行未習韶。',48,'全唐诗/poet.song.163000.json','["水出猶諳贛，車行未習韶。", "忍看鳶跕跕，愁聽雨瀟瀟。", "豈不欲歌棣，寧無工頌椒。", "妻兒環坐外，笑語與誰聊。"]'),
('a2f131bd-3ce6-47d2-8cb9-36b04f276083','舟行艤韶下石夜聽','曾丰','宋','宋诗','song-poetry','','[]','江響合蠻吹，鳥聲諧越吟。',48,'全唐诗/poet.song.163000.json','["江響合蠻吹，鳥聲諧越吟。", "仍收南郭籟，併入大韶音。", "纚纚聽于耳，徐徐寫以琴。", "倘猶有餘韻，著語付何陰。"]'),
('0b8ecece-dcf5-44f5-ae4a-e4a5f9d5cf64','除日送龍涎香與宋評事  其一','曾丰','宋','宋诗','song-poetry','','[]','除夕風霜節，家人錦綺筵。',48,'全唐诗/poet.song.163000.json','["除夕風霜節，家人錦綺筵。", "舌頭餘鳳髓，鼻觀欠龍涎。", "玉餠聊分餉，金爐試一燃。", "更將國香匹，何似海南烟。"]'),
('56942c77-91fa-4358-b76a-511a17b54733','除日送龍涎香與宋評事  其二','曾丰','宋','宋诗','song-poetry','','[]','半載隨蓬轉，中宵送夜分。',48,'全唐诗/poet.song.163000.json','["半載隨蓬轉，中宵送夜分。", "酒供文字飲，香對聖賢焚。", "羨子迎偏老，呼兒酌細君。", "勸酬交錯裏，款款鴨爐薰。"]'),
('ddbb28d0-c179-4e8b-b4c7-ebb066cf7147','望始興','曾丰','宋','宋诗','song-poetry','','[]','指似始興縣，西南天一隅。',48,'全唐诗/poet.song.163000.json','["指似始興縣，西南天一隅。", "荆管今鬰積，山水故盤紆。", "在昔多名士，同時九大夫。", "更添張相國，畫作十賢圖。"]'),
('16283aba-0aac-402f-9c2d-974efa3e2a00','出清遠峽','曾丰','宋','宋诗','song-poetry','','[]','水石三過峽，江流四望平。',48,'全唐诗/poet.song.163000.json','["水石三過峽，江流四望平。", "鳥經波面疾，雲泊樹頭輕。", "晃朗天光合，溟濛海氣生。", "且停篙與槳，遲速信船行。"]'),
('03bfcf3a-86a0-4cac-af0d-bebefb85ca4c','真陽峽','曾丰','宋','宋诗','song-poetry','','[]','嶂合含元氣，巖呀吐太陰。',48,'全唐诗/poet.song.163000.json','["嶂合含元氣，巖呀吐太陰。", "崖根連地入，石笋與天侵。", "堯舜成陳迹，英韶寄古音。", "黄巢徒堰水，遺臭到于今。"]'),
('5194b911-1b16-44c9-a53e-00a1aa82af1f','觸興','曾丰','宋','宋诗','song-poetry','','[]','山向南逾禿，江歸下轉清。',48,'全唐诗/poet.song.163000.json','["山向南逾禿，江歸下轉清。", "鳥那容久立，魚不及潛行。", "雲外雁機動，沙頭鷺意萌。", "信爲吾道計，切忌太分明。"]'),
('94d08c32-d349-40c8-a48c-6eb26df78f88','靈洲妙高臺','曾丰','宋','宋诗','song-poetry','','[]','水心浮出石，洲背湧成山。',48,'全唐诗/poet.song.163000.json','["水心浮出石，洲背湧成山。", "草木仙家種，樓臺梵氏關。", "全輸緇衲老，長與白雲閑。", "隔岸風烟好，終嫌是世間。"]'),
('cf3be788-5cc9-4b92-9d02-5284801d7e20','謁扶胥南海廟','曾丰','宋','宋诗','song-poetry','','[]','南海大都會，扶胥拱聖王。',48,'全唐诗/poet.song.163000.json','["南海大都會，扶胥拱聖王。", "卜靈終自顯，兩廟屹相望。", "香火夤緣在，河沙劫數長。", "昌黎韓子記，相與作存亡。"]'),
('848ecf0f-dd0d-466a-a52f-f774d137b98d','得廣州俸米供給麻券授家人','曾丰','宋','宋诗','song-poetry','','[]','陶潜營五斗，王績辦三升。',48,'全唐诗/poet.song.163000.json','["陶潜營五斗，王績辦三升。", "醉飽曾無幾，驅馳已不勝。", "猶須餬汝口，未果枕吾肱。", "有可供饑渴，休官豈不能。"]'),
('f3c2cf31-ac0d-41df-af09-0d23ea79e76a','廣州  其一','曾丰','宋','宋诗','song-poetry','','[]','室女環垂額，蕃兒布纏頭。',48,'全唐诗/poet.song.163000.json','["室女環垂額，蕃兒布纏頭。", "闠門羅姥婦，游艇售娼優。", "曲巷公渝濫，通衢亂溺溲。", "羊山來輒去，地惡不堪留。"]'),
('4c8bdf0a-0b78-4e51-8e06-4cf097ea9b59','廣州  其二','曾丰','宋','宋诗','song-poetry','','[]','繞處無非濕，終年不識寒。',48,'全唐诗/poet.song.163000.json','["繞處無非濕，終年不識寒。", "家饒安樂睡，市賣喜歡團。", "倡女青芒屨，漁兒白布冠。", "北人落南者，久亦自相安。"]'),
('d6ad4940-8bef-4ac4-89a4-38cae43a11db','窮冬長途觸物遣興','曾丰','宋','宋诗','song-poetry','','[]','蹀躞牛歸柵，翺翔鳥認巢。',48,'全唐诗/poet.song.163000.json','["蹀躞牛歸柵，翺翔鳥認巢。", "垂雲低暗水，倒影上明梢。", "春豈有偏意，梅無未破苞。", "吾心已忘物，聊與物相嘲。"]'),
('7550ed25-01bd-4c85-9456-af6212f9db3e','過達磨泉緬懷東坡','曾丰','宋','宋诗','song-poetry','','[]','分野秦南海，城池漢尉佗。',48,'全唐诗/poet.song.163000.json','["分野秦南海，城池漢尉佗。", "功名徒自苦，寒暑暗相磨。", "破寺容僧少，枯松閲士多。", "我來空想象，百世一東坡。"]'),
('de2e77ba-4179-458b-8fba-ff8a759c02b7','丙午中元留羅子琳小酌','曾丰','宋','宋诗','song-poetry','','[]','送客獨留髠，慇懃共一尊。',48,'全唐诗/poet.song.163000.json','["送客獨留髠，慇懃共一尊。", "星辰冥碧落，燈火耿黄昏。", "笑語渾無間，談諧雜不根。", "遣詩邀月出，相與答中元。"]'),
('1f7da06e-b688-4629-a810-0e5ecd1b8024','贈別藤州法曹南劍張仲明  其一','曾丰','宋','宋诗','song-poetry','','[]','天上張公子，名家更好修。',48,'全唐诗/poet.song.163000.json','["天上張公子，名家更好修。", "文章虹貫日，意氣鶚橫秋。", "桃李春風發，桑榆晚景收。", "丹心猶自在，素業未容休。"]'),
('48007501-2213-4fa5-9354-2f0ebd14d31e','贈別藤州法曹南劍張仲明  其二','曾丰','宋','宋诗','song-poetry','','[]','黄卷堆胸次，青雲出筆頭。',48,'全唐诗/poet.song.163000.json','["黄卷堆胸次，青雲出筆頭。", "小迂蓬島步，聊作嶺南遊。", "穩口開三語，平心活一州。", "陰功終有報，會見襲封侯。"]'),
('8a0d6d6d-9337-4815-90d7-66237340e18d','七月二十五日爲廣州蒲澗節鞏帥相招坐上默營兩詩  其一','曾丰','宋','宋诗','song-poetry','','[]','侵尋逾七夕，次第到中秋。',48,'全唐诗/poet.song.163000.json','["侵尋逾七夕，次第到中秋。", "蒲澗廣南節，熊車城外遊。", "杯盤收復出，賓主勸還酬。", "痛爲江山飲，離騷不讀休。"]'),
('5a0bc39e-722e-4ead-af72-d27bec99fb5d','七月二十五日爲廣州蒲澗節鞏帥相招坐上默營兩詩  其二','曾丰','宋','宋诗','song-poetry','','[]','石激幽泉響，風排古木號。',48,'全唐诗/poet.song.163000.json','["石激幽泉響，風排古木號。", "離城未多遠，去地不勝高。", "出處向來誤，是非何處逃。", "安期相領略，回首付兒曹。"]'),
('9105d50f-066d-455e-8e35-580ae340a700','七月晦日夜坐','曾丰','宋','宋诗','song-poetry','','[]','孟秋俄及晦，甲夜偶成晴。',48,'全唐诗/poet.song.163000.json','["孟秋俄及晦，甲夜偶成晴。", "露坐髮毛冷，風餐頤頰清。", "洗湔凡眼豁，抖擻肉身輕。", "宋玉知何故，悲來不禁情。"]'),
('93a922f4-fdbc-4b2b-9d7e-76382e7e9939','送廣東趙主管得倅臨漳  其一','曾丰','宋','宋诗','song-poetry','','[]','清切分天派，馨香出月宮。',48,'全唐诗/poet.song.163000.json','["清切分天派，馨香出月宮。", "羊城初白髮，蓮幕兩春風。", "外計方將上，南圖又欲東。", "我來猶未晚，幾度笑談同。"]'),
('b98b916d-58bb-4627-9d1e-8172df110238','送廣東趙主管得倅臨漳  其二','曾丰','宋','宋诗','song-poetry','','[]','有偉今丞相，猶虧□令君。',48,'全唐诗/poet.song.163000.json','["有偉今丞相，猶虧□令君。", "全材拔半刺，白髮擁紅裙。", "何處分風月，無時上水雲。", "莫將車騎去，驚動白鷗羣。"]'),
('986dd9ea-150f-414a-a1a3-168805a98411','送管憲出城','曾丰','宋','宋诗','song-poetry','','[]','海上連旬雨，城東一尺泥。',48,'全唐诗/poet.song.163000.json','["海上連旬雨，城東一尺泥。", "肩輿行轍兀，據板坐猶欹。", "鳥語如相問，松聲似見嗤。", "平生說高尚，何事送迎爲。"]'),
('8a12372e-b54a-4b63-bcb1-c75c8cef617f','寄殿院謝艮齋  其一','曾丰','宋','宋诗','song-poetry','','[]','元祐烏臺士，江西董白鬚。',48,'全唐诗/poet.song.163000.json','["元祐烏臺士，江西董白鬚。", "節因父母立，名與道鄉俱。", "耆舊流風遠，衣冠後輩孤。", "此公今復奮，吾道得相扶。"]'),
('cb416517-47d1-488d-a14b-6c4ab26fe479','寄殿院謝艮齋  其二','曾丰','宋','宋诗','song-poetry','','[]','穩著雲霄步，高峩獬豸冠。',48,'全唐诗/poet.song.163000.json','["穩著雲霄步，高峩獬豸冠。", "簡霜凝處冷，姦膽落邊寒。", "奮臂有餘勇，攖鱗不苦難。", "平生功業意，莫到晚年闌。"]'),
('dcaf3eec-dc1b-4c7a-b535-e5ca6006fa16','寄殿院謝艮齋  其三','曾丰','宋','宋诗','song-poetry','','[]','汩汩孤蓬轉，迢迢五嶺來。',48,'全唐诗/poet.song.163000.json','["汩汩孤蓬轉，迢迢五嶺來。", "故人饒鶴髮，新論凜烏臺。", "千里夜間月，一枝春首梅。", "使行無好寄，書到莫慵回。"]'),
('a5d21e18-8df3-49c1-b481-8ac64f3b3892','寄殿院謝艮齋  其四','曾丰','宋','宋诗','song-poetry','','[]','河鼓聘天孫，昭君未出村。',48,'全唐诗/poet.song.163000.json','["河鼓聘天孫，昭君未出村。", "非關媒不善，自是命難婚。", "無貌傾人國，何顔倚市門。", "隨緣幽閣裏，刺繡度朝昏。"]'),
('36324b0d-82b3-4743-bac5-c37f47a30966','寄衡陽尉徐智伯  其一','曾丰','宋','宋诗','song-poetry','','[]','千古南昌尉，神仙人姓梅。',48,'全唐诗/poet.song.163000.json','["千古南昌尉，神仙人姓梅。", "久歸天上去，重謫世間來。", "照乘無人市，傾城不自媒。", "穩乘高士轂，自有鄭莊推。"]'),
('1f8abc37-bf32-4cb3-9e25-07a3f1152472','寄衡陽尉徐智伯  其二','曾丰','宋','宋诗','song-poetry','','[]','刺眼縣門柳，縈心家圃梅。',48,'全唐诗/poet.song.163000.json','["刺眼縣門柳，縈心家圃梅。", "懶爲彭澤住，羞見督郵來。", "藉有湯行聘，要無石作媒。", "吾非癡謝令，自去不須推。"]'),
('96720182-2e1d-46e6-8d8d-e82f3cb38769','寄衡陽尉徐智伯  其三','曾丰','宋','宋诗','song-poetry','','[]','衡陽容有雁，嶺表得無梅。',48,'全唐诗/poet.song.163000.json','["衡陽容有雁，嶺表得無梅。", "半歲人南北，中宵夢往來。", "燈爲輸喜使，酒作嫁愁媒。", "莫决敲門句，幾經改作推。"]'),
('45621355-f342-49cc-9565-10413a3691ae','五羊同官真率','曾丰','宋','宋诗','song-poetry','','[]','小醵無妨職，嬉遊不離城。',48,'全唐诗/poet.song.163000.json','["小醵無妨職，嬉遊不離城。", "盤隨豐儉出，杯聽淺深傾。", "附耳俱情話，巡簷各意行。", "歸猶有餘興，後會莫寒盟。"]'),
('c28a6108-20a7-42d9-b313-c38c80b408e9','同幕李彥中田子真爲倡小醵出遊二月社日登遐觀呈二兄','曾丰','宋','宋诗','song-poetry','','[]','次第韶光半，因循樂事希。',48,'全唐诗/poet.song.163000.json','["次第韶光半，因循樂事希。", "清遊今見約，素懶敢相違。", "天末收行雨，林梢逼落暉。", "瓶中有殘酒，不盡不言歸。"]'),
('5578e5a6-ce35-40d6-b963-5c5c2f7e0499','中元日登越王臺望海南  其一','曾丰','宋','宋诗','song-poetry','','[]','僅從乾道歲，重創越王臺。',48,'全唐诗/poet.song.163000.json','["僅從乾道歲，重創越王臺。", "粉榜猶餘墨，丹楹已上煤。", "舊遊人欲厭，今日我方來。", "老范碑無恙，從頭讀一回。"]'),
('9261dd35-1ffd-418c-8522-e155a2f90e3b','中元日登越王臺望海南  其二','曾丰','宋','宋诗','song-poetry','','[]','乙巳中元日，乾坤半月秋。',48,'全唐诗/poet.song.163000.json','["乙巳中元日，乾坤半月秋。", "危臺掀突兀，老頭攪颼飀。", "北客眼生處，南方天盡頭。", "海槎乘興去，咫尺是瀛洲。"]'),
('7871831b-4019-49ac-b65c-c25b032f8ebe','五羊城南野行書所見','曾丰','宋','宋诗','song-poetry','','[]','棘籬圍敗圃，石桷蓋傾牆。',48,'全唐诗/poet.song.163000.json','["棘籬圍敗圃，石桷蓋傾牆。", "人緝蕉爲布，家儲蔗作糧。", "斷橋鋪以竹，全木聽成航。", "要作南中記，曾須到海鄉。"]'),
('b329537b-912c-43d4-8f4d-bcb933321892','至廣得弟幼能書報卜築江皋  其一','曾丰','宋','宋诗','song-poetry','','[]','遠宦非吾願，傳聞誤此行。',48,'全唐诗/poet.song.163000.json','["遠宦非吾願，傳聞誤此行。", "官忙無復學，俸薄不如耕。", "食物多疑忌，醫人少老成。", "情微書不達，書達若爲情。"]'),
('987ed08d-8ee3-4599-bdb2-62b9b980111e','至廣得弟幼能書報卜築江皋  其二','曾丰','宋','宋诗','song-poetry','','[]','口與腰初强，心隨舌漸柔。',48,'全唐诗/poet.song.163000.json','["口與腰初强，心隨舌漸柔。", "不任包馬革，猶浪到壺頭。", "張翰久羈宦，文園今倦遊。", "喜聞新卜築，約我到滄洲。"]'),
('01257788-562b-4de7-ab38-4563f0aedf81','自入南與二陸丈遊知其爲侍郎族也小陸丈除欽未拜命而大陸丈丙午六月既望赴德慶  其一','曾丰','宋','宋诗','song-poetry','','[]','屈指江山好，南中古晉康。',48,'全唐诗/poet.song.163000.json','["屈指江山好，南中古晉康。", "龍潛開王氣，燕寢貯清香。", "恩數優新守，君王奉太皇。", "政成歸奏最，小陸亦爲郎。"]'),
('83f47aaf-7882-42f2-9780-9ed249f16c0f','自入南與二陸丈遊知其爲侍郎族也小陸丈除欽未拜命而大陸丈丙午六月既望赴德慶  其二','曾丰','宋','宋诗','song-poetry','','[]','郡有宣公集，焚香手自繙。',48,'全唐诗/poet.song.163000.json','["郡有宣公集，焚香手自繙。", "要酬民所望，須踐祖之言。", "牛豈嫌途坦，魚那厭水渾。", "不將漁廢牧，亦足報君恩。"]'),
('10bb1e3e-c98e-4645-82a1-5aefabb385f6','自入南與二陸丈遊知其爲侍郎族也小陸丈除欽未拜命而大陸丈丙午六月既望赴德慶  其三','曾丰','宋','宋诗','song-poetry','','[]','叔姪嶺南邊，熊車相後先。',48,'全唐诗/poet.song.163000.json','["叔姪嶺南邊，熊車相後先。", "同時持紫橐，指日復青氈。", "契分膠投漆，離情雨带烟。", "吾窮公富貴，勿廢往來箋。"]'),
('4f91ed11-1c46-4f9a-a222-fa4fa0e40f11','餞趙提幹次李彥中韻','曾丰','宋','宋诗','song-poetry','','[]','解組圖南日，携壺賀下時。',48,'全唐诗/poet.song.163000.json','["解組圖南日，携壺賀下時。", "三杯幾絕倒，明日兩差池。", "足迹隨蓬轉，顛毛與雪期。", "我愁行未得，更賦送行詩。"]'),
('6f0d413f-64f7-424b-87f6-68ede6c674ce','五羊遣書問董仲脩  其一','曾丰','宋','宋诗','song-poetry','','[]','八面海風亂，四時天氣均。',48,'全唐诗/poet.song.163000.json','["八面海風亂，四時天氣均。", "常饈皆藥物，熟客只醫人。", "筆研爲謀左，烟嵐與死瀕。", "僅從危得飽，姑以健償貧。"]'),
('37c4467c-0831-4688-8899-2c9e7d8056ad','五羊遣書問董仲脩  其二','曾丰','宋','宋诗','song-poetry','','[]','風雨猶關夢，江山不隔心。',48,'全唐诗/poet.song.163000.json','["風雨猶關夢，江山不隔心。", "寧無疑信意，未得吉凶音。", "歲月催人候，春秋得趣深。", "明年天子詔，沙裏得淘金。"]'),
('28468c7e-b078-469c-b82c-54e11d84fea8','重九獨酌次偶成數韻呈江司法李帳幹并同遊諸僚兄  其一','曾丰','宋','宋诗','song-poetry','','[]','濃煮茯苓飲，細研松柏脂。',48,'全唐诗/poet.song.163000.json','["濃煮茯苓飲，細研松柏脂。", "雖名爲節物，未必合時宜。", "旨酒淘茱糝，華顛岸菊枝。", "妻孥爭笑我，將老尚兒癡。"]'),
('3aed8097-bd13-4043-a5cd-0379083f303d','重九獨酌次偶成數韻呈江司法李帳幹并同遊諸僚兄  其二','曾丰','宋','宋诗','song-poetry','','[]','孫盛龍山集，劉洪鳳嶺遊。',48,'全唐诗/poet.song.163000.json','["孫盛龍山集，劉洪鳳嶺遊。", "孰非陪好客，俱不負高秋。", "白髮與時背，清風勸我休。", "黄花嬌媚意，喜上少年頭。"]'),
('81b1923a-d1e0-4184-9765-f015cbcc94f5','簡艮齋  其一','曾丰','宋','宋诗','song-poetry','','[]','廣東漕臣重，本朝名士多。',48,'全唐诗/poet.song.163000.json','["廣東漕臣重，本朝名士多。", "梁題年月古，壁記姓名訛。", "畫象初何補，濂溪自不磨。", "聞名猶起敬，况睹大冠峩。"]'),
('57fa9347-25ea-49aa-8518-ead33fc1a0b7','簡艮齋  其二','曾丰','宋','宋诗','song-poetry','','[]','得古濂溪派，惟今謝艮齋。',48,'全唐诗/poet.song.163000.json','["得古濂溪派，惟今謝艮齋。", "冥搜窮骨髓，燕坐黜形骸。", "晚景登烏府，秋風立玉階。", "狐狸無暇問，閶闔莫空排。"]'),
('4c74afb3-cd81-41f3-bd86-912c10412b72','簡艮齋  其三','曾丰','宋','宋诗','song-poetry','','[]','夢裏常門下，詩中半廣南。',48,'全唐诗/poet.song.163000.json','["夢裏常門下，詩中半廣南。", "句成還自誦，愁到與誰談。", "菊又黄無抵，頭今白不堪。", "剩分新著作，洗我瘴邊嵐。"]'),
('6db44ab3-2d03-4623-a7e6-ac2371e649e2','東廣西漕廳久廢馬少卿葺爲簽廳','曾丰','宋','宋诗','song-poetry','','[]','前廳長貯馬，後閣久盛薪。',48,'全唐诗/poet.song.163000.json','["前廳長貯馬，後閣久盛薪。", "豈料廢臺沼，猶留延幕賓。", "壁蟲悲往事，巢燕笑來人。", "便過十年後，如今跡又陳。"]'),
('38531750-a9cb-4901-82a4-7ce1bb748965','暇日集越王臺','曾丰','宋','宋诗','song-poetry','','[]','著脚卧雲室，回頭蓋海亭。',48,'全唐诗/poet.song.163000.json','["著脚卧雲室，回頭蓋海亭。", "水爲三面白，山作四圍青。", "野鳥餘清哢，幽人得醉聽。", "籃輿不容款，餘思渺南溟。"]'),
('e16a9f10-ca44-4fe2-a825-baa9ec78cf2f','拏舟送使長馬少卿既酌別維舟小憩與李彥中各賦一篇','曾丰','宋','宋诗','song-poetry','','[]','賓主相從久，情親更受知。',48,'全唐诗/poet.song.163000.json','["賓主相從久，情親更受知。", "追隨船泊處，餞送酒醒時。", "落照關思憶，垂楊管別離。", "非詩愁莫寫，愁絕不勝詩。"]'),
('554aaffd-435e-4616-bc42-d54b7506edc7','余以檄出機宜陳伯英先往西津候別舟行風作才前輒退竟爲江隔遂呼酒自飲','曾丰','宋','宋诗','song-poetry','','[]','我出公追送，公賢我急親。',48,'全唐诗/poet.song.163000.json','["我出公追送，公賢我急親。", "文拘猶得說，風阻不由人。", "一廳河爲祟，時乎酒作春。", "相爲酬酢禮，方象是嘉賓。"]'),
('443a830d-e3ae-48c7-acba-fab8e63821b4','羅子琳來就廣漕試予以檄出至西江峽口懷古感興兩篇寄子琳後篇救子琳窮病也  其一','曾丰','宋','宋诗','song-poetry','','[]','自朝連夕去，由海入江來。',48,'全唐诗/poet.song.163000.json','["自朝連夕去，由海入江來。", "紫石巖前出，青山峽外開。", "秦貪徒郡縣，粵僭强樓臺。", "陸賈嚴夫子，千年一倚桅。"]'),
('75c03fb4-ecbd-4913-a413-ddc226281f24','羅子琳來就廣漕試予以檄出至西江峽口懷古感興兩篇寄子琳後篇救子琳窮病也  其二','曾丰','宋','宋诗','song-poetry','','[]','摹寫閑泉石，雕鎪病肺肝。',48,'全唐诗/poet.song.163000.json','["摹寫閑泉石，雕鎪病肺肝。", "得無縻歲月，終不補饑寒。", "上固詔求士，誰將詩得官。", "何如經學熟，隨計上長安。"]'),
('29bd8068-fbc7-4441-a2d5-3dcdce52db13','檄往校旁郡藝舟行值董仲脩來赴漕試復小艤相揖敘乃行  其一','曾丰','宋','宋诗','song-poetry','','[]','吾方懷檄出，子恰負琴來。',48,'全唐诗/poet.song.163000.json','["吾方懷檄出，子恰負琴來。", "津次俄相值，船頭且暫回。", "大鵬風翼起，老驥雪蹄開。", "南斗無多避，餘星不是魁。"]'),
('a8e47ff9-e158-4e90-8cfc-142692734bb0','檄往校旁郡藝舟行值董仲脩來赴漕試復小艤相揖敘乃行  其二','曾丰','宋','宋诗','song-poetry','','[]','命爲天所左，身落廣之東。',48,'全唐诗/poet.song.163000.json','["命爲天所左，身落廣之東。", "剩有南歸雁，全無北至鴻。", "夜懷渾欲惡，秋事半歸空。", "重九黄花酒，相期一笑同。"]'),
('5c2c379f-d1cf-45d6-9520-ccee70a2776d','入德慶舟中看雨','曾丰','宋','宋诗','song-poetry','','[]','雲合蒼天怒，風生老木號。',48,'全唐诗/poet.song.163000.json','["雲合蒼天怒，風生老木號。", "雨跳珠點急，浪湧雪花高。", "作爽輕頭目，俄寒豎髮毛。", "頑軀金氣盛，敢與瘴相鏖。"]'),
('0cff5e49-400c-45da-892b-ab55cd1e2885','檄充晉康考官舟行薄暮霞光與水相映緬懷諸幕兄  其一','曾丰','宋','宋诗','song-poetry','','[]','水作琉璃碧，霞爲琥珀紅。',48,'全唐诗/poet.song.163000.json','["水作琉璃碧，霞爲琥珀紅。", "因依光迭射，畢竟色俱空。", "鼓楫乘秋氣，掀篷納晚風。", "長教凉似許，判得住南中。"]'),
('eb39c71b-d187-4c2f-8919-2e779989bc97','檄充晉康考官舟行薄暮霞光與水相映緬懷諸幕兄  其二','曾丰','宋','宋诗','song-poetry','','[]','同幕時相敘，清談到夜分。',48,'全唐诗/poet.song.163000.json','["同幕時相敘，清談到夜分。", "一朝纔被檄，兩處便拘文。", "未學歸巢雁，猶爲出岫雲。", "南中不聞雁，有雁不堪聞。"]'),
('a731ebb5-a635-47c7-ad3c-7475a12ff325','檄至德慶舟中晚眺','曾丰','宋','宋诗','song-poetry','','[]','雨過山毛浄，潮生水面平。',48,'全唐诗/poet.song.163000.json','["雨過山毛浄，潮生水面平。", "羣鴉團晚色，一鵲發秋聲。", "所至好爲客，其容寬作程。", "吾癡愁不了，愁亦太癡生。"]'),
('2c90fb28-2b63-4876-aeb0-c501cb2077c7','八月上浣與張元輔張子濟小飲德慶貢院聽簷下蟲聲','曾丰','宋','宋诗','song-poetry','','[]','金氣涵秋晚，銀河耿夜晴。',48,'全唐诗/poet.song.163000.json','["金氣涵秋晚，銀河耿夜晴。", "天塗雲色淡，月浸桂花清。", "露坐疑僵髮，風餐欲冰羹。", "壁蟲不相亮，更作戒寒聲。"]'),
('39fa04c9-566b-4005-8ed4-4ab1c38090a3','厨鷄竄房中張元輔憐而賦詩余不能自已亦爲一篇','曾丰','宋','宋诗','song-poetry','','[]','驚栖潛避影，啄怯暗吞聲。',48,'全唐诗/poet.song.163000.json','["驚栖潛避影，啄怯暗吞聲。", "似惜千金命，而逃五鼎烹。", "肋枯那便齒，皮瘠不宜羹。", "肉食非吾事，從今戒殺生。"]'),
('6b65790b-a7a9-4e69-b7c6-3199aeb261f6','丁未上元後二日得老兒稚子平安三日得三從四十伯五十九叔訃  其一','曾丰','宋','宋诗','song-poetry','','[]','夜窗燈黯鬰，春枕夢交加。',48,'全唐诗/poet.song.163000.json','["夜窗燈黯鬰，春枕夢交加。", "二父隨朝露，餘生任歲華。", "倚廬晨復夕，占鵲驗還差。", "爲報兒曹道，先收待客茶。"]'),
('206a03d4-755b-45bb-a3cc-c0f3780367b3','丁未上元後二日得老兒稚子平安三日得三從四十伯五十九叔訃  其二','曾丰','宋','宋诗','song-poetry','','[]','姑無忘冢婦，祖未識頭孫。',48,'全唐诗/poet.song.163000.json','["姑無忘冢婦，祖未識頭孫。", "路遠徒惆悵，書來得慰存。", "冬無餘穀粟，春可養鷄豚。", "切勿廢生事，看人飽更溫。"]'),
('35c3391c-ed7f-4dd7-a9d0-a475feefd344','丁未仲春思鄉味會之樂簡寄董伯虎','曾丰','宋','宋诗','song-poetry','','[]','天下清明節，江南笋蕨天。',48,'全唐诗/poet.song.163000.json','["天下清明節，江南笋蕨天。", "亂生無事種，爭賣不論錢。", "带醋香醒鼻，和糟味滑咽。", "季鷹蓴菜念，徒更雜魚鮮。"]'),
('69dfb5f7-7e0a-4650-a34b-92b213609195','五月一日薄暮至三水倚檣欹枕','曾丰','宋','宋诗','song-poetry','','[]','皓月三江口，青蘋四岸邊。',48,'全唐诗/poet.song.163000.json','["皓月三江口，青蘋四岸邊。", "風頭橫立海，水面上浮天。", "陰氣猶能雜，陽威不敢燃。", "夏行秋月令，造物相吾眠。"]'),
('463fb944-2c95-4c88-a9b5-e189291ef75e','初秋夜歎','曾丰','宋','宋诗','song-poetry','','[]','髣髴蟾蜍影，蕭然蟋蟀聲。',48,'全唐诗/poet.song.163000.json','["髣髴蟾蜍影，蕭然蟋蟀聲。", "秋隨桐葉倒，心與鬢毛驚。", "舊出斑無數，新添白幾莖。", "百年成底事，攬鏡若爲情。"]'),
('29d6ae60-302d-43db-8e02-b7e0dff221dc','張京幹還故廨創茅亭揭以清心  其一','曾丰','宋','宋诗','song-poetry','','[]','雲初間出岫，鵲近喜歸巢。',48,'全唐诗/poet.song.163000.json','["雲初間出岫，鵲近喜歸巢。", "舊物數間屋，新功一把茅。", "壺中非小有，法界可全包。", "公退焚香坐，都忘夢幻泡。"]'),
('ddba31c2-abb6-4d32-a055-b307149a63fd','張京幹還故廨創茅亭揭以清心  其二','曾丰','宋','宋诗','song-poetry','','[]','歲月不饒與，簿書無了期。',48,'全唐诗/poet.song.163000.json','["歲月不饒與，簿書無了期。", "隨緣贏取懶，著意倒成癡。", "朝斂幕中板，晚圍簷下碁。", "更防閑散裏，忙甚坐曹時。"]'),
('915bde6b-7795-45bf-9e07-b4e4028fefe4','贈五行家董季謙','曾丰','宋','宋诗','song-poetry','','[]','奴隸侯千戶，屠沽祿萬鍾。',48,'全唐诗/poet.song.163000.json','["奴隸侯千戶，屠沽祿萬鍾。", "書生無此望，造物不吾容。", "漁釣其清職，田園乃素封。", "煩君試推似，天意合相從。"]'),
('38f83ebb-9236-40f5-a47e-dd2c2f3b50a2','辭東廟途中作','曾丰','宋','宋诗','song-poetry','','[]','海近微茫白，山窮次第平。',48,'全唐诗/poet.song.163000.json','["海近微茫白，山窮次第平。", "固然天遠大，加以眼高明。", "草木驚秋意，松先撓客情。", "西風莫相惱，歸計此回成。"]'),
('9ab12a3d-f1d6-49a0-ac9b-d4d5f6f81cba','潮到看人發舟','曾丰','宋','宋诗','song-poetry','','[]','潮信猶爲小，風聲未至雄。',48,'全唐诗/poet.song.163000.json','["潮信猶爲小，風聲未至雄。", "船輕爭向上，江闊敢當中。", "持後柁宣力，當先帆用功。", "區區篙艕槳，罪與素餐同。"]'),
('dce5fccc-2558-4a47-891b-26f79af32ed1','解任登舟離胥口','曾丰','宋','宋诗','song-poetry','','[]','挈挈離胥口，駸駸到峽中。',48,'全唐诗/poet.song.163000.json','["挈挈離胥口，駸駸到峽中。", "江平無駭浪，船穩不驚風。", "逆水從難上，兼程與易同。", "家人解吾意，呼酒犒篙工。"]'),
('b9919ed6-0e64-4bca-9646-e7b813421b89','再遊南華臨出門書記妙瑩獻絕句索留題賦兩篇謝之  其一','曾丰','宋','宋诗','song-poetry','','[]','詩數江西派，禪歸嶺表宗。',48,'全唐诗/poet.song.163000.json','["詩數江西派，禪歸嶺表宗。", "他寧無出手，終莫敢當鋒。", "欠子廣長舌，資吾磊塊胸。", "打包隨牒跡，豈料適相逢。"]'),
('10d458b2-9eb1-4915-8558-a0f1aeba2760','再遊南華臨出門書記妙瑩獻絕句索留題賦兩篇謝之  其二','曾丰','宋','宋诗','song-poetry','','[]','社裏得詩僧，錚錚可正平。',48,'全唐诗/poet.song.163000.json','["社裏得詩僧，錚錚可正平。", "子今能發願，吾亦許同盟。", "不轉虛空話，難歸雅頌聲。", "金篦容我刮，管取眼增明。"]'),
('9e36b278-cb64-45d7-8f66-710d0fe700c4','遊齊覺寺  其一','曾丰','宋','宋诗','song-poetry','','[]','築寺依橫嶠，開門對遠汀。',48,'全唐诗/poet.song.163000.json','["築寺依橫嶠，開門對遠汀。", "聞之心已渴，見者眼皆醒。", "水瀉鴨頭綠，山排螺髻青。", "他無避地處，得此可忘形。"]'),
('b0191caf-a540-4449-9cfb-778e8dbb89e4','遊齊覺寺  其二','曾丰','宋','宋诗','song-poetry','','[]','不謂僧遊息，猶容俗往還。',48,'全唐诗/poet.song.163000.json','["不謂僧遊息，猶容俗往還。", "薰爐烟縷縷，茗椀雨班班。", "剟坐移門外，携樽置竹間。", "小詩題歲月，多助得江山。"]'),
('fa4d7756-80e5-4b95-8094-86244f369ed4','窮冬積陰','曾丰','宋','宋诗','song-poetry','','[]','將雨未成雨，久霜無復霜。',48,'全唐诗/poet.song.163000.json','["將雨未成雨，久霜無復霜。", "青天方變色，白日且韜光。", "乘勢羣陰逞，歸根萬物忙。", "猶餘南過雁，歲晚客他鄉。"]'),
('bf8ca02c-8abd-4198-bb19-298373841954','路見','曾丰','宋','宋诗','song-poetry','','[]','沿途羈况惡，觸鼻野花香。',48,'全唐诗/poet.song.163000.json','["沿途羈况惡，觸鼻野花香。", "賈酒行如失，搜詩坐似忘。", "不能爲醉聖，寧敢放酲狂。", "家圃含風蘂，垂聊祇自芳。"]'),
('94c75416-2012-42f2-a1a5-7df90299e44a','靜聽鳥相喧','曾丰','宋','宋诗','song-poetry','','[]','靜聽鳥相喧，其中有意存。',48,'全唐诗/poet.song.163000.json','["靜聽鳥相喧，其中有意存。", "提壺愛賓客，脫袴惜兒孫。", "氣結遼城怨，聲銜蜀帝冤。", "阿誰能細譯，收拾入方言。"]'),
('42b65543-7b2f-49eb-9527-df63cb7be538','經從兩浙','曾丰','宋','宋诗','song-poetry','','[]','渺渺秦航渡，茫茫夏蓋湖。',48,'全唐诗/poet.song.163000.json','["渺渺秦航渡，茫茫夏蓋湖。", "地形東带越，山勢右襟吳。", "勝負心徒熱，興亡骨併枯。", "古今姑棄置，一笑問歸途。"]'),
('c7bb626e-997f-42ea-aa0a-407a2324eac3','候潮錢塘渡','曾丰','宋','宋诗','song-poetry','','[]','眼厭紛華久，身離闤闠初。',48,'全唐诗/poet.song.163000.json','["眼厭紛華久，身離闤闠初。", "市聲方較少，春色况猶餘。", "海沸如中熱，山浮若內虛。", "坐窮消息理，萬事付乘除。"]'),
('25663f30-3b8d-40bf-b400-c364771f404c','都下卧中','曾丰','宋','宋诗','song-poetry','','[]','屋密風傳冷，窗虛月漏明。',48,'全唐诗/poet.song.163000.json','["屋密風傳冷，窗虛月漏明。", "九衢朝馬動，四壁候蟲鳴。", "街吏高呵道，衙官急殺更。", "人行吾尚卧，自分利名輕。"]'),
('e5b5e0f5-8e7e-47a5-9788-3979b8f93f9f','坐病不及赴少卿羅春伯登樓觀雪之集因成小詩馳呈兼簡何同叔判院徐用之帳幹','曾丰','宋','宋诗','song-poetry','','[]','飽送欹眠美，寒添兀坐愁。',48,'全唐诗/poet.song.163000.json','["飽送欹眠美，寒添兀坐愁。", "從雄容有酒，訪戴豈無舟。", "怯出風前立，妨陪雪裏遊。", "想餘鹽絮句，題遍仲宣樓。"]'),
('91c710ad-7552-442e-b2d3-128b8a6c9202','續赴羅少卿飯坐上點和前韻','曾丰','宋','宋诗','song-poetry','','[]','孤吟成錮疾，旅坐失牢愁。',48,'全唐诗/poet.song.163000.json','["孤吟成錮疾，旅坐失牢愁。", "晝氣溟銀海，春風沸玉舟。", "詼諧狂後出，汗漫醉中遊。", "已忘行藏事，從渠自倚樓。"]'),
('3eb52d03-457c-4a94-9d8b-871f3a2ba447','冬旅懷歸','曾丰','宋','宋诗','song-poetry','','[]','周正曾未了，秦臘又相尋。',48,'全唐诗/poet.song.163000.json','["周正曾未了，秦臘又相尋。", "風日留餘暖，乾坤失衆陰。", "烏翻南至影，雁墮北來音。", "黄落歸根葉，前陳示意深。"]'),
('f92fa4b4-27e6-407f-85ab-37c9f0a73b12','送五羊曾仲卿改秩受縣南歸','曾丰','宋','宋诗','song-poetry','','[]','近派家于粵，初封國自鄫。',192,'全唐诗/poet.song.163000.json','["近派家于粵，初封國自鄫。", "要無非我族，終不是它曾。", "閲譜宗盟重，聯官事契增。", "居常多阻間，僅獲一瞻承。", "逆旅重交臂，高談屢撫膺。", "秋風樓上月，雨夜案頭燈。", "把酒相兄弟，論文復友朋。", "衆星朝北斗，羣翼讓南鵬。", "墨綬恩光爛，花城喜氣蒸。", "宜民條教出，溢耳頌聲騰。", "鶚牘交飛上，鸞臺緩步登。", "難中須有立，妙處要無稱。", "顧我羞低首，從今樂曲肱。", "未忘爲吏隠，猶學在家僧。", "念舊寧無感，馳書恐不能。", "官高餘健走，可遣到廬陵。"]'),
('8caf3d53-1404-4fa1-83f4-efc677c37dac','呈江西倉使汪太社二首  其一','曾丰','宋','宋诗','song-poetry','','[]','兩朝多侍從，四海一端明。',48,'全唐诗/poet.song.163000.json','["兩朝多侍從，四海一端明。", "與上開皇極，于今享太平。", "芝蘭盈砌茁，鴻雁刺天鳴。", "父子同休少，公家更弟兄。"]'),
('03644410-4808-4833-a8cb-dd41c048cc60','呈江西倉使汪太社二首  其二','曾丰','宋','宋诗','song-poetry','','[]','乾道羣充賦，尚書獨主盟。',48,'全唐诗/poet.song.163000.json','["乾道羣充賦，尚書獨主盟。", "當今賢使者，似我老先生。", "湛輩追隨念，韓門顧盼情。", "相逢談不了，敢更以詩鳴。"]'),
('c4446525-c64c-432e-bc78-03c403b08a45','贈五行家鄭逢元','曾丰','宋','宋诗','song-poetry','','[]','盤古流形後，牽牛起度餘。',48,'全唐诗/poet.song.163000.json','["盤古流形後，牽牛起度餘。", "數寧逃久刺，算不外乘除。", "趙達固非誤，嵩真容有疎。", "試推十年事，容我驗何如。"]'),
('b9903c94-2472-43a5-8eef-16c67d46bcc9','吳必顯欲遠出謁故舊愬情悃賦二章贊其行  其一','曾丰','宋','宋诗','song-poetry','','[]','燈火頭蒙垢，年華鬢茁絲。',48,'全唐诗/poet.song.163000.json','["燈火頭蒙垢，年華鬢茁絲。", "詩書猶見負，韋布未相辭。", "有處可彈鋏，何愁無置錐。", "丈夫行止計，不必問妻兒。"]'),
('07e1fab9-9e23-4548-a392-236f3dce323f','吳必顯欲遠出謁故舊愬情悃賦二章贊其行  其二','曾丰','宋','宋诗','song-poetry','','[]','貧寧少壯貧，貧老却難禁。',48,'全唐诗/poet.song.163000.json','["貧寧少壯貧，貧老却難禁。", "兒女婚姻逼，風霜疾病侵。", "令渠常白眼，見子亦寒心。", "况是舊相議，人人義斷金。"]'),
('32feb8da-ae6a-4436-9f1c-89bef2804424','庚戌三月赴官離松江道中','曾丰','宋','宋诗','song-poetry','','[]','好風消雨鬰，惡水長泥淫。',48,'全唐诗/poet.song.163000.json','["好風消雨鬰，惡水長泥淫。", "戲哢鶑饒舌，狂遊蝶放心。", "枯萎青未了，紅紫老相尋。", "物與我爲一，嗟餘只自瘖。"]'),
('20b524b4-1502-4064-a5ad-103acc94fd19','游稚周和余韻見示復答之','曾丰','宋','宋诗','song-poetry','','[]','韋布窮無濫，軒裳貴莫淫。',48,'全唐诗/poet.song.163000.json','["韋布窮無濫，軒裳貴莫淫。", "一家兄弟學，千古聖賢心。", "去道不能寸，持身肯枉尋。", "它年鳳鳴處，百鳥定皆瘖。"]'),
('7fa7f9c4-bd3a-4f9f-888d-c8ef1673ba99','庚戌赴官過王俊臣門留別','曾丰','宋','宋诗','song-poetry','','[]','師道非韓愈，門人有孟郊。',48,'全唐诗/poet.song.163000.json','["師道非韓愈，門人有孟郊。", "未投攻玉石，已拔塞心茅。", "衆妙俱神悟，殘文尚手抄。", "江西盟社裏，它日續弦膠。"]'),
('6b903a3d-63d5-42d5-b6b1-55422b88197b','過湘弔屈','曾丰','宋','宋诗','song-poetry','','[]','彭蠡澤南地，祝融峯上天。',48,'全唐诗/poet.song.163000.json','["彭蠡澤南地，祝融峯上天。", "其洪無擇物，所褊不容賢。", "湘水恨歸處，衡雲愁到邊。", "勇哉輸一死，死日勝生年。"]'),
('d21b3dcf-a41c-4323-b619-76e2db74df92','衡陽西溪','曾丰','宋','宋诗','song-poetry','','[]','眼底西溪少，碑間北客多。',48,'全唐诗/poet.song.163000.json','["眼底西溪少，碑間北客多。", "雪霜風日剝，歲月姓名訛。", "後有詩堪勒，傍無石可磨。", "可磨懸絕處，留勒中興歌。"]'),
('10d545c9-976b-4332-8b0d-deb1f829896b','衡陽合江亭','曾丰','宋','宋诗','song-poetry','','[]','經過西溪勝，追尋後洞幽。',48,'全唐诗/poet.song.163000.json','["經過西溪勝，追尋後洞幽。", "江形叉燕尾，石勢湧鰲頭。", "至止岳餘氣，歸歟湖合流。", "酒杯饒不下，千古弔湘愁。"]'),
('b49b07ed-c86a-45a8-b1de-1985e41b88f3','君舉再飯五峰閣四望','曾丰','宋','宋诗','song-poetry','','[]','城中無隙地，閣上有餘天。',48,'全唐诗/poet.song.163000.json','["城中無隙地，閣上有餘天。", "白雪重湖浪，黄茅五嶺烟。", "高樓南蜃湧，大字北鴻連。", "總是詩之具，收歸作畫傳。"]'),
('0385a2dd-cc37-4d1c-99b2-8d5583fffb4b','神農塚在茶陵舜塚在道途中行人指似焉','曾丰','宋','宋诗','song-poetry','','[]','康樂神農塚，蒼梧大舜邱。',48,'全唐诗/poet.song.163000.json','["康樂神農塚，蒼梧大舜邱。", "望望千許里，表表萬斯秋。", "御祝書名謹，皇家祀典優。", "行人相指似，若或見松楸。"]'),
('7f950d80-34a5-46d6-9d2e-e5fc922a2a25','至榕溪閣覽黄','曾丰','宋','宋诗','song-poetry','','[]','元年留桂嶺，六月至榕溪。',48,'全唐诗/poet.song.163000.json','["元年留桂嶺，六月至榕溪。", "水木清相湱，風烟暝欲淒。", "精廬千古跡，樂石兩公題。", "造物生賢意，寧圖到廣西。"]'),
('599697ae-f119-494d-9138-0fb3a92c436b','至興安縣遊乳洞','曾丰','宋','宋诗','song-poetry','','[]','雷怒潛轟響，龍驚起噴津。',48,'全唐诗/poet.song.163000.json','["雷怒潛轟響，龍驚起噴津。", "泥中灘泯跡，卧處有遺鱗。", "三伏了無暑，四時長是春。", "遊嬉白衣老，疑是避秦人。"]'),
('4d0032fc-d385-4a7f-b5ed-1987ebb4b470','吊落梅','曾丰','宋','宋诗','song-poetry','','[]','佛來非墮有，仙去豈超無。',48,'全唐诗/poet.song.163000.json','["佛來非墮有，仙去豈超無。", "寧可死歸潔，莫教生合汙。", "出餘純白在，入與太清俱。", "百世下回首，高風立懦夫。"]'),
('6ff266dd-1b36-4fbb-8d32-969a9f21511e','春夜感物書懷','曾丰','宋','宋诗','song-poetry','','[]','閣閣蛙鳴夜，嘈嘈鳥語春。',48,'全唐诗/poet.song.163000.json','["閣閣蛙鳴夜，嘈嘈鳥語春。", "物情猶任理，世事豈由人。", "時自有遲速，道初無屈伸。", "聖賢得貧力，吾恨不全貧。"]'),
('a52d2300-ca89-468a-a7c2-d4a0e884a060','一春不得家書因省歸計','曾丰','宋','宋诗','song-poetry','','[]','飛絮白相颭，落花紅自紛。',48,'全唐诗/poet.song.163000.json','["飛絮白相颭，落花紅自紛。", "鯉魚何處去，楊鳥豈堪聞。", "婦老難教饁，兒驕不解耘。", "歸耕誠所願，耕責望誰分。"]'),
('c5ced51b-f6e0-4e9a-9c63-dbc3a05620d3','憲使范右司具饌屬屬官爲主人又屬衡陽張宰助筵同遊石鼓書院','曾丰','宋','宋诗','song-poetry','','[]','湘水前縈带，蒸江後引裾。',216,'全唐诗/poet.song.163000.json','["湘水前縈带，蒸江後引裾。", "中容齊塔阜，上建讀書廬。", "氣象河汾上，規模景祐餘。", "帝王無異學，孔孟有遺書。", "絳帳講之熟，青衿受以虛。", "心原逢左右，理窟悟終初。", "糟粕包高厚，精華寄起居。", "作成端若此，徵用合何如。", "學士唐全炬，經師漢石渠。", "致君登栗陸，措俗減華胥。", "訪古行陪履，觀光坐接祛。", "上臺供甕酒，傍縣具盤蔬。", "笑臉人人醉，設眉箇箇舒。", "傳香薰馧馞，寄傲卧籧篨。", "如浴沂中水，而觀濠上魚。", "落暉猶可却，上馬不妨徐。", "紀勝俾傳遠，書崖字放疎。", "姓名年月日，刻罷賦歸歟。"]'),
('86f891db-f699-459d-bd2f-f39a95b90eb9','義寧禱霽未應','曾丰','宋','宋诗','song-poetry','','[]','叢祠精舍裏，所至以柴燔。',48,'全唐诗/poet.song.163000.json','["叢祠精舍裏，所至以柴燔。", "未沐佛青眠，何圖神素餐。", "雨師佯弄霽，農叟暗含冤。", "老令深相誤，從知罪莫原。"]'),
('d3ff683e-6b1e-4d74-bf47-39d30547eb24','擬試以蟲鳴秋','曾丰','宋','宋诗','song-poetry','','[]','大化轉無休，蟲那得自由。',72,'全唐诗/poet.song.163000.json','["大化轉無休，蟲那得自由。", "暗中誰擘口，閒裏共鳴秋。", "氣感蟾蜍冷，聲歸蟋蟀愁。", "幽閨勤杼柚，遠塞急衾裘。", "豈不便鉗口，而猶强出頭。", "呶呶竟無益，也勝喚晴鳩。"]'),
('dac5b82c-4052-4fec-b9da-e3c0be7b6b6f','庚戌冬乘浣隙謁西林寺漸老  其一','曾丰','宋','宋诗','song-poetry','','[]','下走長呵道，前驅疾喚航。',48,'全唐诗/poet.song.163000.json','["下走長呵道，前驅疾喚航。", "足贏黏履淖，頭羨颭巾霜。", "澗淺橋梁廢，村深道路荒。", "不圖爲政暇，猶爲看山忙。"]'),
('77fa27c4-ac54-4f91-82b5-c888a8f81c7c','庚戌冬乘浣隙謁西林寺漸老  其二','曾丰','宋','宋诗','song-poetry','','[]','傳衣今北秀，駐錫小西林。',48,'全唐诗/poet.song.163000.json','["傳衣今北秀，駐錫小西林。", "握手鼎相別，敲門踵見尋。", "溫顔塵外禮，軟語法中音。", "從此利名垢，那容點我心。"]'),
('a117aa6d-d645-40a8-ac9d-e46ff73c22a2','居官思歸','曾丰','宋','宋诗','song-poetry','','[]','有性非便鬨，無謀可取閑。',48,'全唐诗/poet.song.163000.json','["有性非便鬨，無謀可取閑。", "顛毛新雪旺，臉暈舊朱慳。", "槽食馬懷土，棧居羊樂山。", "若爲陶靖節，未賦鳥知還。"]'),
('cbe30c3a-2fc5-405d-bd2d-23d7bf603e55','猶子松字茂之者慶長兄之子也有志于學樂從余遊歲在庚戌偕至廣西談經論文次授二詩  其一','曾丰','宋','宋诗','song-poetry','','[]','廼翁窮古學，之子廣家聲。',48,'全唐诗/poet.song.163000.json','["廼翁窮古學，之子廣家聲。", "頭不容高枕，心無外短檠。", "床頭周易熟，角上漢書精。", "更得賢師友，終當大有成。"]'),
('f63838cf-2de8-44f4-afbb-ec09cecc1ed6','猶子松字茂之者慶長兄之子也有志于學樂從余遊歲在庚戌偕至廣西談經論文次授二詩  其二','曾丰','宋','宋诗','song-poetry','','[]','鯉非慳授伋，點豈吝傳參。',48,'全唐诗/poet.song.163000.json','["鯉非慳授伋，點豈吝傳參。", "內棄元和脚，旁求一祖心。", "能容石攻玉，會使鐵成金。", "十訣先傳九，餘其默自尋。"]'),
('0cec0920-7ab1-41ea-b1a0-e6c96fa92304','送陰陽家彭元清','曾丰','宋','宋诗','song-poetry','','[]','嶺北山開脈，江西水發源。',48,'全唐诗/poet.song.163000.json','["嶺北山開脈，江西水發源。", "陰陽餘闔闢，小大幾乾坤。", "銀海有精力，金函無法門。", "頻年過我客，始可與君論。"]'),
('a20f653e-34b8-436b-a0dc-9ae61f43cd2c','出郊','曾丰','宋','宋诗','song-poetry','','[]','曉欲晴還雨，春疑早又遲。',48,'全唐诗/poet.song.163000.json','["曉欲晴還雨，春疑早又遲。", "勾萌麻俟命，穎拔麥乘時。", "水有浮天意，山非入俗姿。", "野人逢野景，相愛似相知。"]'),
('e96e05d1-e428-485e-add0-3e35eaaddca7','寧都趙令君貽貺五言四首意索余和不可虛辱如其意酬之  其一','曾丰','宋','宋诗','song-poetry','','[]','只今公子行，蓋不數其餘。',48,'全唐诗/poet.song.163000.json','["只今公子行，蓋不數其餘。", "要牘江西社，親傳肘後書。", "飽聞劉子政，渴見馬相如。", "肯許交盟結，休嫌笠溷車。"]'),
('ea381d74-c5ac-4479-bf3e-c9956467bef6','寧都趙令君貽貺五言四首意索余和不可虛辱如其意酬之  其二','曾丰','宋','宋诗','song-poetry','','[]','江西窮處縣，松竹勿嫌深。',48,'全唐诗/poet.song.163000.json','["江西窮處縣，松竹勿嫌深。", "簿領塵中坐，溪山好處吟。", "鳴絃人異調，把酒月同斟。", "倘有可書事，閑收入志林。"]'),
('3ee5d7d0-45db-4c8d-bc96-ee1c01b7ede8','寧都趙令君貽貺五言四首意索余和不可虛辱如其意酬之  其三','曾丰','宋','宋诗','song-poetry','','[]','介庵前後集，熟讀眼生花。',48,'全唐诗/poet.song.163000.json','["介庵前後集，熟讀眼生花。", "學問祖千古，文章雌百家。", "今非公莫繼，况有子堪誇。", "換骨蓬萊去，分吾九轉沙。"]'),
('a76e4089-f22a-4ad1-9c93-031c11ea3332','寧都趙令君貽貺五言四首意索余和不可虛辱如其意酬之  其四','曾丰','宋','宋诗','song-poetry','','[]','世途無復古，吾道不宜今。',48,'全唐诗/poet.song.163000.json','["世途無復古，吾道不宜今。", "風月多饒舌，軒裳久死心。", "家猶須五斗，命豈止千金。", "有路可親炙，那能入桂林。"]'),
('edeab35b-0c34-4f12-8748-6cbf21519c5f','與鄧繼高望沙山同賦','曾丰','宋','宋诗','song-poetry','','[]','先喜見沙山，俄藏靉靆間。',48,'全唐诗/poet.song.163000.json','["先喜見沙山，俄藏靉靆間。", "雲非奪吾好，天固與人慳。", "未遽清風起，何當舊觀還。", "崢嶸終莫掩，茲且聽潺湲。"]'),
('e6cec21a-a37b-47f7-96f8-3639873b15f0','瀧岡','曾丰','宋','宋诗','song-poetry','','[]','堂堂馬鬣封，清淑鞠其中。',48,'全唐诗/poet.song.163000.json','["堂堂馬鬣封，清淑鞠其中。", "庚戌歲行遠，熙寧恩數空。", "石羊委荒草，木鶴矯清風。", "吊古淒相慨，蒼然十八公。"]'),
('0fb06ce3-2087-469c-a634-fb0d3ffe6055','送董一之之長沙謁周丞相','曾丰','宋','宋诗','song-poetry','','[]','北陸澄彭蠡，南青拔祝融。',48,'全唐诗/poet.song.163000.json','["北陸澄彭蠡，南青拔祝融。", "古都爲漢郡，今牧得周公。", "訪戴休辭遠，依劉莫諱窮。", "寬爲五旬別，歸橐盎春宮。"]'),
('1f6baded-1efd-41ef-9c61-97ce86faf49d','送管長源之子光祖往謁周益公','曾丰','宋','宋诗','song-poetry','','[]','齒德兩崢嶸，嚴君漢伏生。',48,'全唐诗/poet.song.163000.json','["齒德兩崢嶸，嚴君漢伏生。", "勗哉恢學力，行矣赫家聲。", "一代道宗主，三朝人老成。", "金篦容刮膜，管取眼增明。"]'),
('640e42f1-dce3-492f-8418-c4df864e6d94','三山寺戲堂頭僧  其一','曾丰','宋','宋诗','song-poetry','','[]','竹不容塵入，山寧與俗交。',48,'全唐诗/poet.song.163000.json','["竹不容塵入，山寧與俗交。", "開門懸梵偈，置榻解僧包。", "不見肘生柳，未聞頭戴巢。", "葛籐非我事，笑語浪相嘲。"]'),
('c21c7a34-33f4-4cf3-a218-6e5899c6718e','三山寺戲堂頭僧  其二','曾丰','宋','宋诗','song-poetry','','[]','晝熱催三伏，宵凉報五更。',48,'全唐诗/poet.song.163000.json','["晝熱催三伏，宵凉報五更。", "鍾鳴塵外響，犬吠世間聲。", "强聒蛙鳴雨，譸張鳥噪晴。", "黎明重睡熟，栩栩夢魂清。"]'),
('82b24324-eb62-49b8-88d9-e56b2a21d951','晚春客路','曾丰','宋','宋诗','song-poetry','','[]','流水綠相沸，落花紅自紛。',48,'全唐诗/poet.song.163000.json','["流水綠相沸，落花紅自紛。", "乾坤容盎盎，草木意芸芸。", "布穀聲通俗，提壺語带文。", "杜鵑相告處，益有激而云。"]'),
('eca8c690-dad6-42fe-b591-28626387c9dc','季夏宿省前董家樓','曾丰','宋','宋诗','song-poetry','','[]','明朝從伏末，今日幸秋初。',48,'全唐诗/poet.song.163000.json','["明朝從伏末，今日幸秋初。", "御閣斜陽裏，天溝小雨餘。", "風吹塵陌靜，月照堊窗虛。", "一枕三更夢，清凉意自如。"]'),
('80e97077-e365-48dc-be7a-bf7e2086418a','癸丑秋遊疏山首坐璣上人以其嘗在五羊相識求詩','曾丰','宋','宋诗','song-poetry','','[]','達磨泉華湧，曹溪水綫開。',48,'全唐诗/poet.song.163000.json','["達磨泉華湧，曹溪水綫開。", "何從南派出，而過北宗來。", "眼勘江西破，肩擔法窟回。", "少伸龍象蹋，無復說黄梅。"]'),
('52536f50-a897-4d3a-b596-8aa1cf0acc90','至漢灘訪陳梗臣','曾丰','宋','宋诗','song-poetry','','[]','雨速荷團碧，風催麥擺黄。',48,'全唐诗/poet.song.163000.json','["雨速荷團碧，風催麥擺黄。", "又容春回白，誰使我乾忙。", "杖履諳同社，江山駭異鄉。", "醉談平日事，歲久不無忘。"]'),
('fd32910a-4493-49e5-b293-14c4ca5ac448','月明復翳','曾丰','宋','宋诗','song-poetry','','[]','大鏡爲誰圓，非昭莫破昏。',48,'全唐诗/poet.song.163000.json','["大鏡爲誰圓，非昭莫破昏。", "澡身翻渤澥，耀德掠崑崙。", "有狗疑相食，何蟲欲見吞。", "光明法眼藏，點涴不成痕。"]'),
('7efaa5e5-83b6-4687-ab85-3f3ef0da25aa','贈高山人德充','曾丰','宋','宋诗','song-poetry','','[]','渾沌包元氣，支離入九流。',48,'全唐诗/poet.song.163000.json','["渾沌包元氣，支離入九流。", "陰陽從此有，源委問誰求。", "眼法窮山脈，囊經掛杖頭。", "卜吾新築處，相伴得沙鷗。"]'),
('f5cb7c89-e0bf-452c-af62-deeef2f58d7d','秋意自適','曾丰','宋','宋诗','song-poetry','','[]','燕方爲去計，鴻已報來期。',48,'全唐诗/poet.song.163000.json','["燕方爲去計，鴻已報來期。", "老火晨相謝，新凉夜見私。", "耽書燈可眼，渴睡簟宜肌。", "好處分明是，橙黄橘綠時。"]'),
('f3b76bb2-6801-42ca-a0a0-4f85e5bdbe43','贈日者陸道人','曾丰','宋','宋诗','song-poetry','','[]','象彖該無極，蓍龜識未然。',48,'全唐诗/poet.song.163000.json','["象彖該無極，蓍龜識未然。", "學窮精髓處，談入髮毛顛。", "著脚九流外，回頭三畫前。", "屈伸皆在我，造物更無權。"]'),
('8fe20c8c-35b5-4078-a351-b14abb4784a8','秋日途中','曾丰','宋','宋诗','song-poetry','','[]','祝融辭退舍，少皞出專權。',48,'全唐诗/poet.song.163000.json','["祝融辭退舍，少皞出專權。", "清氣露之獨，殺聲風所偏。", "林凋光漏日，水落影澄天。", "每出皆秋季，與秋殊有緣。"]'),
('edb4b18b-a7ff-4183-91d9-effcc8800ff5','中秋途中','曾丰','宋','宋诗','song-poetry','','[]','携孥猶勝旅，在道不如家。',48,'全唐诗/poet.song.163000.json','["携孥猶勝旅，在道不如家。", "素已中秋月，徒然九日花。", "厚顔今事左，短氣始謀差。", "酒戒難爲破，澆胸且瀹茶。"]'),
('6510fccf-d58b-4850-a3e8-3d3adec59b97','窮秋羈路','曾丰','宋','宋诗','song-poetry','','[]','點也孤楓赤，參乎列岫青。',48,'全唐诗/poet.song.163000.json','["點也孤楓赤，參乎列岫青。", "新炊乘欲餒，舊釀誘初酲。", "床下秋蠉響，籬邊晚茁馨。", "六根元不動，在在得忘形。"]'),
('35946b60-57ed-4267-9df6-f920fe169290','冬景感懷','曾丰','宋','宋诗','song-poetry','','[]','草曾爲底惡，霜乃得能嗔。',48,'全唐诗/poet.song.163000.json','["草曾爲底惡，霜乃得能嗔。", "罷曳木無守，虔劉風不仁。", "楓衰山反本，石出水藏神。", "浩歎吾其老，猶爲逆旅人。"]'),
('e5a231e7-a17c-4688-aed7-02fb027670ae','送參議劉仲洪就京制置辟入蜀  其一','曾丰','宋','宋诗','song-poetry','','[]','蜀屈嚴公子，先聲到處驚。',48,'全唐诗/poet.song.163000.json','["蜀屈嚴公子，先聲到處驚。", "幕中添老杜，關外得長城。", "渭上屯田便，山西買馬平。", "願言賓與主，無立小功名。"]'),
('195cc450-f8e6-460e-969f-1320d07eac1a','送參議劉仲洪就京制置辟入蜀  其二','曾丰','宋','宋诗','song-poetry','','[]','江西清絕處，頻賞厭還休。',48,'全唐诗/poet.song.163000.json','["江西清絕處，頻賞厭還休。", "快作坤維去，閑爲丙穴遊。", "百牢山倒拔，三峽水橫流。", "未有人收拾，公其與筆謀。"]'),
('67817ff9-a3e2-4f7b-9dc3-f7a6cdd5f2cd','送中書舍人鄭惠叔入國  其一','曾丰','宋','宋诗','song-poetry','','[]','北戎輕用武，西漢重開邊。',48,'全唐诗/poet.song.163000.json','["北戎輕用武，西漢重開邊。", "幣帛毫芒費，生靈百萬全。", "幾馳銜命使，今輟判花員。", "專對從容道，王君正樂天。"]'),
('32adfb36-57a6-45b8-aa2e-137223561f82','送中書舍人鄭惠叔入國  其二','曾丰','宋','宋诗','song-poetry','','[]','萬里出疆車，馳驅過故都。',48,'全唐诗/poet.song.163000.json','["萬里出疆車，馳驅過故都。", "離離京國黍，獵獵塞垣榆。", "城邑堅和脆，山川逕與迂。", "要歸奏天子，潜筆寫爲圖。"]'),
('36836c96-3e90-4f21-84f4-c58b1611aa68','送副將胡義民到部復還廣東  其一','曾丰','宋','宋诗','song-poetry','','[]','等是天涯客，同爲嶺表官。',48,'全唐诗/poet.song.163000.json','["等是天涯客，同爲嶺表官。", "曳裾行躡履，持板立駢冠。", "簿領無多暇，杯盤未盡歡。", "夤緣離復合，爛熳醉長安。"]'),
('d30e9f88-689e-4a39-ac61-8489c8d9b3e4','送副將胡義民到部復還廣東  其二','曾丰','宋','宋诗','song-poetry','','[]','誦史胸翻海，談兵氣拔山。',48,'全唐诗/poet.song.163000.json','["誦史胸翻海，談兵氣拔山。", "奔馳非得已，矍鑠未容閑。", "瓜戍開年赴，梅關趁臘還。", "同僚如問我，炊玉待春班。"]'),
('788817d9-870d-43ea-aa13-183e4d6a0ecd','送鎮江張禹功獻邊事未報過建康謀辟','曾丰','宋','宋诗','song-poetry','','[]','邊上事千種，袖中書一編。',48,'全唐诗/poet.song.163000.json','["邊上事千種，袖中書一編。", "曳裾逢白眼，驤首隔青天。", "又輟安劉手，而撐訪戴船。", "嚴公猶欠士，應辟老詩仙。"]'),
('5727e686-383e-4640-9161-fcf5e10e65f6','中都邂逅新崇德宰范純之爲同館著語贈別','曾丰','宋','宋诗','song-poetry','','[]','文正三槐宅，延平六桂家。',48,'全唐诗/poet.song.163000.json','["文正三槐宅，延平六桂家。", "芝蘭含露秀，雕鶚著風斜。", "螭首終簪筆，河陽且種花。", "乘時長得意，毋忘夜分茶。"]'),
('2610d20e-210f-4b48-9268-4444f54ceab8','新淦陸伯仁過我錢塘逆旅中漫出詩篇輒蒙賞音敬賦短章相謝','曾丰','宋','宋诗','song-poetry','','[]','自從刪變雅，誰復許離騷。',48,'全唐诗/poet.song.163000.json','["自從刪變雅，誰復許離騷。", "顧我知音少，逢君著眼高。", "江山成疾錮，笑語破愁牢。", "勿浪相鎸切，姑從癢處搔。"]'),
('46825acb-cdbb-4644-99d3-f0e8319bed49','南浦思歸','曾丰','宋','宋诗','song-poetry','','[]','黨論開危道，功臣發禍端。',48,'全唐诗/poet.song.163000.json','["黨論開危道，功臣發禍端。", "未投彭澤紱，猶著外黄冠。", "用是顔其厚，言之鼻似酸。", "薄羹鱸鱠好，歸興未應闌。"]'),
('6ced0f7d-4d76-407d-afcd-2e483408077a','題諶氏奉先亭','曾丰','宋','宋诗','song-poetry','','[]','大協龜䶲兆，新成馬鬣封。',48,'全唐诗/poet.song.163000.json','["大協龜䶲兆，新成馬鬣封。", "雨餘生亂草，霜後拱孤松。", "泣酹春秋酒，顰撞旦暮鐘。", "若無翁仲在，誰鑒答恩胸。"]'),
('ba3fe524-4300-4a99-a138-ac64d113c4cc','贈浦城星家周廷輔','曾丰','宋','宋诗','song-poetry','','[]','胸中千歲日，掌上一天星。',48,'全唐诗/poet.song.163000.json','["胸中千歲日，掌上一天星。", "河洛無餘妙，著龜不敢靈。", "曾何便自狂，也不忘相形。", "左右逢原話，公卿滿意聽。"]'),
('8f9e773f-01f8-4234-8e3e-73a6a3796327','贈臨川浦城昌鄧二術士','曾丰','宋','宋诗','song-poetry','','[]','試出希夷手，偷傳混沌機。',48,'全唐诗/poet.song.163000.json','["試出希夷手，偷傳混沌機。", "不容天地遁，可使鬼神歸。", "爲我推奇偶，從今驗是非。", "萬猶失其一，却更問麻衣。"]'),
('c83013e5-11f6-4b5f-bfe8-7c2c9f311622','秩升得朝散告歸','曾丰','宋','宋诗','song-poetry','','[]','名似龍肝爾，實如雞肋然。',48,'全唐诗/poet.song.163000.json','["名似龍肝爾，實如雞肋然。", "言之爲下汗，愛者至垂涎。", "兒輩喜忘寐，臧徒舞欲顛。", "未深知我意，再拜賀于前。"]'),
('a133b4cb-a014-4315-8979-0f0155ca2b18','感梅有作','曾丰','宋','宋诗','song-poetry','','[]','浪爾逢時早，終然受命孤。',48,'全唐诗/poet.song.163000.json','["浪爾逢時早，終然受命孤。", "性便行所獨，物忌與之俱。", "巢許耳難浼，夷齊腸莫汙。", "十分要相稱，太素可爲徒。"]'),
('25e40da1-dcfb-4e37-8ddb-52bc01b4e3c9','逸圃','曾丰','宋','宋诗','song-poetry','','[]','莫空勞晚景，寧小負清時。',48,'全唐诗/poet.song.163000.json','["莫空勞晚景，寧小負清時。", "天下復何事，漢陰殊不知。", "桔槔時俯仰，畬插幾盈虧。", "吾策未爲得，渠言得策誰。"]'),
('10d4587e-a00f-4da1-95a8-76fa8af4972f','贈陰陽家謝子美','曾丰','宋','宋诗','song-poetry','','[]','心變掌中卦，地翻天上星。',48,'全唐诗/poet.song.163000.json','["心變掌中卦，地翻天上星。", "肩擔一盤古，背負幾玄冥。", "鶴失含禾瑞，龜亡食墨靈。", "擬修方士傳，乞換左仙經。"]'),
('5af855e1-2473-4ecf-8c65-9a1544c55fbe','書張必達詩詞卷首','曾丰','宋','宋诗','song-poetry','','[]','詩寫水雲真，詞傳花柳神。',48,'全唐诗/poet.song.163000.json','["詩寫水雲真，詞傳花柳神。", "溜脂松濯濯，凝粉竹津津。", "色者空中幻，聲其寂裏塵。", "願言收視聽，其細入無倫。"]'),
('1ea3223a-aea9-4c11-b7c5-c1b07a31a624','贈術者朱明遠  其一','曾丰','宋','宋诗','song-poetry','','[]','占得九流籍，名爲三命家。',48,'全唐诗/poet.song.163000.json','["占得九流籍，名爲三命家。", "逆推枝上葉，翻算水中沙。", "吾數豈其偶，子言無乃誇。", "相過勿浪說，同飯更分茶。"]'),
('cae48df5-aca2-4349-9f20-6e570c99e39b','贈術者朱明遠  其二','曾丰','宋','宋诗','song-poetry','','[]','五嶽精華裂，三光度數分。',48,'全唐诗/poet.song.163000.json','["五嶽精華裂，三光度數分。", "人才非是少，事業未之聞。", "信道鍾南氣，難教策北勳。", "中原流落士，物色試煩君。"]'),
('f2c2457b-8c44-4f73-b02f-88cbee663f61','贈術者朱明遠  其三','曾丰','宋','宋诗','song-poetry','','[]','挾術有如子，那須要我詩。',48,'全唐诗/poet.song.163000.json','["挾術有如子，那須要我詩。", "曲江何處住，全廣是人知。", "未宦中都者，猶期大貴誰。", "今言他日驗，人口勝于碑。"]'),
('af0d469e-6f91-434d-ba6c-7f86ac181711','贈術者','曾丰','宋','宋诗','song-poetry','','[]','莫辦田爲活，猶貪祿代耕。',48,'全唐诗/poet.song.163000.json','["莫辦田爲活，猶貪祿代耕。", "區區營一飽，僅僅了餘生。", "幸脫蛇驚犬，休談戊食庚。", "他逢豪傑士，口莫惜公卿。"]'),
('bb53ccee-812e-47bb-9bdb-32006cc3ffca','贈五行家涂舜舉','曾丰','宋','宋诗','song-poetry','','[]','火輪窮曠劫，初度起秋毫。',48,'全唐诗/poet.song.163000.json','["火輪窮曠劫，初度起秋毫。", "一寸心能照，三千界莫逃。", "許吾無乃過，竟此未相遭。", "使有相遭處，天其損我高。"]'),
('4238cd49-91bb-484f-9aa9-d19530148b0c','王俊臣嘗從予遊己未訪別于廬陵群庠','曾丰','宋','宋诗','song-poetry','','[]','師席我虛設，道機君飽參。',48,'全唐诗/poet.song.163000.json','["師席我虛設，道機君飽參。", "玄初疑若白，青卒過于藍。", "蟻戰何傷北，鵬圖不日南。", "江臯離合思，烟與水相涵。"]'),
('ded93d5d-d5c0-4f07-88c1-55d8cd5c2860','葉丞相之孫潛仲後余至中都同館相與談易累日先東歸敬賦詩送行','曾丰','宋','宋诗','song-poetry','','[]','客裏幸相逢，青燈幾夜同。',48,'全唐诗/poet.song.163000.json','["客裏幸相逢，青燈幾夜同。", "笑談機械外，操履準繩中。", "學問關宗旨，功名襲祖風。", "江船不吾泊，遽載易而東。"]'),
('ad5f393f-0414-4658-8ed1-455266bd3ae9','端午家集  其一','曾丰','宋','宋诗','song-poetry','','[]','自我生壬戌，于今到戊申。',48,'全唐诗/poet.song.163000.json','["自我生壬戌，于今到戊申。", "殊無送端午，獨不負嘉辰。", "裹黍金膏凍，糜蒲玉屑勻。", "未能全免俗，杯酒饗家人。"]'),
('c81a79af-5cdc-4092-a3d9-5fb990bc1134','端午家集  其二','曾丰','宋','宋诗','song-poetry','','[]','戲纏朱綵索，爭带赤靈符。',48,'全唐诗/poet.song.163000.json','["戲纏朱綵索，爭带赤靈符。", "踏草仍懸艾，包菰更結蘆。", "都還癡子弟，半出騃僮奴。", "老病無他好，惟餐朮與蒲。"]'),
('b434a807-810d-4082-b0cb-bf202ef64325','暑夜露坐','曾丰','宋','宋诗','song-poetry','','[]','出坐日初曛，歸眠夜欲分。',48,'全唐诗/poet.song.163000.json','["出坐日初曛，歸眠夜欲分。", "竹濃猶漏月，風橫不容雲。", "霧露氣相薄，星辰天自文。", "更深羣動息，地籟可相聞。"]'),
('67dc512f-3700-4c8b-9908-2192500016c2','謝邱行之','曾丰','宋','宋诗','song-poetry','','[]','剝啄屨聲寒，夫誰闖我關。',48,'全唐诗/poet.song.163000.json','["剝啄屨聲寒，夫誰闖我關。", "芝開眉宇紫，豹露管中斑。", "客有志鑽孔，得無人儔顔。", "倘餘化砂法，其敢爲君慳。"]'),
('5eff3e8d-aa6c-4b12-b66a-336288e6b899','遊烏石寺','曾丰','宋','宋诗','song-poetry','','[]','縹緲崖懸屋，崢嶸柍亙天。',48,'全唐诗/poet.song.163000.json','["縹緲崖懸屋，崢嶸柍亙天。", "我疑家玉帝，誰道宅金仙。", "鐘鼓風雷上，星辰燈火前。", "眼高胸次大，沙界眇三千。"]'),
('8e2f746b-3e58-4c15-a951-ac12cf8d5873','秋途暮息','曾丰','宋','宋诗','song-poetry','','[]','密密初秋雨，蒙蒙欲暮天。',48,'全唐诗/poet.song.163000.json','["密密初秋雨，蒙蒙欲暮天。", "牛羊爭欲下，車馬敢求前。", "蟋蟀挑孤詠，梧桐攪獨眠。", "及身無一事，夢到汗漫邊。"]'),
('0e0db128-6793-4648-b724-d9d629aab2df','題曾見卓時思亭','曾丰','宋','宋诗','song-poetry','','[]','自幸知韋布，相期到廟堂。',48,'全唐诗/poet.song.163000.json','["自幸知韋布，相期到廟堂。", "一朝天奪鑒，千古地埋光。", "春雨松凝鬰，秋風草萎黄。", "德公三酹罷，頃刻九回腸。"]'),
('73af666b-5b6a-4619-b82a-47dcd5ae0f47','龍母廟','曾丰','宋','宋诗','song-poetry','','[]','母乘乾變化，兒主震神通。',48,'全唐诗/poet.song.163000.json','["母乘乾變化，兒主震神通。", "江海藩籬外，風雷掌握中。", "水居依罔極，血食至無終。", "爲在扶桑國，曾收夾日功。"]'),
('725c76d0-0167-4d83-b9be-ce91e0ed9f4c','曲江值歐陽伯起舟行至封川  其一','曾丰','宋','宋诗','song-poetry','','[]','清望醉翁族，俊聲童子科。',48,'全唐诗/poet.song.163000.json','["清望醉翁族，俊聲童子科。", "三千新奏牘，百二舊山河。", "孰是披沙者，其如抱璞何。", "世終無棄劍，越砥可重磨。"]'),
('ba38b785-0352-487b-89ab-9a5953d45f7c','曲江值歐陽伯起舟行至封川  其二','曾丰','宋','宋诗','song-poetry','','[]','華髮吾衰矣，妙齡君浩然。',48,'全唐诗/poet.song.163000.json','["華髮吾衰矣，妙齡君浩然。", "追隨多計日，笑語兩忘年。", "功業無它遜，文章收自專。", "浯溪崖石上，準擬效拳拳。"]'),
('a85680ed-c8e2-484a-8dcc-600d777fa68c','英連江口三廟','曾丰','宋','宋诗','song-poetry','','[]','何處丈夫兒，不知名姓誰。',48,'全唐诗/poet.song.163000.json','["何處丈夫兒，不知名姓誰。", "弟兄三異相，上下兩靈祠。", "江海爲疆域，風雷聽指麾。", "與人作方便，慷慨似生時。"]'),
('873b7bcf-c589-49a6-8a85-9d61f6c98aa9','題南康呂丞哦松軒','曾丰','宋','宋诗','song-poetry','','[]','位嫌旁見逼，權忌暗相侵。',48,'全唐诗/poet.song.163000.json','["位嫌旁見逼，權忌暗相侵。", "李下無留跡，松間可寄音。", "不平風弔古，無頼雨傷今。", "盡數歸君律，隨機寫此心。"]'),
('f4cbc994-d616-44ba-9172-8167c4e789be','陸川尉吳子實死于李接之難','曾丰','宋','宋诗','song-poetry','','[]','螻蟻僕臣命，乾坤君父恩。',48,'全唐诗/poet.song.163000.json','["螻蟻僕臣命，乾坤君父恩。", "難于忘所本，可以喪其元。", "生素幾何字，殺青如許言。", "彼雖速亡我，我故自存存。"]'),
('c5d65a73-f020-44a2-97ea-f3b14ac17fa7','元日海南試筆','曾丰','宋','宋诗','song-poetry','','[]','南荒春較早，上朔日常暄。',48,'全唐诗/poet.song.163000.json','["南荒春較早，上朔日常暄。", "陡地風聲惡，連天海氣昏。", "夭桃與其媚，旨酒即之溫。", "摸索吾胸次，熙熙自一元。"]'),
('126d6647-d5ed-4ae9-8d60-a3943b3ba095','渡海後自北流縣過鬼門關','曾丰','宋','宋诗','song-poetry','','[]','抽身龍伯國，著脚鬼門關。',48,'全唐诗/poet.song.163000.json','["抽身龍伯國，著脚鬼門關。", "每每經從處，皇皇嶮阻閒。", "不支生所忽，有立出于艱。", "順境成人少，天初不是慳。"]'),
('0196cdc3-1e01-4a14-ac12-89471a0832d4','自懷澤至武仙道之左皆石峰','曾丰','宋','宋诗','song-poetry','','[]','蟬聯三百里，特立二千峯。',48,'全唐诗/poet.song.163000.json','["蟬聯三百里，特立二千峯。", "或者銳于笋，時乎圓似鐘。", "天開瓊帑藏，地闢玉疆封。", "似慮詩材少，慇懃分外供。"]'),
('e981575d-b3ce-49c9-be5e-0704476b8f50','辛酉中秋前後舟行自英入韶晚與全真姪傳杯','曾丰','宋','宋诗','song-poetry','','[]','山色秋分後，月華霜降前。',48,'全唐诗/poet.song.163000.json','["山色秋分後，月華霜降前。", "况方行水國，而復遇晴天。", "萬象入搔首，百懷歸扣舷。", "傳觴非至禮，聊爾勝徒然。"]'),
('a1d93c5a-32a8-48e9-84ea-e524969e158c','嘉泰改元季夏中澣經從武仙尉仙袁君攝縣事載酒相勞苦敬賦小詩呈似  其一','曾丰','宋','宋诗','song-poetry','','[]','道出武仙縣，因依識尉仙。',48,'全唐诗/poet.song.163000.json','["道出武仙縣，因依識尉仙。", "貌相交以禮，心自許其賢。", "學問追前輩，功名付晚年。", "漢庭偏用老，歸路在凌烟。"]'),
('e8178b78-e1cd-4d7b-b16c-319213e7f656','嘉泰改元季夏中澣經從武仙尉仙袁君攝縣事載酒相勞苦敬賦小詩呈似  其二','曾丰','宋','宋诗','song-poetry','','[]','言別富沙士，回頭五六年。',48,'全唐诗/poet.song.163000.json','["言別富沙士，回頭五六年。", "試詢今健否，見謂尚依然。", "效意傾新釀，忘懷誦近篇。", "尚其頻記憶，曾此一留連。"]'),
('72564345-806c-485c-aa33-ea5c6ca568ed','久與廣西帥年丈左史張舍人別自瓊罷歸過靜江相見  其一','曾丰','宋','宋诗','song-poetry','','[]','離年稠似髮，契義重于山。',48,'全唐诗/poet.song.163000.json','["離年稠似髮，契義重于山。", "不計命窮達，猶移書往還。", "匽藩新位貌，聞燕舊辭顔。", "勘破詩文處，吾其得訂頑。"]'),
('d8011693-adbd-44e3-b4a0-2325454103c0','久與廣西帥年丈左史張舍人別自瓊罷歸過靜江相見  其二','曾丰','宋','宋诗','song-poetry','','[]','直鈎追古道，方鑿背時風。',48,'全唐诗/poet.song.163000.json','["直鈎追古道，方鑿背時風。", "得不坐三黜，曾何銜五窮。", "物情難復獲，天理窒斯通。", "李絳鶚書裏，能無孟李同。"]'),
('d824a9b5-2bce-471c-8c68-53f8b404e241','落葉自幸','曾丰','宋','宋诗','song-poetry','','[]','恬受煦之賜，怪爲寒所干。',48,'全唐诗/poet.song.163000.json','["恬受煦之賜，怪爲寒所干。", "摇空危自落，卷地亂相翻。", "醉雨纔狼戾，驕風又虎賁。", "顧何嫌逐末，曾不礙歸根。"]'),
('17dbffe6-5950-4dc0-a742-2f4adb1b31c2','飛蓬自解','曾丰','宋','宋诗','song-poetry','','[]','有底重安土，若爲輕徇流。',48,'全唐诗/poet.song.163000.json','["有底重安土，若爲輕徇流。", "羞隨草木腐，樂與汗漫遊。", "凡是性如水，固然生若浮。", "勿嗤吾潦倒，天地海之漚。"]'),
('242b081f-c60b-41d4-a600-0a206dea0b70','贈三命家彭景升','曾丰','宋','宋诗','song-poetry','','[]','逆推多中者，與論頗奇之。',48,'全唐诗/poet.song.163000.json','["逆推多中者，與論頗奇之。", "我怪所謀左，君言其數奇。", "已回槐國夢，寧復帝鄉期。", "切勿多相許，雖多奚以爲。"]'),
('98bbab23-9b59-4f44-8e8d-516ae4f55299','四月十二日至廟山僦市樓挈行李','曾丰','宋','宋诗','song-poetry','','[]','有客難逃熱，無臺可納凉。',48,'全唐诗/poet.song.163000.json','["有客難逃熱，無臺可納凉。", "市中投漢邸，樓上置胡床。", "梅潤雨謀始，槐清風議將。", "北窗高卧處，何適不羲黄。"]'),
('c363865e-8e30-4e88-bf68-cabbc55ad51d','梅月客廟山厭潤思霽','曾丰','宋','宋诗','song-poetry','','[]','雲漫山若沒，海漲地如沉。',48,'全唐诗/poet.song.163000.json','["雲漫山若沒，海漲地如沉。", "人已苦卑濕，天猶容衆陰。", "非關河伯濫，自是雨師淫。", "上有太陽在，何當一照臨。"]'),
('fd55dd88-c710-47bc-a217-5814a3efc12e','余倅瓊鄭宰仁和俱以不爲言者所容去官控訴次相慰釋','曾丰','宋','宋诗','song-poetry','','[]','蘇子似韓公，斗牛身命宮。',48,'全唐诗/poet.song.163000.json','["蘇子似韓公，斗牛身命宮。", "釀成三黜累，贏得四愁工。", "自分寧瀕死，相期勿濫窮。", "安知天定處，不少假其衷。"]'),
('080ee8f1-98cc-4b90-b658-07c8a27f3e52','黄侍郎元章題處士何熙績所居曰肥遯熙績又結生墓而銘之予題其墓曰大歸遺之詩焉','曾丰','宋','宋诗','song-poetry','','[]','圭蓽逸民宅，羊鶉處士衣。',48,'全唐诗/poet.song.163000.json','["圭蓽逸民宅，羊鶉處士衣。", "人才于古有，天命與時違。", "初不厭肥遯，終何辭大歸。", "初終兩題目，君自一其機。"]'),
('356d9bc8-23f7-48ec-8cd5-408f7f0f71d4','簡寄鄭將使','曾丰','宋','宋诗','song-poetry','','[]','經史舊家風，薰陶磊塊胸。',48,'全唐诗/poet.song.163000.json','["經史舊家風，薰陶磊塊胸。", "書堪干乙夜，學未輟三冬。", "豹畧得無用，虎頭能不封。", "漢勳留我頌，相許細形容。"]'),
('49dce2d2-eaef-462a-8786-1aa65909ab08','贈璣上人','曾丰','宋','宋诗','song-poetry','','[]','幼拋南聚落，晚據北叢林。',48,'全唐诗/poet.song.163000.json','["幼拋南聚落，晚據北叢林。", "道貌枯中澤，禪機淺處深。", "山腰雲出沒，水面月浮沉。", "賈島勘還破，牢籠付一吟。"]'),
('2ae736bd-f8d8-458c-b770-07af386148d8','送曹伯高  其一','曾丰','宋','宋诗','song-poetry','','[]','絳帳橫經後，青燈曲几前。',48,'全唐诗/poet.song.163000.json','["絳帳橫經後，青燈曲几前。", "酒杯閒留坐，茶椀幾忘眠。", "虛受口三益，平反詩十愆。", "未闌賓主意，相約更明年。"]'),
('51ca3bb7-9f17-4ef5-bf6c-ac27117b1bd7','送曹伯高  其二','曾丰','宋','宋诗','song-poetry','','[]','筆研爲謀左，風霜與歲瀕。',48,'全唐诗/poet.song.163000.json','["筆研爲謀左，風霜與歲瀕。", "犬呿如不夜，雞噤似無晨。", "杖屨喚行客，衣冠辭主人。", "願言偏强飯，涵養竇庭椿。"]'),
('d9ea3c69-1435-4f53-bd62-8698dbc6ab37','別林和卿  其一','曾丰','宋','宋诗','song-poetry','','[]','夜榻無高枕，秋燈有短檠。',48,'全唐诗/poet.song.163000.json','["夜榻無高枕，秋燈有短檠。", "嗜書如女色，敲賦若金聲。", "豈是長貪者，何其太瘦生。", "功名猶欠子，子不欠功名。"]'),
('5bd26300-5904-42d8-9beb-cf0bf5a92078','別林和卿  其二','曾丰','宋','宋诗','song-poetry','','[]','甚矣身如幻，加之跡若浮。',48,'全唐诗/poet.song.163000.json','["甚矣身如幻，加之跡若浮。", "妙山孤倜儻，良友貳遨遊。", "水挾月涵夜，風推雨鬰秋。", "物來吾不拒，隨件以詩收。"]'),
('d59a032f-dd24-4125-a6d8-99132d02f597','贈游子信  其一','曾丰','宋','宋诗','song-poetry','','[]','可言詩已矣，多學識之與。',48,'全唐诗/poet.song.163000.json','["可言詩已矣，多學識之與。", "牛尾繄經始，羊腸殆緒餘。", "江山開闢後，情性渾成初。", "機械相融處，真成可起予。"]'),
('8b41b1b9-3ea0-4021-968f-db4275e72f65','贈游子信  其二','曾丰','宋','宋诗','song-poetry','','[]','孰是文之用，茲其道所藏。',48,'全唐诗/poet.song.163000.json','["孰是文之用，茲其道所藏。", "典謨書渾渾，晁董策洋洋。", "唐宋建長策，韓歐蹈大方。", "過庭詩禮次，歸更議其將。"]'),
('cc7e4fe6-908d-46bf-835c-aa5aa99e29c2','乙丑十一月十一日决獄次日迎帥舟中賦二詩首呈吳司理  其一','曾丰','宋','宋诗','song-poetry','','[]','滯舟推若泥，逆水去如還。',48,'全唐诗/poet.song.163000.json','["滯舟推若泥，逆水去如還。", "已歷三辰次，纔行十里間。", "千斯吾命薄，獨爾破天慳。", "所頼聖賢事，其初不厭艱。"]'),
('fafda109-346e-487e-89a8-b657e07c8941','乙丑十一月十一日决獄次日迎帥舟中賦二詩首呈吳司理  其二','曾丰','宋','宋诗','song-poetry','','[]','年老未歸老，旬休那得休。',48,'全唐诗/poet.song.163000.json','["年老未歸老，旬休那得休。", "將迎金屋客，方便石門遊。", "白浪海之怒，玄雲天也愁。", "詩情不關性，正爾自夷猶。"]'),
('ca1c8678-e577-4104-8548-c247178202f0','復用前韻呈黄教授  其一','曾丰','宋','宋诗','song-poetry','','[]','程子軻而下，韓公漢以還。',48,'全唐诗/poet.song.163000.json','["程子軻而下，韓公漢以還。", "彼非孤所上，人莫奪其間。", "死後虛名滿，生前實效慳。", "始吾謀向背，其决不勝艱。"]'),
('d519ba48-2722-4c32-a208-fcd573a3bd54','復用前韻呈黄教授  其二','曾丰','宋','宋诗','song-poetry','','[]','有底杜陵語，不驚人不休。',48,'全唐诗/poet.song.163000.json','["有底杜陵語，不驚人不休。", "筆端非外鑠，胸次有天遊。", "自發人三嘆，而銷我四愁。", "忘其舒若疾，何適不猶猶。"]'),
('4fab6273-5977-4c81-a6ec-c1b7f7b0607f','韓尚書南澗公之從弟德文爲東廣常平上幕丙寅八月上旬護印迎新使長李監丞先五日會客于翼然亭余與焉賦三詩  其一','曾丰','宋','宋诗','song-poetry','','[]','西清人表表，南澗跡陳陳。',48,'全唐诗/poet.song.163000.json','["西清人表表，南澗跡陳陳。", "麟筆可無託，鴈行猶有人。", "姓名知子舊，聞見與吾新。", "自分寧攻苦，相期勿抗塵。"]'),
('aecec1aa-2033-41c2-a504-90fa458917b6','韓尚書南澗公之從弟德文爲東廣常平上幕丙寅八月上旬護印迎新使長李監丞先五日會客于翼然亭余與焉賦三詩  其二','曾丰','宋','宋诗','song-poetry','','[]','白露一旬後，秋分三日前。',48,'全唐诗/poet.song.163000.json','["白露一旬後，秋分三日前。", "幕中餘暇日，城上肆華筵。", "卓立參天木，橫陳撲地烟。", "主人非獨答，客筆不如椽。"]'),
('c4601f63-317b-437d-903e-2b49d788e5e7','韓尚書南澗公之從弟德文爲東廣常平上幕丙寅八月上旬護印迎新使長李監丞先五日會客于翼然亭余與焉賦三詩  其三','曾丰','宋','宋诗','song-poetry','','[]','山鄉仍水國，玉露更金風。',48,'全唐诗/poet.song.163000.json','["山鄉仍水國，玉露更金風。", "置印龜䶲上，揚鞭馬首東。", "勤渠蓮幕客，款曲綉衣翁。", "言我坐詩累，至今依舊窮。"]'),
('a3ae8656-c1af-4491-9609-3bfdef2e2995','公餘野立','曾丰','宋','宋诗','song-poetry','','[]','文書聊却掃，耳目且恢張。',48,'全唐诗/poet.song.163000.json','["文書聊却掃，耳目且恢張。", "海大水歸往，山深雲退藏。", "春雷溫也厲，晦月闇而章。", "萬象相關處，悠然興味長。"]'),
('e1cf7409-80ca-4535-bd1e-984c0909db86','贈顧君美','曾丰','宋','宋诗','song-poetry','','[]','三命孰如李，五星誰似袁。',48,'全唐诗/poet.song.163000.json','["三命孰如李，五星誰似袁。", "目前談者衆，足下悟其玄。", "歸養老和病，看耕田與園。", "他無可推步，君往扣侯門。"]'),
('db7c8723-7061-43e5-9c77-0c452e8e3861','挽孺人雷氏','曾丰','宋','宋诗','song-poetry','','[]','箕帚當人室，繅紉起我家。',48,'全唐诗/poet.song.163000.json','["箕帚當人室，繅紉起我家。", "所羞轑釜爾，其憚下機邪。", "剪髻戶盈屨，斷絲書滿車。", "天何奪之速，不待服褕霞。"]'),
('261d5301-7bf7-4f14-a212-f1f626791da0','挽廬陵葛孝子母夫人','曾丰','宋','宋诗','song-poetry','','[]','笄珥初歸室，繅紉共起家。',48,'全唐诗/poet.song.163000.json','["笄珥初歸室，繅紉共起家。", "清風依玉樹，和氣茁蘭芽。", "送子歸黄壤，收名入白華。", "大書彤史上，誰謂過于夸。"]'),
('0242289b-2779-4503-9ff8-086687b399b1','挽王誠夫母夫人','曾丰','宋','宋诗','song-poetry','','[]','雍雍瑟配琴，詩禮五青衿。',48,'全唐诗/poet.song.163000.json','["雍雍瑟配琴，詩禮五青衿。", "四舉一門事，三遷平日心。", "桂枝方日長，萱草已春深。", "咫尺青山裏，蕭然隔古今。"]'),
('ef18d443-1de5-45ba-8f57-a598ede70b24','挽宜人李氏  其一','曾丰','宋','宋诗','song-poetry','','[]','養成中饋德，留與後人言。',48,'全唐诗/poet.song.163000.json','["養成中饋德，留與後人言。", "翰墨其餘事，詩書蓋上根。", "不徒爲大母，猶復見曾孫。", "蕭瑟堂前意，青葱雨後萱。"]'),
('12392eac-9374-44a6-8cd9-70778411add4','挽宜人李氏  其二','曾丰','宋','宋诗','song-poetry','','[]','僧戒阿誰受，法儀何處迎。',48,'全唐诗/poet.song.163000.json','["僧戒阿誰受，法儀何處迎。", "兩回經夢境，三歎悟人生。", "食已難爲强，衣猶不憚更。", "得非禪力重，去住自由情。"]'),
('03ed46fc-e894-45b5-a9f7-aed2c3719986','挽上官茂叔','曾丰','宋','宋诗','song-poetry','','[]','讀書初有激，知命復何營。',48,'全唐诗/poet.song.163000.json','["讀書初有激，知命復何營。", "熊掌酒中趣，鴻毛身後名。", "山川揫寶氣，學校戛金聲。", "老驥隨駒逝，若爲泉下情。"]'),
('d91b42b3-bfb6-4d6d-aa84-c46360fc689f','有悼','曾丰','宋','宋诗','song-poetry','','[]','苧麻功敏裕，蘋藻意精忱。',48,'全唐诗/poet.song.163000.json','["苧麻功敏裕，蘋藻意精忱。", "和氣分珠樹，悲聲寄藁砧。", "一天無後望，三紀有初心。", "后土相知處，千秋墓草深。"]'),
('96eb4446-1b91-4543-8e3b-41548acbfa77','挽張郴州  其一','曾丰','宋','宋诗','song-poetry','','[]','輕甘相潤澤，清苦自磨磋。',48,'全唐诗/poet.song.163000.json','["輕甘相潤澤，清苦自磨磋。", "數矣充周賦，優哉中漢科。", "上分之左竹，公付以南柯。", "天不憗遺意，其如人望何。"]'),
('59ba2e86-9418-4b16-8578-893cdc202a8a','挽張郴州  其二','曾丰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','四海鄭元樞，三朝范石湖。',48,'全唐诗/poet.song.163000.json','["四海鄭元樞，三朝范石湖。", "利光騰鶚表，自足濟鵬圖。", "芝檢豈欺我，朱轓何負余。", "幸而廉吏傳，名與泰山俱。"]'),
('f423585d-9adc-4a3c-9a69-478ed70e1fe6','挽張郴州  其三','曾丰','宋','宋诗','song-poetry','','[]','永平稱善狀，長樂沸廉聲。',48,'全唐诗/poet.song.163000.json','["永平稱善狀，長樂沸廉聲。", "孝史行于世，尚書薦以名。", "匪朝金馬去，有頃玉樓成。", "不是文星墜，文星復太清。"]'),
('ddc8d2bf-b7d7-4674-8bfe-e152d2e79b40','挽張郴州  其四','曾丰','宋','宋诗','song-poetry','','[]','鴻漸南中掾，鶑喬西外丞。',48,'全唐诗/poet.song.163000.json','["鴻漸南中掾，鶑喬西外丞。", "華途于此奮，厄算廼吾乘。", "妙學家傳鉢，殊科世續燈。", "茲其有以死，名死實何曾。"]'),
('df15d4dd-f9f7-463c-a32d-bb8e469b3606','挽饒伯餘室氏曾夫人  其一','曾丰','宋','宋诗','song-poetry','','[]','歸相起家翁，繅紉奮婦庸。',48,'全唐诗/poet.song.163000.json','["歸相起家翁，繅紉奮婦庸。", "初心光四教，末願滿三從。", "已已谿毛薦，行行馬鬣封。", "斷機遲後效，黄紙賁青松。"]'),
('a72f81da-6f60-4887-9a85-a82fc12d57ab','挽饒伯餘室氏曾夫人  其二','曾丰','宋','宋诗','song-poetry','','[]','始託得其地，中傷乖所天。',48,'全唐诗/poet.song.163000.json','["始託得其地，中傷乖所天。", "心猶持七戒，教不廢三遷。", "大本中孚卦，繁文內則篇。", "區區彤史筆，未足遠其傳。"]'),
('065ef18f-0fc7-4792-bbb0-7fa1a9ca81c4','賦梅  其一','曾丰','宋','宋诗','song-poetry','','[]','萬物叢中要獨行，榮枯不愛與時爭。',64,'全唐诗/poet.song.163000.json','["萬物叢中要獨行，榮枯不愛與時爭。", "翛翛水性雲情重，栩栩仙風道骨輕。", "飯顆一時工部瘦，首陽千古伯夷清。", "未言鼎鼐功猶在，雖竟無功也有名。"]'),
('ad7620ed-1d28-49cd-a1b0-85194065eb57','賦梅  其二','曾丰','宋','宋诗','song-poetry','','[]','作意偷春破隊行，橫翔捷出不容爭。',64,'全唐诗/poet.song.163000.json','["作意偷春破隊行，橫翔捷出不容爭。", "窗前納月神光白，水上乘風縠漏輕。", "違物行歸廉士潔，傲時身中聖人清。", "賞音不遇林和靖，也是花經第一名。"]'),
('c55d7414-8190-4233-9095-e4c225d8c19a','賦梅  其三','曾丰','宋','宋诗','song-poetry','','[]','素妃勇作探春行，紅紫躊躇不及爭。',64,'全唐诗/poet.song.163000.json','["素妃勇作探春行，紅紫躊躇不及爭。", "萬物莫移天性淡，一毫無累世緣輕。", "雪霜得伴成三白，松竹爲羣免獨清。", "中壓羣芳外相混，有名常處以無名。"]'),
('d67bb78f-b4dd-4771-a7e4-c557326d5c2c','晨霜客路','曾丰','宋','宋诗','song-poetry','','[]','卧駭窗紗已報明，籃輿札札破霜行。',64,'全唐诗/poet.song.163000.json','["卧駭窗紗已報明，籃輿札札破霜行。", "踏開凍淖瓊漿溜，摇動凝梢玉屑傾。", "山色喜人猶念舊，鳥聲冤客不留情。", "從今得檄莫嫌出，後集詩猶編未成。"]'),
('bcb333f7-b987-4c81-af8a-ad66d3de3054','題盤古山  其一','曾丰','宋','宋诗','song-poetry','','[]','太初盤古造乾坤，鬼力神筋擘混元。',64,'全唐诗/poet.song.163000.json','["太初盤古造乾坤，鬼力神筋擘混元。", "妙果雖圓心不有，凡身已蛻跡獨存。", "女媧石带補天色，波利巖餘飛錫痕。", "想與南安白衣老，三生元是一精魂。"]'),
('0b20aff4-bb27-473a-aab4-6354e92f00b8','題盤古山  其二','曾丰','宋','宋诗','song-poetry','','[]','清風撲袂冷颼颼，吹到盤山最上頭。',64,'全唐诗/poet.song.163000.json','["清風撲袂冷颼颼，吹到盤山最上頭。", "石室少開嫌俗看，蓮花時落任僧收。", "銅人閲世幾寒暑，木客嘲風誰唱酬。", "故老相傳半疑信，粥盂茶碗慰吾遊。"]'),
('a1ac0c18-5ed6-48c3-81b9-51ad3c72d4ce','會昌勸農','曾丰','宋','宋诗','song-poetry','','[]','官不勸農農亦耕，詔書那可廢常行。',64,'全唐诗/poet.song.163000.json','["官不勸農農亦耕，詔書那可廢常行。", "烟霞自避旌旗色，魚鳥相疑金鼓聲。", "蝶急豈遑追夢覺，鳩閑猶强管陰晴。", "忙中偷得須臾暇，聊借江山答太平。"]'),
('03ce51f1-704e-4d6f-828b-218fe75174ee','隆興貢院彭國壽以詩見示次韻奉酬','曾丰','宋','宋诗','song-poetry','','[]','共閲文場幸小休，燕齋還我舊天遊。',64,'全唐诗/poet.song.163000.json','["共閲文場幸小休，燕齋還我舊天遊。", "青燈影裏消除夜，黄菊杯中漸送秋。", "此念在家身在客，吾行非去坐非留。", "諸公往往離懷惡，曾悟乘流過坎不。"]'),
('fe5bd0cc-95a2-4955-aa1f-38e30468de67','簡隠居陳公儔伯英','曾丰','宋','宋诗','song-poetry','','[]','士人臭味自薰蘭，一度相逢一破顔。',64,'全唐诗/poet.song.163000.json','["士人臭味自薰蘭，一度相逢一破顔。", "隨牒抗塵吾著急，弄花踏月子偷閑。", "熟眠無夢到槐國，佯醉有人扶玉山。", "李杜吟魂已長往，興來時以筆追還。"]'),
('7c0ef702-d9c3-4f54-ada9-70d9778607e8','會昌小峴亭有碑侍郎陸公作也今通守蓋公之孫迺發家傳爲南齋宴坐之計敬酬見教','曾丰','宋','宋诗','song-poetry','','[]','小峴豐碑大陸書，摩挲蠆尾掃龜趺。',64,'全唐诗/poet.song.163000.json','["小峴豐碑大陸書，摩挲蠆尾掃龜趺。", "機雲宗派公家是，晉宋文章此外無。", "方被春牽時夢草，豈爲秋動輒思鱸。", "行藏俱不達情性，在在江山聽指呼。"]'),
('cc39f107-a851-4808-9cab-095e66cb14b0','上魏太守壽','曾丰','宋','宋诗','song-poetry','','[]','臘雪紛紛天散花，餘清不但茁梅芽。',64,'全唐诗/poet.song.163000.json','["臘雪紛紛天散花，餘清不但茁梅芽。", "更添西漢賢良種，聊振中興宰相家。", "雙手幸猶堪活國，百年元不在餐霞。", "壽隨名勒南山石，石可磨礱壽莫涯。"]'),
('f6721c38-38ba-4b97-baa7-fe65d8cabba4','登滕王閣','曾丰','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','落霞未厭我來頻，一度來觀一度新。',64,'全唐诗/poet.song.163000.json','["落霞未厭我來頻，一度來觀一度新。", "出沒無時鷗弄暖，飛鳴不禁鵲思春。", "物華幾換江如故，沙界常空世自塵。", "料得西山仙隠輩，且憐且笑倚欄人。"]'),
('66f976cb-521f-4cbf-9b78-41dbdeb502fc','江路見梅懷泉臺留主管王提幹','曾丰','宋','宋诗','song-poetry','','[]','强號梅爲自在春，淡粧貴不失天真。',64,'全唐诗/poet.song.163000.json','["强號梅爲自在春，淡粧貴不失天真。", "園林爛熳空多事，籬落伶俜倒出塵。", "無竹無松自風韻，得江得月更精神。", "清高惟雪可相配，次有冰臺兩玉人。"]'),
('c4fafc31-f081-4189-8173-e7db149c2d70','甲辰冬辭塚赴官寄曾鼎臣','曾丰','宋','宋诗','song-poetry','','[]','過家來上塚頭山，禽鳥歡呼勞我還。',64,'全唐诗/poet.song.163000.json','["過家來上塚頭山，禽鳥歡呼勞我還。", "石礙猶前溪水勇，風吹不動嶺雲頑。", "菅茆尚向燒邊翠，鬚鬢偏從鑷處斑。", "吾坐奔馳累如許，此詩不分魯齋閑。"]'),
('cd4a55fe-5b40-4ce1-89e0-48cc153d8f80','買舟赴廣至太和逢迓吏','曾丰','宋','宋诗','song-poetry','','[]','只被饑寒兩字催，輒輕洶湧易崔嵬。',64,'全唐诗/poet.song.163000.json','["只被饑寒兩字催，輒輕洶湧易崔嵬。", "篙師方借北風去，驛使忽將南信來。", "鍾鼎孰非相邂逅，江山何惜且徘徊。", "松風蘿月良收拾，猶勝垂囊將手回。"]'),
('bea3e01a-f3a5-4e77-b3ba-f3350950c31e','入廣至贛雪霽天朗聊舒耳目','曾丰','宋','宋诗','song-poetry','','[]','數自離家今幾程，半風半雨半陰晴。',64,'全唐诗/poet.song.163000.json','["數自離家今幾程，半風半雨半陰晴。", "白雲故作關愁色，烏鵲爭爲報喜聲。", "來耗得梅偷傳送，去途惟柳管將迎。", "囊中少带江西雪，見說五羊烟瘴輕。"]'),
('ab366049-3589-4bc9-a893-b381c188a4bd','赴廣過贛呈留主管王提幹','曾丰','宋','宋诗','song-poetry','','[]','世味不分甘與苦，吾年未老已先嘗。',64,'全唐诗/poet.song.163000.json','["世味不分甘與苦，吾年未老已先嘗。", "爐邊醉後暖生睡，雪裏饑餘寒欲僵。", "出處任緣常夢好，陸沉隨分自心凉。", "經過少敘江山舊，魚鳥多情尚未忘。"]'),
('b725546f-6099-4b1c-8c47-0c0f62b7a2e5','南康黎蔡昆仲四君子隆興乾道間與余爲廬陵郡庠同舍淳熙乙巳之元日余赴廣東漕屬道出南康敬賦一詩書兩通分遺之','曾丰','宋','宋诗','song-poetry','','[]','轉徙廬陵邂逅間，青燈相照稔相看。',64,'全唐诗/poet.song.163000.json','["轉徙廬陵邂逅間，青燈相照稔相看。", "那知文社春隨冷，未放交盟血便寒。", "腰强豈猶便歛板，手閒何不試彈冠。", "山巖倘久奇文塞，我辦工夫續子殘。"]'),
('51734e7f-4436-45fc-b51a-15264841c22e','爲廣東解嘲','曾丰','宋','宋诗','song-poetry','','[]','曲江而下水多石，大庾以南山半茅。',64,'全唐诗/poet.song.163000.json','["曲江而下水多石，大庾以南山半茅。", "相國猶餘心裏印，祖師更剩杖頭包。", "依稀舜樂宜人聽，零落韓文任客抄。", "氣候太偏風土惡，今詩聊解古人嘲。"]'),
('7f8f43b9-5b43-4f50-b364-96e4b206c102','五羊中秋熱未艾','曾丰','宋','宋诗','song-poetry','','[]','火氣之餘金氣乘，嶺南寒暑獨無憑。',64,'全唐诗/poet.song.163000.json','["火氣之餘金氣乘，嶺南寒暑獨無憑。", "雖非滷地亦卑溫，不必梅天皆鬰蒸。", "椰子簟凉膚起粟，荔枝膏冷齒生冰。", "休言惡地欠霜雪，似爲貧家省絮繒。"]'),
('6b5f122c-f20b-45a9-aa0d-f4b07c369e65','南海祠東海中有小山可著屋','曾丰','宋','宋诗','song-poetry','','[]','海裏山巔著數椽，舂容仰止已翛然。',64,'全唐诗/poet.song.163000.json','["海裏山巔著數椽，舂容仰止已翛然。", "仙家自我有方丈，沙界從今無大干。", "萬物長春天不夜，清風莫逆月忘年。", "神遊不制夢回興，未了君臣父子緣。"]'),
('bee96e64-4387-4e5c-9851-1432bf498ac8','宿南海神祠東廊候月烹茶次聞雷','曾丰','宋','宋诗','song-poetry','','[]','祠宇眈眈海岸頭，况逢冷夜更清秋。',64,'全唐诗/poet.song.163000.json','["祠宇眈眈海岸頭，况逢冷夜更清秋。", "風前塵外笛三弄，飯後月中茶一甌。", "借我孤舟隨水住，乘時一棹與天浮。", "舊談八月流槎事，豈料予來傍女牛。"]'),
('06803fdf-cdbb-4e9d-8cf7-be04d3b0cbdd','戊戌與彭元忠相別于安城丙午皆爲東廣幕屬遂獲再集','曾丰','宋','宋诗','song-poetry','','[]','同郡同年五弟兄，兩人猶幸竊餘生。',64,'全唐诗/poet.song.163000.json','["同郡同年五弟兄，兩人猶幸竊餘生。", "要閑莫苦追名路，得健休冤落選坑。", "一別九年頭半白，三城重見眼增明。", "相從詩酒莫相舍，分散何時又合并。"]'),
('8ad6949f-0f33-40f2-8366-6f8f628ab6d3','登浴日堂','曾丰','宋','宋诗','song-poetry','','[]','五更起望大洋東，遠水摇蒼日湧紅。',64,'全唐诗/poet.song.163000.json','["五更起望大洋東，遠水摇蒼日湧紅。", "暘谷初開羣蟄起，咸池一洗萬塵空。", "頓令穢濁河沙界，都入光明寶藏中。", "事了不知功小大，列仙誰是狄梁公。"]'),
('5fcca422-a71e-4b76-b722-8bf2838afd94','四月二十七日登靈洲閣明日前迓新漕回首望閣賦長韻寄堂頭僧','曾丰','宋','宋诗','song-poetry','','[]','昨日我登山閣上，前村人落世塵中。',64,'全唐诗/poet.song.163000.json','["昨日我登山閣上，前村人落世塵中。", "今還望望尋村去，復覺區區與世同。", "眼界那分清與濁，心機已破礙爲通。", "撙齋寄語靈洲老，莫向空邊更說空。"]'),
('00b4a87c-a470-4f92-9fb9-281ffe623e50','昨與余遊如陳廣元張壽卿江伯紀陳通卿皆上計矣獨鄒用之鄧繼高困阨况今相去愈遠焉緬我懷因成兩詩各書一通寄之  其一','曾丰','宋','宋诗','song-poetry','','[]','枕中肘後爲渠空，效驗如何小不同。',64,'全唐诗/poet.song.163000.json','["枕中肘後爲渠空，效驗如何小不同。", "失馬安知非後福，獲麟未必不終窮。", "紀昌已費二年學，造父猶爭三日功。", "了却酸辛殘事業，從教運塞與時通。"]'),
('a2d344c0-11e7-4c94-a360-ae784c29f5e3','昨與余遊如陳廣元張壽卿江伯紀陳通卿皆上計矣獨鄒用之鄧繼高困阨况今相去愈遠焉緬我懷因成兩詩各書一通寄之  其二','曾丰','宋','宋诗','song-poetry','','[]','章貢三年兩到休，况今又落最南州。',64,'全唐诗/poet.song.163000.json','["章貢三年兩到休，况今又落最南州。", "思歸梅嶺不相夢，惜別葛溪猶漲愁。", "子爲坐窮知理道，吾從遭病憶交遊。", "明年肯爲槐花出，來看海瀕天盡頭。"]'),
('2b08cfff-91d7-4ae9-b899-29b85b94c8c8','同官醵呈林簽判','曾丰','宋','宋诗','song-poetry','','[]','廣南一路逢春早，幕下諸公醵飲遲。',64,'全唐诗/poet.song.163000.json','["廣南一路逢春早，幕下諸公醵飲遲。", "莊蝶舞風忙似我，杜鵑啼月怨歸誰。", "梅兄樊弟風流態，魏后姚王富貴姿。", "過去那容更追賞，且隨見在醉殘枝。"]'),
('ccd4e635-acd7-4c24-8b9e-bee967c52bef','遊春集未成再賦呈趙司法','曾丰','宋','宋诗','song-poetry','','[]','我來已作一年癡，敢問諸公幾許時。',64,'全唐诗/poet.song.163000.json','["我來已作一年癡，敢問諸公幾許時。", "客裏酒杯初到口，風前花片半辭枝。", "尚餘魏紫姚黄在，安用桃紅李白爲。", "公事相尋無了日，得閑莫更負春期。"]'),
('4d69dc91-10fb-4d03-af25-27d182180287','送春','曾丰','宋','宋诗','song-poetry','','[]','春來如柅去如流，遲速乘除不自由。',64,'全唐诗/poet.song.163000.json','["春來如柅去如流，遲速乘除不自由。", "人道朱明陰見迫，我疑紅紫老知收。", "蜂圍蝶繞爭依戀，燕語鶑啼强挽留。", "惟有杜鵑却相亮，聲聲勸道好歸休。"]'),
('965ad375-a0df-4516-900e-12d55d9a60a1','和陸倅聞雨之韻','曾丰','宋','宋诗','song-poetry','','[]','白晝雷驅風入城，豔陽天氣太陰生。',64,'全唐诗/poet.song.163000.json','["白晝雷驅風入城，豔陽天氣太陰生。", "方看雲墨濃翻汁，俄駭天河倒瀉聲。", "布穀殷勤休勸客，添丁長大即歸耕。", "落南少有知音者，且與候蟲相對鳴。"]'),
('5106cf92-58e8-4453-a7b1-2be8317863dc','再簡陸倅諸公屢速小醵未成','曾丰','宋','宋诗','song-poetry','','[]','嬉遊那欲食前言，俗事不容人出門。',64,'全唐诗/poet.song.163000.json','["嬉遊那欲食前言，俗事不容人出門。", "屋上風餘中夜響，津頭水過去年痕。", "梅無未熟青青子，竹有新生𧥄𧥄孫。", "白放春歸太空去，哢禽聲裏似啣冤。"]'),
('72604b52-ab9e-4609-bdec-aa8f3a6fb565','陸倅連和三篇見示敬酬其一','曾丰','宋','宋诗','song-poetry','','[]','信筆揮成五七言，敲門豈復作推門。',64,'全唐诗/poet.song.163000.json','["信筆揮成五七言，敲門豈復作推門。", "江河自有長流勢，斧鑿俱無未沒痕。", "雨带客愁橫白帝，風吹閨怨入烏孫。", "公于樂府有餘思，更爲楊妃賦所冤。"]'),
('621a1605-e36f-4c86-ac8d-bf4876fab051','丁未端月南倅率諸同幕遊景秦還至滴水巖南倅諸君賦兩詩爲倡隨例次韻  其一','曾丰','宋','宋诗','song-poetry','','[]','海邊城北最高峯，嶺外浮圖第一宮。',64,'全唐诗/poet.song.163000.json','["海邊城北最高峯，嶺外浮圖第一宮。", "落葉掃空春乍至，浮雲捲盡日方中。", "登高已幸容鄒湛，向暖那應笑郝隆。", "收拾物華壯歸色，囊中不是去年窮。"]'),
('de934ad3-a412-4133-ad05-a856a069b7f2','丁未端月南倅率諸同幕遊景秦還至滴水巖南倅諸君賦兩詩爲倡隨例次韻  其二','曾丰','宋','宋诗','song-poetry','','[]','拄到烟蘿最上頭，試詢達磨問浮丘。',64,'全唐诗/poet.song.163000.json','["拄到烟蘿最上頭，試詢達磨問浮丘。", "仙人安往佛安在，木葉自沉雲自浮。", "胸次不堪全汩沒，公餘無廢小嬉遊。", "杯盤各稱家豐儉，有即莫慳無莫求。"]'),
('e6ba4225-95e8-42fe-87eb-0bb721f109cf','落南二年無人相牽挽詩幾于廢羅子琳跫然至止喜而賦長韻','曾丰','宋','宋诗','song-poetry','','[]','冷落江西香火緣，嶺南人少問吾傳。',64,'全唐诗/poet.song.163000.json','["冷落江西香火緣，嶺南人少問吾傳。", "一行水陸餘千里，兩歲風花僅百篇。", "句眼竟誰知落處，古囊長是挂閑邊。", "獿人常試斲泥手，客裏相逢喜欲顛。"]'),
('04248d96-b532-496d-a7c3-b40a25f60ebd','余出疏語示陳伯英伯英勉予讀傳燈錄諸書因用羅子琳韻挑伯英要看一轉語','曾丰','宋','宋诗','song-poetry','','[]','學結蒲團禪板緣，黄梅衣鉢問誰傳。',64,'全唐诗/poet.song.163000.json','["學結蒲團禪板緣，黄梅衣鉢問誰傳。", "彌天北秀經三藏，曠劫南能偈一篇。", "夢幻固知無起滅，虛空安得有中邊。", "無人語此聞君至，急著衣裳倒且顛。"]'),
('97c2ac51-c4c9-47b3-bc1c-205b8ab0beaf','陳伯英侍郎子也廣帥辟入幕既至參差帥別思所以處未定間余載酒相過','曾丰','宋','宋诗','song-poetry','','[]','少陵入蜀倚嚴公，捧檄非無米可舂。',64,'全唐诗/poet.song.163000.json','["少陵入蜀倚嚴公，捧檄非無米可舂。", "懶教纖腰舞楊柳，來遊上幕看芙蓉。", "十連豈吝回青顧，千戶猶疑羨素封。", "忝是故人恨無力，一樽時復畧從容。"]'),
('5db4075d-309a-4d52-b24d-9f3b03ec773e','余以檄出陳機宜往西津候別余阻風不得前','曾丰','宋','宋诗','song-poetry','','[]','孺子未來圯水上，遠公已過虎溪頭。',64,'全唐诗/poet.song.163000.json','["孺子未來圯水上，遠公已過虎溪頭。", "佳人密邇不相見，弱水瀰漫那自由。", "非負酪奴辜玉友，莫誅風伯訟陽侯。", "明年訪戴留髠日，大白梨花爛熳酬。"]'),
('a07fd655-afbd-4098-8cfa-47aa0a0b30fe','至德慶崖下回想松江山','曾丰','宋','宋诗','song-poetry','','[]','江灣一轉一重山，自入江來幾轉灣。',64,'全唐诗/poet.song.163000.json','["江灣一轉一重山，自入江來幾轉灣。", "檄到如風心倥傯，船行似箭眼斕斑。", "三場題目那容緩，一切工夫未得閑。", "夾岸青峯可相約，黄花前後待吾還。"]'),
('1cc30661-c9aa-409c-be75-d83af61edfb1','增城丞嘉禾張元輔纔過郡輒去未及款曲已而同校藝晉康  其一','曾丰','宋','宋诗','song-poetry','','[]','易學淵源出義方，緒餘猶作漢文章。',64,'全唐诗/poet.song.163000.json','["易學淵源出義方，緒餘猶作漢文章。", "名高未急蓬萊島，心遠寧專雁鶩行。", "紙尾固無勳可策，松間殊有味難忘。", "諸公論薦休聞早，且候珠璣滿一囊。"]'),
('52ce0aef-2464-47c3-9933-ce179750dfd4','增城丞嘉禾張元輔纔過郡輒去未及款曲已而同校藝晉康  其二','曾丰','宋','宋诗','song-poetry','','[]','隨牒相逢瘴海邊，經從不爲小留連。',64,'全唐诗/poet.song.163000.json','["隨牒相逢瘴海邊，經從不爲小留連。", "藍田晝短子姑去，彭澤春濃我欲眠。", "近境曾無携具日，殊鄉却有對床緣。", "天知道大話長意，借我黄花節以前。"]'),
('2ae11757-8055-4686-b0c6-3a653650b455','梅  其一','曾丰','宋','宋诗','song-poetry','','[]','太清儲氣置南荒，非我閒生誰足當。',64,'全唐诗/poet.song.163000.json','["太清儲氣置南荒，非我閒生誰足當。", "瘦可以風饒道骨，白難爲月飽神光。", "寧教大庾有山色，莫管長安無國香。", "驛使借令不相外，孤芬未必合羣芳。"]'),
('52d21be7-f61e-4c20-832a-e3f493f2a506','梅  其二','曾丰','宋','宋诗','song-poetry','','[]','萬物無先我得春，誰言骨立相之屯。',64,'全唐诗/poet.song.163000.json','["萬物無先我得春，誰言骨立相之屯。", "御風栩栩臞仙骨，立雪亭亭苦佛身。", "不放喬松爲獨行，猶容修竹作同人。", "彼矜香色自孤者，不道未離香色塵。"]'),
('a48ef5f0-331b-42d2-89c0-4c3a16a271f3','梅  其三','曾丰','宋','宋诗','song-poetry','','[]','受命于天已背時，形模骨相歲寒姿。',64,'全唐诗/poet.song.163000.json','["受命于天已背時，形模骨相歲寒姿。", "馨香事業清風覺，枯淡生涯皓月知。", "簷下橫窗誰領畧，溪邊照水自娛嬉。", "嶺南驛使雖相愛，送入京華豈所宜。"]'),
('3c191359-e891-4722-acf4-ec37daca0685','簡寄幼能弟','曾丰','宋','宋诗','song-poetry','','[]','愧無毫髮補于公，老不相饒病見攻。',64,'全唐诗/poet.song.163000.json','["愧無毫髮補于公，老不相饒病見攻。", "夜雨燈窗清苦後，春風枕席黑甜中。", "頻餐粥飯長教健，僅活妻兒不管窮。", "飽計須秔醉須秫，爲吾蚤策買田功。"]'),
('25a3611e-8fe3-445f-ae72-a9ffc9b3dc60','呈張彥容','曾丰','宋','宋诗','song-poetry','','[]','風月性情狂莫羈，簿書今不放人嬉。',64,'全唐诗/poet.song.163000.json','["風月性情狂莫羈，簿書今不放人嬉。", "舊攻日課歸乾沒，新負時名入坐馳。", "白雪陽春挑我和，高山流水結誰知。", "髭髯能美非窮者，恐到窮時莫罪詩。"]'),
('7d4d01f7-f6c9-4c37-a815-39f7d4822e51','散步後園','曾丰','宋','宋诗','song-poetry','','[]','簿書不放出公門，飯罷舂容步後園。',64,'全唐诗/poet.song.163000.json','["簿書不放出公門，飯罷舂容步後園。", "燕子方歸猶認主，竹君未老已生孫。", "姚王泣雨淚含怨，望帝啼風聲带冤。", "新舊兩重公案在，一依詩律與平反。"]'),
('08a8c989-1b28-44e7-a7bf-8ee9e0ad48bd','北歸回首謝庾嶺','曾丰','宋','宋诗','song-poetry','','[]','五羊一住閲三冬，諳盡人情與土風。',64,'全唐诗/poet.song.163000.json','["五羊一住閲三冬，諳盡人情與土風。", "醫拙市空多藥物，肉平官又少庖工。", "大寒氣候初中伏，稚子顔容七十翁。", "天下豈無遊宦處，吾車不復指南中。"]'),
('cdd9e1d1-15ac-4daf-9dbc-f8dec6fb3b48','自廣歸至南康與蔡承之黎夏卿劉成叟相見','曾丰','宋','宋诗','song-poetry','','[]','轉蓬隨牒入番禺，中土交遊愈見疏。',64,'全唐诗/poet.song.163000.json','["轉蓬隨牒入番禺，中土交遊愈見疏。", "嶺隔不容南至雁，水分無復北來魚。", "往還一介動千里，終始三年纔兩書。", "所頼清風與明月，時將吾夢到君廬。"]'),
('35cca5fe-d47b-4183-8d8c-0c45b33291b8','北歸至廬陵過州學前記認舊遊嘆同舍之半不在也','曾丰','宋','宋诗','song-poetry','','[]','久落殊鄉今始回，學門未改舊崔嵬。',64,'全唐诗/poet.song.163000.json','["久落殊鄉今始回，學門未改舊崔嵬。", "交遊髭鬢綠成白，齋館簷楹朱上煤。", "同舍無多登仕路，連年已半入泉臺。", "閽人怪我面塵土，不道功名心亦灰。"]'),
('ef23bde6-f65e-4f47-a6e0-4e9331c5563c','解館歸至永豐繼善伯熊寶臣敦禮昆仲皆化去','曾丰','宋','宋诗','song-poetry','','[]','新自梅關返葛溪，天心不與我心違。',64,'全唐诗/poet.song.163000.json','["新自梅關返葛溪，天心不與我心違。", "市廛城郭依元在，親戚交遊過半非。", "紙上銜猶仍舊署，腰間带已減初圍。", "候門童稚倚廬老，幸不空教賦式微。"]'),
('5880591d-44e8-4652-bda6-222086be37c2','自廣至永豐呈熊直卿鄒用之鄧繼高','曾丰','宋','宋诗','song-poetry','','[]','斷梗歸從南海邊，絕長補短恰三年。',64,'全唐诗/poet.song.163000.json','["斷梗歸從南海邊，絕長補短恰三年。", "聲音幸未移蠻氣，鬚鬢疑猶带瘴烟。", "走俗抗塵吾老矣，吟風弄月子超然。", "鶴袍可著終須脫，鐵硯雖穿請更研。"]'),
('d3d41ef4-a551-47d6-8db1-8b350dc80c5d','招董彥文以下十二人小酌道舊','曾丰','宋','宋诗','song-poetry','','[]','鶴髮雞皮十二人，非親非故即比鄰。',64,'全唐诗/poet.song.163000.json','["鶴髮雞皮十二人，非親非故即比鄰。", "觥籌交錯情初洽，舌本瀾翻事半陳。", "父祖艱難猶在耳，兒孫憤悱可書紳。", "主人未似賓之老，浩嘆何當老似賓。"]'),
('8826cbf0-2f89-4065-a50b-6b1734db56e7','仲春既晴復雨','曾丰','宋','宋诗','song-poetry','','[]','東君無力破天慳，紅紫遭時得志難。',64,'全唐诗/poet.song.163000.json','["東君無力破天慳，紅紫遭時得志難。", "多可幸然風借暖，少恩傷是雨遺寒。", "云云無謂鶑情沮，僕僕何之蝶意闌。", "爛賞未酬無慍見，計春之日限猶寬。"]'),
('5bee4116-7710-414f-8f70-9e8fe988141c','晚春告遊人','曾丰','宋','宋诗','song-poetry','','[]','春初弄色取知音，旁午尊前獻孔壬。',64,'全唐诗/poet.song.163000.json','["春初弄色取知音，旁午尊前獻孔壬。", "紫守不堅紅更怯，風來無度雨仍侵。", "鶑狂猶妄起羞口，蝶老未知求放心。", "解道不如歸去語，得非知禮識機禽。"]'),
('2b9fa70b-5824-47a7-9928-6966349d184e','江水出峽','曾丰','宋','宋诗','song-poetry','','[]','衢婺徽嚴水固豪，其如所至與山遭。',64,'全唐诗/poet.song.163000.json','["衢婺徽嚴水固豪，其如所至與山遭。", "當難進處雖回避，到不平時輒怒號。", "出峽衝開崖脚闊，迎潮激起浪頭高。", "乘風終作歸墟去，畧湧三山駕六鰲。"]'),
('d8aa5755-60f8-4b62-9698-f3d096940c5b','贈相士曾邵','曾丰','宋','宋诗','song-poetry','','[]','在在衣冠滿坐傾，欲從言下得公卿。',64,'全唐诗/poet.song.163000.json','["在在衣冠滿坐傾，欲從言下得公卿。", "那知胸次重風鑒，不放舌端輕月評。", "天地莫能逃氣數，江湖無處掩名聲。", "鬼神推出中都去，乞與王侯斷死生。"]'),
('3ce34697-e4e0-4e50-bf68-afb5faa5f9b5','十一月六日雨至次月一日始霽','曾丰','宋','宋诗','song-poetry','','[]','數自初旬至末旬，雨猶末了雪相尋。',64,'全唐诗/poet.song.163000.json','["數自初旬至末旬，雨猶末了雪相尋。", "千山草木收元氣，萬里乾坤入太陰。", "城郭譙樓吹凍角，郊原驛舍擣寒砧。", "靜聽年少心須折，幸我已無年少心。"]'),
('17532b29-2a79-4a71-83dd-6bc9db80b2c8','冬行買酒炭自隨','曾丰','宋','宋诗','song-poetry','','[]','大寒已過臘來時，萬物那逃出入機。',64,'全唐诗/poet.song.163000.json','["大寒已過臘來時，萬物那逃出入機。", "木葉隨風無顧藉，溪流落石有依歸。", "炎官後殿排霜氣，玉友前驅挫雪威。", "寄與來鴻不須怨，離鄉作客未爲非。"]'),
('079d6872-11de-437e-9a01-4507f3b907cc','歸途值去客','曾丰','宋','宋诗','song-poetry','','[]','歲晚乾坤閉未開，地中方蟄振天雷。',64,'全唐诗/poet.song.163000.json','["歲晚乾坤閉未開，地中方蟄振天雷。", "山雲已覺成輕出，塞鴈何爲獨遠來。", "失學齊侯隨馬去，甘爲墨子叱車回。", "從今行止休多問，有尼安知不有推。"]'),
('ec60c015-c3a0-44a6-900f-f025f78dbd6d','常山道中','曾丰','宋','宋诗','song-poetry','','[]','閩廣江湖人造朝，水行陸出路迢迢。',64,'全唐诗/poet.song.163000.json','["閩廣江湖人造朝，水行陸出路迢迢。", "誰知鷗鷺爲高尚，我與江山是久要。", "多詐青雲猶見誘，少恩白髮不相饒。", "往哉粗辦老焉計，三徑一丘歸自聊。"]'),
('b3a33180-1bd7-4455-bc05-25aa654a3c06','再題嚴子陵釣臺','曾丰','宋','宋诗','song-poetry','','[]','四百年間將相誰，豐功偉績竟何歸。',64,'全唐诗/poet.song.163000.json','["四百年間將相誰，豐功偉績竟何歸。", "生前有望榮招辱，死後無明是反非。", "麟閣故基爲草鞠，雲臺遺屋與烟飛。", "桐江自漢至今日，依舊行人指釣磯。"]'),
('6af14da8-ec00-4d96-abc0-16c6d04e082b','江下望永思陵','曾丰','宋','宋诗','song-poetry','','[]','臣生差晚十餘年，八彩堯眉僅一瞻。',64,'全唐诗/poet.song.163000.json','["臣生差晚十餘年，八彩堯眉僅一瞻。", "鳳出未能前附翼，龍歸不及上攀髯。", "山頭鑄鼎爐長冷，湖上號弓淚滿霑。", "漠漠穀林無認處，城陽烟與草相黏。"]'),
('df2b89dc-169a-45dd-aad6-83d26d878038','靈山','曾丰','宋','宋诗','song-poetry','','[]','三過靈山總有緣，曉無逗靄晚無烟。',64,'全唐诗/poet.song.163000.json','["三過靈山總有緣，曉無逗靄晚無烟。", "橫眠吳楚中央地，高拄東南半壁天。", "芝草本爲人所上，水晶猶得氣之偏。", "山靈還有中原意，更爲時生十數賢。"]'),
('2408acb8-9213-4425-a535-45a72692903d','月巖','曾丰','宋','宋诗','song-poetry','','[]','巖腹刳爲半月形，全功天且不能成。',64,'全唐诗/poet.song.163000.json','["巖腹刳爲半月形，全功天且不能成。", "勿嗟圓處便生缺，猶幸晦中堪養明。", "更朔還多終有望，受虧已久得無盈。", "願言鍊石補教足，使我衆生眼界平。"]'),
('44bfdbb1-aa12-480e-a30e-ef00a82fe940','登會稽蓬萊閣讀唐宋士大夫詩','曾丰','宋','宋诗','song-poetry','','[]','盤盤矯矯卧龍峯，傑閣崢嶸龍腹中。',64,'全唐诗/poet.song.163000.json','["盤盤矯矯卧龍峯，傑閣崢嶸龍腹中。", "柱脚下懸危踏軟，簷牙高豁巧銜空。", "江山互以青相繞，雲霧時翻黑自蒙。", "物態任呈千百種，倚欄吾自嘯清風。"]'),
('c0d94c90-370f-4968-9b05-06873c8238c6','中都值東廣便馳寄管漕','曾丰','宋','宋诗','song-poetry','','[]','落在京華九陌塵，鏡中無日不眉顰。',64,'全唐诗/poet.song.163000.json','["落在京華九陌塵，鏡中無日不眉顰。", "未論妻子其如母，不奈秋冬况復春。", "餒食且將蔬作肉，寒炊寧免桂爲薪。", "餘無可獻逐貧賦，寄與知音舊主人。"]'),
('8aa80183-9574-4b41-9e8c-04cf6c7f446a','過古暨見故人程夢良夢周','曾丰','宋','宋诗','song-poetry','','[]','先德曾同贛上官，六年今始到門闌。',64,'全唐诗/poet.song.163000.json','["先德曾同贛上官，六年今始到門闌。", "寒溫畧敘顔初破，存沒徐詢鼻即酸。", "可著江山胸磊隗，不遺今古舌瀾翻。", "弟兄幸是洛中派，一炷爐薰更反觀。"]'),
('326e5913-877f-4887-a43f-7146c318ddda','寄廣東提幹田子真','曾丰','宋','宋诗','song-poetry','','[]','初悔投身落海涯，擁車猶幸襲蹤來。',64,'全唐诗/poet.song.163000.json','["初悔投身落海涯，擁車猶幸襲蹤來。", "畏途機械鹿貙虎，晏歲風霜松竹梅。", "分首二年眉慣鬰，舉頭千里眼傭開。", "江山不隔往還夢，一夢醒時悶一回。"]'),
('66aba35a-715d-4054-a0aa-091c957d3af2','甲辰歲與涂漢英別己酉復相過遽告行固小留之','曾丰','宋','宋诗','song-poetry','','[]','轉蓬分首入梅關，千里空餘夢往還。',64,'全唐诗/poet.song.163000.json','["轉蓬分首入梅關，千里空餘夢往還。", "把酒無非酹明月，鳴弦不復鼓高山。", "匆匆六載重携手，草草三杯一破顔。", "相聚勿嫌寬數日，天于吾道意常慳。"]'),
('1d4c4ced-4022-41f0-9043-e815ea0a3609','題李達先靜暉軒','曾丰','宋','宋诗','song-poetry','','[]','瀟灑一區山四圍，朱簾高捲晝陰移。',64,'全唐诗/poet.song.163000.json','["瀟灑一區山四圍，朱簾高捲晝陰移。", "三竿已上其誰報，一線初長也自知。", "鼓腹曬書春拍拍，蓬頭晞髮暖垂垂。", "晴窗大得志機趣，渴爵窺盆更不疑。"]'),
('f7628a05-19fa-41db-ac64-fa99e55d473c','憩古寺','曾丰','宋','宋诗','song-poetry','','[]','綠繞青圍春一窩，精廬突兀在烟蘿。',64,'全唐诗/poet.song.163000.json','["綠繞青圍春一窩，精廬突兀在烟蘿。", "地容牆壁剩無幾，山視樓臺高不多。", "馴爵諳知僧自在，吠尨怪見客相過。", "古音獨幸黄鸝會，挑我風前一再哦。"]'),
('15534ba4-f26d-4c49-b21d-fbfd076a8f87','雨霽宿薦福寺遣問寺僧','曾丰','宋','宋诗','song-poetry','','[]','松筠邀我梵王宮，耳目俱醒骨肉融。',64,'全唐诗/poet.song.163000.json','["松筠邀我梵王宮，耳目俱醒骨肉融。", "風雨收聲禪入寂，烟雲歛色法歸空。", "出浮漚外不生滅，從浩劫來無異同。", "問數比丘皆卷舌，舌雖不卷亦無功。"]'),
('ce572e7a-c50d-4524-8828-3032542f82b9','坐貧止挈孥累之半赴義寧','曾丰','宋','宋诗','song-poetry','','[]','半住山西半廣西，一家兩處互憂疑。',64,'全唐诗/poet.song.163000.json','["半住山西半廣西，一家兩處互憂疑。", "北音不至雁之扉，南□先回梅所私。", "橫膝未能忘舐犢，齊眉何必□□□。", "俸餘一一持竿去，兒女分爲飽暖資。"]'),
('d9c2fb2f-0b67-45dd-a9fc-efcaced6ba9f','春夏之交沿途觸目','曾丰','宋','宋诗','song-poetry','','[]','往年休歎去駸駸，只數今年且十旬。',64,'全唐诗/poet.song.163000.json','["往年休歎去駸駸，只數今年且十旬。", "稚綠已爭欺旭暑，老紅猶强護畸春。", "水平似面因風皺，山遠如眉得雨顰。", "物態到前長是笑，不知物態總關身。"]'),
('8b8379d2-7465-4fe1-8cfc-13071366c637','觸目','曾丰','宋','宋诗','song-poetry','','[]','無我那虞物所侵，從教物與我相尋。',64,'全唐诗/poet.song.163000.json','["無我那虞物所侵，從教物與我相尋。", "雲頭翻墨任濃淡，山頂潑藍隨淺深。", "春色若空疑有著，天工雖巧實無心。", "可憐杜宇空多淚，更笑黄鸝强好音。"]'),
('0e76d866-aed9-4714-a9f3-9a45a6085816','簡寄游稚牧昆仲','曾丰','宋','宋诗','song-poetry','','[]','或許伊川到聖賢，弟兄今又學伊川。',64,'全唐诗/poet.song.163000.json','["或許伊川到聖賢，弟兄今又學伊川。", "會將不二心傳印，還出無雙手續絃。", "當道書中無大道，後天易外有先天。", "更思猶合下功處，有一毫遺未大全。"]'),
('7a43fba8-05d8-4457-a4f5-6b547476b666','永新道中會曾時仲敘舊','曾丰','宋','宋诗','song-poetry','','[]','數自傾心結友時，幾離還合合還離。',64,'全唐诗/poet.song.163000.json','["數自傾心結友時，幾離還合合還離。", "三年夜話燈知爾，千里秋懷月鑒之。", "黄卷孰非歸領會，青雲終不負襟期。", "相逢有一設不盡，前此區區枉夢思。"]'),
('8588d8e7-5991-4fc9-b06f-88907c8b9a53','至衡陽謁陳提舉國錄君舉  其一','曾丰','宋','宋诗','song-poetry','','[]','邇年前輩又凄凉，吾教他無敢主張。',64,'全唐诗/poet.song.163000.json','["邇年前輩又凄凉，吾教他無敢主張。", "飲食起居歸道德，笑嬉怒駡出文章。", "南軒間氣初歸嶽，北客道風半落湘。", "收拾發揮天所屬，公餘不可以它妨。"]'),
('299233ad-34e4-4615-ad77-271dda2a13b9','至衡陽謁陳提舉國錄君舉  其二','曾丰','宋','宋诗','song-poetry','','[]','夜論語罷醉相辭，公尚留中我獨歸。',64,'全唐诗/poet.song.163000.json','["夜論語罷醉相辭，公尚留中我獨歸。", "跡似雲泥長落落，心如秋月固依依。", "淵明久轉非爲是，子夏方從瘦覓肥。", "邂逅莫孤鎸切望，後期未必不相違。"]'),
('e7a00a57-c3d9-4451-b7d7-cacbaf14b15d','至衡陽謁提刑范右司東叔同年兄  其一','曾丰','宋','宋诗','song-poetry','','[]','西士無傳不得宗，我公况是有家風。',64,'全唐诗/poet.song.163000.json','["西士無傳不得宗，我公况是有家風。", "長卿東望輕雲夢，太史南遊小祝融。", "萬里饑寒民所德，半生辛苦學之功。", "擴充更卒晚年業，殺等猶爲小蜀公。"]'),
('38a84739-89fe-4013-992c-fc8a9c45f3df','至衡陽謁提刑范右司東叔同年兄  其二','曾丰','宋','宋诗','song-poetry','','[]','久別重逢岳麓邊，未遑扣謁已招延。',64,'全唐诗/poet.song.163000.json','["久別重逢岳麓邊，未遑扣謁已招延。", "杯盤一笑心相下，風雨三更膝輒前。", "我愧莫當公過禮，他求無復此同年。", "年來天厭義風薄，借喫湖南作樣傳。"]'),
('a921d35b-31a9-4bab-8c17-f39c385a6213','陳君舉飯余倉司之五峰閣移坐臨簷口占舉似','曾丰','宋','宋诗','song-poetry','','[]','傑閣崢嶸著樹間，門從好色未嘗關。',64,'全唐诗/poet.song.163000.json','["傑閣崢嶸著樹間，門從好色未嘗關。", "簷前珠箔開平遠，坐上清尊答燕閒。", "能卷塵心三曲水，欲迷客眼九嶷山。", "主人胸次俱收拾，筆力雖饒萬象慳。"]'),
('425b3954-f30c-4553-8765-a1a01190a96e','沿衡陽而下觸目撫懷','曾丰','宋','宋诗','song-poetry','','[]','湖深無敵岳無倫，流峙云胡各駿奔。',64,'全唐诗/poet.song.163000.json','["湖深無敵岳無倫，流峙云胡各駿奔。", "水守以兼常下下，山□□分固尊尊。", "蒼梧螻蟻慕虞舜，彭蠡鱣鯨切屈原。", "吾與大通合爲一，有懷何必問乾坤。"]'),
('baabfbc1-7614-4ffa-8e4d-30e6cf6aa4b5','舟至衡陽轉入茶陵','曾丰','宋','宋诗','song-poetry','','[]','來怯南中氣候偏，歸乘不熱不寒天。',64,'全唐诗/poet.song.163000.json','["來怯南中氣候偏，歸乘不熱不寒天。", "口防湘濕未安食，身忌粵嵐猶擇眠。", "山不相高谷水過，天能自不與江連。", "到前却入江西路，耳目相諳性可便。"]'),
('98bba61d-7f3a-4b9b-ab2a-13c781b4b30b','望嶽','曾丰','宋','宋诗','song-poetry','','[]','方嶽分爲五太宗，江南崒嵂祝融峰。',64,'全唐诗/poet.song.163000.json','["方嶽分爲五太宗，江南崒嵂祝融峰。", "中天自立如皇極，支嶠相歸若附庸。", "湖不多浮爲所鎮，斗猶小退避其衡。", "太高要以卑爲德，七十二君休更封。"]'),
('ceed51f9-323e-48af-a669-833b3e60ae33','遊淡巖  其一','曾丰','宋','宋诗','song-poetry','','[]','混沌誰將竅鑿穿，巨靈留巧與人傳。',64,'全唐诗/poet.song.163000.json','["混沌誰將竅鑿穿，巨靈留巧與人傳。", "坎中著脚疑無地，缺處回頭却有天。", "穴虎將風時出嘯，淵龍挾雨夜歸眠。", "瑶臺瓊室人難住，佛未來時必是仙。"]'),
('c7bbba65-ec16-4805-9562-45d8dd62aa45','遊淡巖  其二','曾丰','宋','宋诗','song-poetry','','[]','谽谺萬狀眼中奇，四顧三嘆天下稀。',64,'全唐诗/poet.song.163000.json','["谽谺萬狀眼中奇，四顧三嘆天下稀。", "秦帝詔方宣美意，徵君心已悟危機。", "追隨談姓俱韜晦，邂逅涪翁併發揮。", "却羨桃源人更會，和名和姓襲鴻飛。"]'),
('0f7ecb2c-e74d-4b42-915d-45412066f088','致敬五公祠堂','曾丰','宋','宋诗','song-poetry','','[]','五公稷契益臯夔，朝蹟纔安輒復危。',64,'全唐诗/poet.song.163000.json','["五公稷契益臯夔，朝蹟纔安輒復危。", "始信君非讎格處，皆緣國是有摇時。", "高山日矯行人首，喬木時顰故老眉。", "莫道落南非美事，也多添得永州碑。"]'),
('ec62fe95-fa8b-48ea-83a8-c79b36de05a0','舟入平流','曾丰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','危機垂跌又平過，宿處捫心幸蓋多。',64,'全唐诗/poet.song.163000.json','["危機垂跌又平過，宿處捫心幸蓋多。", "初月曲如鈎倒挂，長江平似鏡新磨。", "四聽群動詒音寂，中有一禽呼字訛。", "萬念俱灰眠即熟，終宵無夢入南柯。"]'),
('a22d007c-8279-4c68-9426-14b1312d6ee5','興安縣西南石峰秀拔無數','曾丰','宋','宋诗','song-poetry','','[]','天限華夷數十峯，秦王始鑿始相逢。',64,'全唐诗/poet.song.163000.json','["天限華夷數十峯，秦王始鑿始相逢。", "勞民浪闢嶠南國，失德徒成身後胸。", "楚粵未爭尋丈遠，炎凉無復半分同。", "賓鴻諱入嚴關去，吾策如今不似鴻。"]'),
('95bdf5b7-e31e-4ee4-b55f-0645583359b0','過嚴關','曾丰','宋','宋诗','song-poetry','','[]','誓不南游今復遊，東西雖異等南州。',64,'全唐诗/poet.song.163000.json','["誓不南游今復遊，東西雖異等南州。", "妻兒累己何人免，行止關天不自由。", "伏櫪過都從野馬，乘流遇坎任虛舟。", "嚴關猿鳥休相笑，更過梅關笑却羞。"]'),
('9a3544f2-3ff0-42be-81bf-4fbc49942c70','到義寧自夏至秋不得家書思親謀歸不遂','曾丰','宋','宋诗','song-poetry','','[]','散客强名邑大夫，琴堂餘暇北窗孤。',64,'全唐诗/poet.song.163000.json','["散客强名邑大夫，琴堂餘暇北窗孤。", "燈前夜雨無寧竹，枕上秋風有戰梧。", "懸望北音思射雁，滿懷東道夢烹鱸。", "白雲一望二千里，羞聽林間反哺烏。"]'),
('0034ea17-c1e7-47b3-aa1e-4eaf946682c7','方罹殘熱忽值新凉喜而賦反悲秋','曾丰','宋','宋诗','song-poetry','','[]','晴宵如浸晝如蒸，變氣知從激處生。',64,'全唐诗/poet.song.163000.json','["晴宵如浸晝如蒸，變氣知從激處生。", "風不相饒乘木敗，火猶自負與金爭。", "纖阿洗月爲純白，少皞澄天作太清。", "宋玉所悲吾所喜，長哦聊復發秋聲。"]'),
('87df5b79-a02c-4274-8abd-a802b3748b1c','冬夜官舍圍爐傳酒','曾丰','宋','宋诗','song-poetry','','[]','放散衙曹小退安，閉門開架檢書看。',64,'全唐诗/poet.song.163000.json','["放散衙曹小退安，閉門開架檢書看。", "簷前月色生寥寂，屋外風聲長隙寒。", "灰火撥愁頭屢點，燼燈挑喜指頻彈。", "家人知我飲機動，大白梨花送夜闌。"]'),
('00577129-a9d5-4935-b01a-98c5175057e9','呈臨桂宰歐陽丈','曾丰','宋','宋诗','song-poetry','','[]','中都倥傯合還離，臆料雲萍不復齊。',64,'全唐诗/poet.song.163000.json','["中都倥傯合還離，臆料雲萍不復齊。", "官下有緣俱嶺表，社中何幸更江西。", "四民自喜歸摩撫，百嶂相爭入品題。", "嗟我簿書塵裏坐，來篇疑是辟塵犀。"]'),
('8a87abb4-ee1a-41e6-bfcf-3e22c57ed51d','庚戌長至稚子杓覓詩賦一篇警之','曾丰','宋','宋诗','song-poetry','','[]','芒芒草色木方枯，泱泱乾坤氣又噓。',64,'全唐诗/poet.song.163000.json','["芒芒草色木方枯，泱泱乾坤氣又噓。", "凋歲似吾華髮後，稚陽如子妙齡初。", "冬寒乍熱宜磨墨，日短初長好讀書。", "一字未之曾究竟，百年何者是權輿。"]'),
('355a08d6-ce5f-433c-85f8-8af5d068f29d','深冬積暖乍寒','曾丰','宋','宋诗','song-poetry','','[]','冬令將終尚未霜，伏陰猶强遜愆陽。',64,'全唐诗/poet.song.163000.json','["冬令將終尚未霜，伏陰猶强遜愆陽。", "連旬逗暖日驕放，半夜邀寒風怒張。", "蟲不開關平引退，木無背本隠歸藏。", "道消固自有時長，世事那由得汝忙。"]'),
('6ecb6d3e-bb34-44c0-b01a-4d7a44f7f30f','冬晴釀霜雪不成','曾丰','宋','宋诗','song-poetry','','[]','一晴初已涉秋殘，晴到深冬興未闌。',64,'全唐诗/poet.song.163000.json','["一晴初已涉秋殘，晴到深冬興未闌。", "不雨臨空聊爾濕，無霜元是盛哉寒。", "出乘氣末羣陰亂，歸抱精風萬物安。", "深省莫如堅坐是，還家毋更負蒲團。"]'),
('92c223b3-c829-48bb-845f-c5b632bc971f','窮冬逆旅','曾丰','宋','宋诗','song-poetry','','[]','日月隙中容易過，歸期我與歲相蹉。',64,'全唐诗/poet.song.163000.json','["日月隙中容易過，歸期我與歲相蹉。", "雪霜使氣張湯酷，風日容情下惠和。", "木葉先凋歸宿早，梅花後發得春多。", "輿臺不識吾忘物，猶怪鴉鳴慮有他。"]'),
('a3623625-ccd2-4682-bf38-e6bb7b80421a','送張叔介','曾丰','宋','宋诗','song-poetry','','[]','籍甚江西汝水頭，功名驅作嶺南遊。',64,'全唐诗/poet.song.163000.json','["籍甚江西汝水頭，功名驅作嶺南遊。", "當機筆易千人陣，得意詩輕萬戶侯。", "炫晝江山供泛愛，酣冬風雨送牢愁。", "脚皸莫患無堪軟，四海多情涂柳州。"]'),
('486e5d7f-9225-446a-ba28-ce6e4f71c9e8','高德成訪予義寧留久之告歸賦兩長韻  其一','曾丰','宋','宋诗','song-poetry','','[]','經史百家書挂眼，唐虞三代事蟠胸。',64,'全唐诗/poet.song.163000.json','["經史百家書挂眼，唐虞三代事蟠胸。", "不孤父祖餘良貴，猶累妻兒一素封。", "賢者大凡先鉏鋙，貴人强半晚遭逢。", "况余先慶未曾報，天意初違後必從。"]'),
('ecdda9c4-2a4e-4fb1-9619-0c2a8da95226','高德成訪予義寧留久之告歸賦兩長韻  其二','曾丰','宋','宋诗','song-poetry','','[]','足輕橫桂易瀟湘，背負唐瓢李賀臧。',64,'全唐诗/poet.song.163000.json','["足輕橫桂易瀟湘，背負唐瓢李賀臧。", "何者江山非痛快，孰云杖屨是乾忙。", "馬遷南歷靡遺記，陸賈北歸元儉裝。", "徒折梅花寄消息，家人眉豈不空黄。"]'),
('81163173-e97c-4932-9864-6a2e1cedeaba','宿上望之桂樓','曾丰','宋','宋诗','song-poetry','','[]','重屋崢嶸據道周，浪行良勸小淹留。',64,'全唐诗/poet.song.163000.json','["重屋崢嶸據道周，浪行良勸小淹留。", "星無匿彩天澄夜，雲不遺瑕月粲秋。", "金氣方張猶重殺，物華已結未多收。", "老來姑置行藏事，它日其懷獨倚樓。"]'),
('6043f9c6-56a6-4635-b35c-76378380cef5','首夏歸途感物自酌','曾丰','宋','宋诗','song-poetry','','[]','不寒不熱小梅天，千里歸懷正所便。',64,'全唐诗/poet.song.163000.json','["不寒不熱小梅天，千里歸懷正所便。", "嫩笋觸沙抽犢角，新荷拏水握兒拳。", "游絲有緒誰紬繹，野繭難繰自裹纏。", "歡伯疑吾猶著物，殷勤送至汗漫邊。"]'),
('a73c2cb5-6559-4910-90fc-e533be8fd7d9','涉夏歸途','曾丰','宋','宋诗','song-poetry','','[]','一意貪歸百事忘，其如耳目觸吾旁。',64,'全唐诗/poet.song.163000.json','["一意貪歸百事忘，其如耳目觸吾旁。", "女桑醉日多相靡，孫竹驕風半自强。", "螻蟈無稽言語泛，蜻蜓罔念性情狂。", "鳲鳩占盡世間拙，未害云爲蹈大方。"]'),
('c0b45ae4-fbc3-44e5-a49f-21e9d3d9433f','至沙溪拜六一先生墓','曾丰','宋','宋诗','song-poetry','','[]','文章事業宋名臣，潁上輕投未老身。',64,'全唐诗/poet.song.163000.json','["文章事業宋名臣，潁上輕投未老身。", "葛水衣冠凄欲斷，沙溪泉石鬰空陳。", "高山踞視廢興事，喬木坐邀來往人。", "碑未失真公手澤，中餘廊廟舊精神。"]'),
('8febc0b0-defb-4f3f-8028-fcabc3806e39','讀六一先生碑亭記','曾丰','宋','宋诗','song-poetry','','[]','六一先生自不磨，太丘興卜植僵多。',64,'全唐诗/poet.song.163000.json','["六一先生自不磨，太丘興卜植僵多。", "牛羊莫犯墓塋者，風雨其如阡表何。", "器識誰能三世合，規摹可復百年過。", "豐碑幸出老彭手，讀罷寧容不一哦。"]'),
('f708371a-dae0-4019-9d47-78bbb49b6b21','太白山西隠寺木犀','曾丰','宋','宋诗','song-poetry','','[]','族出于仙住傍僧，羞爲春事與時爭。',64,'全唐诗/poet.song.163000.json','["族出于仙住傍僧，羞爲春事與時爭。", "長專太白山涵潤，獨淹中秋月滲清。", "色染真空如自失，香熏正覺若相成。", "靈雲有幸相遭遇，不要桃花作證明。"]'),
('c079fe81-8520-48ee-99b1-cb3658a0449b','社前雷雨連旬','曾丰','宋','宋诗','song-poetry','','[]','社到如今已有涯，陰罅陽隙卒乘之。',64,'全唐诗/poet.song.163000.json','["社到如今已有涯，陰罅陽隙卒乘之。", "風雷撼夜何相激，桃李催春不自支。", "鴻狃猶寒忘去計，燕疑未暖爽來期。", "杜鵑毋怨鶑毋喜，春早春遲自有時。"]'),
('dc57db67-ea4e-44c0-9c08-296526140a96','題疏山一覽亭','曾丰','宋','宋诗','song-poetry','','[]','孤絕招邀杜道過，支筇不足更捫蘿。',64,'全唐诗/poet.song.163000.json','["孤絕招邀杜道過，支筇不足更捫蘿。", "旁無斷岸乾坤大，上有餘天日月多。", "道限與空歸不二，色塵隨幻入無何。", "虛中元自寄吾實，往古來今不可磨。"]'),
('68f250c6-ef01-48bd-b0ab-b70e2308d1a1','再與鼎臣遊龍門寺','曾丰','宋','宋诗','song-poetry','','[]','初嘆來遊未必重，等閑十載又相逢。',64,'全唐诗/poet.song.163000.json','["初嘆來遊未必重，等閑十載又相逢。", "壁間故跡塵輕涴，物外初心病暗攻。", "坐上酒生冬暖意，檐前梅弄歲寒容。", "半酣僧不須烹茗，自有山雲可盪胸。"]'),
('95e3c1df-2cde-471f-b6e8-9f4ad12ff3fb','二十年前與曾恭仲爲忘年之交歲辛亥值便賦長韻寄似','曾丰','宋','宋诗','song-poetry','','[]','孔欲華顛禰妙齡，忘年不足更忘形。',64,'全唐诗/poet.song.163000.json','["孔欲華顛禰妙齡，忘年不足更忘形。", "弟兄偏是子眉白，朋友獨于吾眼青。", "心若互馳常鑒寐，跡如相避各雲萍。", "十年功已到千古，何日酣看又飫聽。"]'),
('b4c7fbb0-ba63-4b6f-90b2-e175ca889197','題陳宗元拂雲軒','曾丰','宋','宋诗','song-poetry','','[]','灘西地不愛其珍，虎豹文章善自陳。',64,'全唐诗/poet.song.163000.json','["灘西地不愛其珍，虎豹文章善自陳。", "縹節猶儲何尉粉，緗苞不納庾公塵。", "性高霜雪摧難折，氣直風雷拔易伸。", "寄語籜龍無傲主，主家今有似龍人。"]'),
('ed9b54e3-7dc0-4fd3-8079-b410371caad0','題黄武子齊雲樓','曾丰','宋','宋诗','song-poetry','','[]','禔棟重簷矯欲飛，與天相近可捫奎。',64,'全唐诗/poet.song.163000.json','["禔棟重簷矯欲飛，與天相近可捫奎。", "晴宵拄月輕烟漠，暝晝撐虹小雨凄。", "燕客樂催雷響落，照筵燈壓電光低。", "馭風騎氣非渠事，萬里青雲可以梯。"]'),
('71f53254-0a63-4b28-b666-5e3627a220d1','題戴主簿德成盡得樓','曾丰','宋','宋诗','song-poetry','','[]','樓與主人俱卓然，主人步更與樓遷。',64,'全唐诗/poet.song.163000.json','["樓與主人俱卓然，主人步更與樓遷。", "面前加闢山河地，頭上增高日月天。", "指顧大千俄可度，拊循方寸浩無邊。", "校讎所得孰多寡，萬物支離我混全。"]'),
('1b1f60f0-e1bf-4f46-85e1-5bff00ff9177','呈吾宗茂夫','曾丰','宋','宋诗','song-poetry','','[]','國初名下數三陳，今代吾宗又有人。',64,'全唐诗/poet.song.163000.json','["國初名下數三陳，今代吾宗又有人。", "兄弟已推眉更白，功名何慮骨猶屯。", "濂溪氣韻娟娟月，康節襟懷盎盎春。", "奮迅發揮吾敢許，穩登鸞鳳上麒麟。"]'),
('5edd3a35-d19e-4ff2-a825-3ab68d6ca757','贈陰陽家鄧彬叔','曾丰','宋','宋诗','song-poetry','','[]','舌本瀾翻郭璞書，試今措手驗何如。',64,'全唐诗/poet.song.163000.json','["舌本瀾翻郭璞書，試今措手驗何如。", "星辰聚處收玄武，江漢潮邊避尾閭。", "山水流形開闔後，陰陽受氣混淪初。", "要參融結玄機破，心眼長教等太虛。"]'),
('a7a36b40-75f1-4e39-b153-dcd9dcd856a2','贈陰陽家邱明遠','曾丰','宋','宋诗','song-poetry','','[]','誰云素手動朱門，我固知君有道存。',64,'全唐诗/poet.song.163000.json','["誰云素手動朱門，我固知君有道存。", "鳳曆三元胸次具，龍圖八卦掌中翻。", "懸知地理善之善，正恐天機玄又玄。", "借使乾坤權在我，更當有以制乾坤。"]'),
('d999c205-6979-4000-8002-fab762460458','贈黄正卿競秀樓','曾丰','宋','宋诗','song-poetry','','[]','巴西地不愛其珍，山影溪光輒自陳。',64,'全唐诗/poet.song.163000.json','["巴西地不愛其珍，山影溪光輒自陳。", "霜後竹饒松意氣，雨餘花奪草精神。", "千斯態度出天功，百爾光華歸色塵。", "好事至人寧外慕，反身元自有真春。"]'),
('589e911a-d9ac-4d4e-9c62-4bc9d71168ba','贈陰陽家童國用','曾丰','宋','宋诗','song-poetry','','[]','生于參政侍郎村，它尚詩書况近孫。',64,'全唐诗/poet.song.163000.json','["生于參政侍郎村，它尚詩書况近孫。", "鐵硯無功招白眼，金函有訣動朱門。", "天開西北衆星聚，地闢東南元氣溫。", "要就其間卜佳處，胸中須自有乾坤。"]'),
('f6c0eb1e-b3b6-47ee-b384-5fa7bd021a95','逆旅書懷','曾丰','宋','宋诗','song-poetry','','[]','吾生宜客不宜家，今趁輕舟傍淺沙。',64,'全唐诗/poet.song.163000.json','["吾生宜客不宜家，今趁輕舟傍淺沙。", "天擁雲堆浮玉乳，波摇日影弄金花。", "詩中已醉那消酒，飯後雖酲可廢茶。", "安得長閑棹歌裏，清風明月任年華。"]'),
('86478189-118e-4a56-8bbf-21d6d7cf880c','京都旅卧','曾丰','宋','宋诗','song-poetry','','[]','喜得家書睡不成，擁衾欹枕數寒更。',64,'全唐诗/poet.song.163000.json','["喜得家書睡不成，擁衾欹枕數寒更。", "衝風鐵板俄驚曉，映日紗窗又報晴。", "蹀躞過橋朝馬響，咄嗟爭道擔夫聲。", "利名失脚時回首，雖未能忘也較輕。"]'),
('6f17c46c-e5bb-4189-9ebe-0fd300141783','題潮出海門圖','曾丰','宋','宋诗','song-poetry','','[]','海漲爲潮在在均，浙江別有主潮神。',64,'全唐诗/poet.song.163000.json','["海漲爲潮在在均，浙江別有主潮神。", "聲摇地脈雷霆怒，風擘崖根贔屭嗔。", "鮫鰐乘風噴立雪，虹蜺挾雨湧橫銀。", "吾詩渠畫俱摹寫，試鑒工夫孰逼真。"]'),
('02848b87-eaa5-4e49-9dd4-8db04c79d850','張功甫見贈丁藁','曾丰','宋','宋诗','song-poetry','','[]','王孫氣習窶儒生，壯士襟期老典刑。',64,'全唐诗/poet.song.163000.json','["王孫氣習窶儒生，壯士襟期老典刑。", "疾俗如仇幾掃跡，貪書若癖至忘形。", "風雲未會心先冷，水石無遊眼不醒。", "獨據清高天所忌，吟邊分我小鷗汀。"]'),
('005f27d6-c1cc-4874-a992-a9b39fc5558a','比以形字韻詩遞送張功甫直閣未報復于本韻中思之別得一篇并寫呈','曾丰','宋','宋诗','song-poetry','','[]','桂隠心雖欲謝名，其如德與桂俱馨。',64,'全唐诗/poet.song.163000.json','["桂隠心雖欲謝名，其如德與桂俱馨。", "研窮詩學杜爲史，勘破賦家騷是經。", "豹變不容藏炳蔚，鴻飛何遽入青冥。", "淵明門下無車馬，竹杖芒鞋敢扣扃。"]'),
('4cd367fc-2ff9-4524-a36a-e2da3c2ab10d','直閣張功甫南湖集','曾丰','宋','宋诗','song-poetry','','[]','百好何嘗一徇時，遊心上與古相追。',64,'全唐诗/poet.song.163000.json','["百好何嘗一徇時，遊心上與古相追。", "不容萬物移吾學，猶得餘功到此詩。", "玄酒太羹無痛快，光風霽月有長思。", "披吟不足仍含咀，吾坐若忘行若遺。"]'),
('7212a494-5ea7-4b3c-9228-6a07fcf39fb3','呈太府曾寺簿','曾丰','宋','宋诗','song-poetry','','[]','吾宗昌大是蘭溪，況在蘭溪最白眉。',64,'全唐诗/poet.song.163000.json','["吾宗昌大是蘭溪，況在蘭溪最白眉。", "闖足鵷行初養望，策勳麟閣少須時。", "中原自古須歸正，上策從今要出奇。", "公自可爲蕭相國，求如韓信即今誰。"]'),
('776fa791-02a2-4a2f-85a9-ffbeea43e88e','寄臨汀推官盧伯壽  其一','曾丰','宋','宋诗','song-poetry','','[]','解官赴調出臨川，倒指侵尋十二年。',64,'全唐诗/poet.song.163000.json','["解官赴調出臨川，倒指侵尋十二年。", "文學背時招白眼，功名迂路得華顛。", "胸中要與天相似，分內姑安理自然。", "素業更須頻點檢，有無可以上青編。"]'),
('1323723f-f358-4560-b5ae-8c8bf17fa4d3','寄臨汀推官盧伯壽  其二','曾丰','宋','宋诗','song-poetry','','[]','都下燈前別酒闌，我歸江國子閩關。',64,'全唐诗/poet.song.163000.json','["都下燈前別酒闌，我歸江國子閩關。", "鯉魚不賜書來去，蝴蝶猶將夢往還。", "抵掌伊吾灰壯志，折腰彭澤汗衰顔。", "十年以後來相問，收拾俸餘歸買山。"]'),
('14a71195-0d08-45f3-9b60-8bb89042eb57','觸目','曾丰','宋','宋诗','song-poetry','','[]','筆頭紙上兩無功，擁被開篷眼自空。',64,'全唐诗/poet.song.163000.json','["筆頭紙上兩無功，擁被開篷眼自空。", "石脈直尋江脈去，山光元與水光同。", "春隨草木高低到，氣併乾坤裏外通。", "反顧有吾即無物，卓然獨立太虛中。"]'),
('43125810-43e7-4e8e-806d-792022c38ca1','慶元改元浦城桑田大稔余按視次告父老','曾丰','宋','宋诗','song-poetry','','[]','農桑初軫素餐憂，幸爾天然大有秋。',64,'全唐诗/poet.song.163000.json','["農桑初軫素餐憂，幸爾天然大有秋。", "壯穗凝鎌黄䆉䅉，柔絲滑杼白綢繆。", "黎明婦女放雞犬，薄暮兒童歸馬牛。", "飽煖自聊無背本，輕肥相尚莫如流。"]'),
('8fad2c2f-1a4b-4a44-9418-6811565a2b91','題南浦萬乘寺瀑布','曾丰','宋','宋诗','song-poetry','','[]','緬止銀崖瀉玉泉，似乎有以使之然。',64,'全唐诗/poet.song.163000.json','["緬止銀崖瀉玉泉，似乎有以使之然。", "素虹挾雨斜搶地，澄練披風倒倚天。", "山不曾分青自斷，月猶未落白相連。", "掬清嚥冷吾能事，老不禁多凜欲顛。"]'),
('94301cb3-83e9-4693-a7dc-65490586f384','尋春觸興','曾丰','宋','宋诗','song-poetry','','[]','乾坤無計嗇春妍，擁在詩人耳目前。',64,'全唐诗/poet.song.163000.json','["乾坤無計嗇春妍，擁在詩人耳目前。", "桃带酒容紅煦煦，李餘粉態白娟娟。", "蜂情落魄華胥國，燕思嫖姚兜率天。", "陽鳥獨參浴沂意，風前特賦詠歸篇。"]'),
('c2c69ab2-d0b2-4527-a388-3c563a5339fa','舟中忽聞瀑布','曾丰','宋','宋诗','song-poetry','','[]','江行終日聽江聲，忽怪潺潺聲較清。',64,'全唐诗/poet.song.163000.json','["江行終日聽江聲，忽怪潺潺聲較清。", "泉乳融爲玉乳白，浪花散作雪花輕。", "一船是水人心異，萬想俱空眼界平。", "更作曹溪餘滴看，談空猶是强聰明。"]'),
('fd65f4ef-711f-4f36-9885-c1e53019bf1d','題建寧府丹青閣','曾丰','宋','宋诗','song-poetry','','[]','傑觀安之險處佳，兩崖幾欲薄簷牙。',64,'全唐诗/poet.song.163000.json','["傑觀安之險處佳，兩崖幾欲薄簷牙。", "猶餘隙地盛泉滴，不礙長天放物華。", "縹蝕以緗霜後葉，朱渝其碧水中霞。", "有聲畫裏難爲色，色即謂空又一家。"]'),
('e72ba438-89c2-46b1-ba58-cf05e28c81e1','端月上浣','曾丰','宋','宋诗','song-poetry','','[]','玄冬連日太陰凝，醖釀開年滿意晴。',64,'全唐诗/poet.song.163000.json','["玄冬連日太陰凝，醖釀開年滿意晴。", "槁植驚春榮意動，孤飛觸暖偶情生。", "心無外慕溪南牧，眼不旁觀隴上耕。", "桀溺長沮渠輩是，休教知我爲將迎。"]'),
('a7b3f159-ac68-4d5f-8aa7-611bfa4a927b','送管廷輝歸章貢','曾丰','宋','宋诗','song-poetry','','[]','久別重逢笑脫頤，休談愁緒殺腰圍。',64,'全唐诗/poet.song.163000.json','["久別重逢笑脫頤，休談愁緒殺腰圍。", "不如意處人人有，未放心時事事非。", "蔬筍家風難以住，鶑花天氣速人歸。", "歸囊强半詩材具，莫怪齊眉不下機。"]'),
('290f702e-7d2d-4048-b8c9-3e903be51f96','崇安葉簿之先大夫易學得于天而未傳于人余竊于執事聞焉幸矣敢以相期之意併賦長句呈似','曾丰','宋','宋诗','song-poetry','','[]','夢與神遊會自然，廼翁于易發先天。',64,'全唐诗/poet.song.163000.json','["夢與神遊會自然，廼翁于易發先天。", "東周以上更三聖，南渡而來第一傳。", "入室飽參誰舍瑟，過庭精意自忘筌。", "勾稽小詘論思具，行侍玉皇香案前。"]'),
('f77b89d7-f165-4507-9c5f-8fa0a21944d9','贈楊持正','曾丰','宋','宋诗','song-poetry','','[]','國初天下一文公，子豈他楊未襲封。',64,'全唐诗/poet.song.163000.json','["國初天下一文公，子豈他楊未襲封。", "大地江山資本領，長天風雨發機鋒。", "齊門不分輕彈瑟，魯廟何當細奏鏞。", "未有可分和氣處，薰然煦甚自喬松。"]'),
('b1f46496-ad63-4ea2-9fc4-5fbd97e2a2aa','南峰寺勸農','曾丰','宋','宋诗','song-poetry','','[]','隊吏衙官出勸農，前驅亭午駐南峯。',64,'全唐诗/poet.song.163000.json','["隊吏衙官出勸農，前驅亭午駐南峯。", "香烘貯霧含雲鼻，茶盪吞江納漢胸。", "柳自放慵乘困思，花相學醉弄嬌容。", "老人莫答韶光意，盡量相陪酒一鍾。"]'),
('0ff48bb2-f14a-477d-941c-a4378472b66c','寄孫學長孝思','曾丰','宋','宋诗','song-poetry','','[]','短檠方冊不增窮，窮到無錐文字工。',64,'全唐诗/poet.song.163000.json','["短檠方冊不增窮，窮到無錐文字工。", "與我心同如印印，使人意快似風風。", "江山信筆機之熟，天地忘懷氣所充。", "耆舊錄中書隠德，其他無以易龐公。"]'),
('e7773b34-4cde-4ea4-bec5-fe4603456823','丙辰十月風日積煖浙間花卉俱開','曾丰','宋','宋诗','song-poetry','','[]','廣東冬氣作春蒸，浙土如之得我驚。',64,'全唐诗/poet.song.163000.json','["廣東冬氣作春蒸，浙土如之得我驚。", "桃李猖狂爭竊發，昆蟲齷齪學微行。", "向南柳可爲先進，投北梅猶是後生。", "物理乘除自相補，速成未必似遲成。"]'),
('53e16f2e-6329-450c-a24f-b0a375e26377','窮冬征途觸目省身','曾丰','宋','宋诗','song-poetry','','[]','青陽用事到玄冥，萬彙營營幸歲成。',64,'全唐诗/poet.song.163000.json','["青陽用事到玄冥，萬彙營營幸歲成。", "霜雪不仁偏嗜殺，松筠有道善含生。", "巢居凍鵲常高遁，血食饑鷹輒下爭。", "自反吾其不攖物，懸知物亦不吾攖。"]'),
('831fad11-9a34-48ab-a940-47ed662a5dd8','上時相','曾丰','宋','宋诗','song-poetry','','[]','閶闔初開黄道乾，貂蟬屹立侍中冠。',64,'全唐诗/poet.song.163000.json','["閶闔初開黄道乾，貂蟬屹立侍中冠。", "天高莫共星辰貴，地厚雖遥動植安。", "萬物有歸元氣足，一毛無外太虛寬。", "相期淺淺非相愛，稷契臯陶頭上看。"]'),
('0666effb-89c7-4910-a0e9-8c35c445d092','歐陽全真爲贛佐先余去越七年又爲廣漕屬後余至己酉會于中都','曾丰','宋','宋诗','song-poetry','','[]','東都重會省初盟，爾許多年獨不驚。',64,'全唐诗/poet.song.163000.json','["東都重會省初盟，爾許多年獨不驚。", "二水牘中先署字，三城碑上復題名。", "往還必有子孫契，離合面無兒女情。", "功業相期非老事，願言仙佛學俱成。"]'),
('7474f749-9e6c-4bc6-bfa9-fb0b5d19c0b6','歐陽全真改秩得邑欲其循循爲之無效余尤','曾丰','宋','宋诗','song-poetry','','[]','銓法如毛動見繩，通班歲許幾人登。',64,'全唐诗/poet.song.163000.json','["銓法如毛動見繩，通班歲許幾人登。", "銅章未有路能脫，鶴髮不無機可乘。", "長策報君簪袚忌，短檠忘本簡編憎。", "相期循吏傳中事，循吏傳中無所稱。"]'),
('315cae8f-0e0d-4c1f-8b40-e2ccf283a263','賦桃李花  其一','曾丰','宋','宋诗','song-poetry','','[]','盤根玉嶺氣形全，擢秀霜林雨露偏。',64,'全唐诗/poet.song.163000.json','["盤根玉嶺氣形全，擢秀霜林雨露偏。", "傾國笑容斜媚日，惱人香氣上薰天。", "禪僧悟道疑爲佛，漁父迷途似得仙。", "印可幾人成白業，自身寧久墊塵緣。"]'),
('ee67ea49-524b-4a03-a00a-518d195cda58','賦桃李花  其二','曾丰','宋','宋诗','song-poetry','','[]','春風已暢上林枝，况得連朝雨發揮。',64,'全唐诗/poet.song.163000.json','["春風已暢上林枝，况得連朝雨發揮。", "越女嬌紅純任白，楊妃懲瘦少教肥。", "微風遠送難言意，亂蝶潜生不肖機。", "本是鍾山瀛渚骨，猶容蛻濁刺空飛。"]'),
('f99de6af-7273-4de0-b4d7-ae85ad2d1a21','題文晉卿明齋','曾丰','宋','宋诗','song-poetry','','[]','磨礱抆拭費詩書，一點靈光與道俱。',64,'全唐诗/poet.song.163000.json','["磨礱抆拭費詩書，一點靈光與道俱。", "不缺不圓涵霽月，無中無表澈冰壺。", "真機已熟虛生白，幻法寧容紫亂朱。", "照物之餘時反照，故吾殊不似今吾。"]'),
('a85e3417-4145-4cfc-a22c-b439b58fe3ed','謝黄秀才則惠詩','曾丰','宋','宋诗','song-poetry','','[]','義根理密有餘功，更學商周雅頌風。',64,'全唐诗/poet.song.163000.json','["義根理密有餘功，更學商周雅頌風。", "收拾江山開闢後，歸藏情性混成中。", "天私北道君心足，鬼發其藏我眼空。", "歸與友朋笑相賀，江西後社有人同。"]'),
('840887f5-03c2-433d-afa0-589293d7b54e','涂漢英學詩二十餘年矣挾近作來示賞歎之次俾更印可諸公間','曾丰','宋','宋诗','song-poetry','','[]','三厄五窮能養詩，養之成熟氣混夷。',64,'全唐诗/poet.song.163000.json','["三厄五窮能養詩，養之成熟氣混夷。", "不知胸次是三代，可與筆端爲四時。", "收拾性情歸大樸，發揮風月出多儀。", "勘符容有一未合，更把大通相轉移。"]'),
('28a3c547-43cf-424f-a34f-3cc1633f5af4','李叔度與兒曹談理道余竊聽而記以一詩','曾丰','宋','宋诗','song-poetry','','[]','天地未分先立經，自吾道外豈常情。',64,'全唐诗/poet.song.163000.json','["天地未分先立經，自吾道外豈常情。", "伊周孔子直方大，堯舜文王純粹精。", "新犢生時無次剌，白羊熟後可縱橫。", "有言終與一爲二，予欲無言是混成。"]'),
('47c13759-9b56-40fa-9e5f-ef80409b6a23','送歐陽瑩中往湖南謁卿漕','曾丰','宋','宋诗','song-poetry','','[]','幾回雙脚爲親輕，未饜其親銳此行。',64,'全唐诗/poet.song.163000.json','["幾回雙脚爲親輕，未饜其親銳此行。", "白面書生誰一顧，繡衣使者自多情。", "祝融雨後山歸潔，彭蠡秋來水中清。", "收拾還家自金玉，從渠喚我太高生。"]'),
('6b8d5f91-9f4c-4a10-b85e-8468fadc77a9','送夏國寶','曾丰','宋','宋诗','song-poetry','','[]','螺山螺水愛其英，屬者分之太少生。',64,'全唐诗/poet.song.163000.json','["螺山螺水愛其英，屬者分之太少生。", "不啻海涵胸次大，猶賢泉湧筆端清。", "百年事已餘長慮，千古功猶欠大成。", "歸覓知音振貧顇，重來參我勘希聲。"]'),
('b2e191cb-baf6-49a8-8e95-d2fd3321f8b0','謝宜黄樂奇卿投詩','曾丰','宋','宋诗','song-poetry','','[]','大初分氣入三才，詩與吾生一處來。',64,'全唐诗/poet.song.163000.json','["大初分氣入三才，詩與吾生一處來。", "胸次融教成樂國，筆頭點出是春臺。", "摘君句眼詩三復，撩我吟腸月久回。", "機械相投意相得，交盟不結自陳雷。"]'),
('21b5402a-8c26-4165-926a-63e70f2a14fd','贈鄔文伯','曾丰','宋','宋诗','song-poetry','','[]','詩與時投未救饑，君詩况復不投時。',64,'全唐诗/poet.song.163000.json','["詩與時投未救饑，君詩况復不投時。", "紛紛噲等揶揄甚，堇堇顔徒從臾之。", "雅頌國風歸雋永，簞瓢陋巷付讎夷。", "更充以易卒忘物，與自然遊了不知。"]'),
('735fb235-0db0-4586-8681-7268fb83d680','贈陰陽家聶蒙德','曾丰','宋','宋诗','song-poetry','','[]','陰陽家者太高生，見謂青囊未是經。',64,'全唐诗/poet.song.163000.json','["陰陽家者太高生，見謂青囊未是經。", "舌卷東南諸海水，胸羅西北一天星。", "與人後代爲長吉，疑爾前身是巨靈。", "莫把山川爲道看，山川猶是未離形。"]'),
('befcca1d-434d-435e-8f4d-62804017b1aa','李熙載業儒未效轉爲五行家','曾丰','宋','宋诗','song-poetry','','[]','典謨訓誥飽蟠胸，一字于君未有功。',64,'全唐诗/poet.song.163000.json','["典謨訓誥飽蟠胸，一字于君未有功。", "參到五行劉子政，轉爲三命李虛中。", "牛毛有底事非左，蝸角孰何人不東。", "肯自戚施相從臾，片言可送半生窮。"]'),
('a28db5b6-6568-4963-b3e4-c191bd50d04e','垂絲海棠','曾丰','宋','宋诗','song-poetry','','[]','春風場裏一嬋娟，情性脂韋氣力綿。',64,'全唐诗/poet.song.163000.json','["春風場裏一嬋娟，情性脂韋氣力綿。", "外不自持如醉者，中無他歉若羞然。", "避風皇后身傾靡，承露仙人手覆懸。", "正恐梅知固相聘，含香自嗅不容傳。"]'),
('8241915a-3093-4ceb-a5c0-34847d1f610e','題李子權江月亭','曾丰','宋','宋诗','song-poetry','','[]','太陰元是水之精，與水相宜妙莫名。',64,'全唐诗/poet.song.163000.json','["太陰元是水之精，與水相宜妙莫名。", "霽夜懸芒翻浪白，澄秋逗彩湧流清。", "冰輪影裏山河見，玉鑑光中星斗明。", "萬象主人收拾盡，一樽酬罷一詩成。"]'),
('fcab6634-54fc-42a2-b3d3-8217151e8b2f','吾宗翔叔學詩知方矣與之商榷次勉之蹈大方焉','曾丰','宋','宋诗','song-poetry','','[]','浩劫以來無限詩，牢籠收拾若爲齊。',64,'全唐诗/poet.song.163000.json','["浩劫以來無限詩，牢籠收拾若爲齊。", "未離聲病即爲韻，猶涉色塵皆是題。", "三代後無非濮上，百年前豈有江西。", "子其高出諸公右，恐太高時少放低。"]'),
('095a0638-976a-4f18-a7c2-9fcba567993f','送五行家唐克壽','曾丰','宋','宋诗','song-poetry','','[]','初心半信術家流，百諾于茲未一酬。',64,'全唐诗/poet.song.163000.json','["初心半信術家流，百諾于茲未一酬。", "一行無非占不驗，北平終是命難侯。", "雲霄許我乘南鵠，江海教誰伴白鷗。", "季主遊方逢賈誼，慇懃勉爲漢家謀。"]'),
('3bd1c32c-990b-4a40-a6d7-dfe08bbe9d3e','過快閣','曾丰','宋','宋诗','song-poetry','','[]','一回艤艦一翛然，境界非凡人是仙。',64,'全唐诗/poet.song.163000.json','["一回艤艦一翛然，境界非凡人是仙。", "山是平沉眠吐月，江如倒激仰吞天。", "宜州乃事一朝去，快閣之詩千古傳。", "正恐癡兒小癡耳，大癡身自與名全。"]'),
('2db771aa-5c4a-491f-9c6e-db042eb37d5f','赴瓊州次大蓼灘風雨交作寒未艾也其勢欲雪  其一','曾丰','宋','宋诗','song-poetry','','[]','僕僕漫郎蹤跡孤，星星迂叟髮毛疏。',64,'全唐诗/poet.song.163000.json','["僕僕漫郎蹤跡孤，星星迂叟髮毛疏。", "三千里外辭鄉後，十八灘前問宿初。", "山未容雲思底麗，風猶與雪議權輿。", "有蒲團在不能享，吾策從初悔讀書。"]'),
('42e449fa-538b-4a46-8a8f-5ee03274fca4','赴瓊州次大蓼灘風雨交作寒未艾也其勢欲雪  其二','曾丰','宋','宋诗','song-poetry','','[]','挈家隨牒一陽初，視險如夷舟當車。',64,'全唐诗/poet.song.163000.json','["挈家隨牒一陽初，視險如夷舟當車。", "贛石罅中漁路寢，楚天包處燕蘧廬。", "木無棄本藏于密，江不辭流受以虛。", "萬物外吾詩者少，惜乎南燕久歸歟。"]'),
('e9a793cc-3330-4f32-b358-c04103cdee61','慶元六年七月至儋耳問前守之政改元四年罷歸八月過封川謁譚史君乃前守也用賦二長韻呈似  其一','曾丰','宋','宋诗','song-poetry','','[]','小詘南遊得大觀，天函無際碧相環。',64,'全唐诗/poet.song.163000.json','["小詘南遊得大觀，天函無際碧相環。", "盤黎錯䝤周遭海，亙縣綿州詭譎山。", "自幸賞音毛穎下，相爭充數錦囊間。", "更無可以重收拾，莫怪吾詩今次慳。"]'),
('5b442445-df90-4e5d-9798-e74939b04ac4','慶元六年七月至儋耳問前守之政改元四年罷歸八月過封川謁譚史君乃前守也用賦二長韻呈似  其二','曾丰','宋','宋诗','song-poetry','','[]','吾輕瘴海易烟嵐，去歲今辰訪古儋。',64,'全唐诗/poet.song.163000.json','["吾輕瘴海易烟嵐，去歲今辰訪古儋。", "壹意良民誰似漢，百年循吏莫如譚。", "鶚書已費幾將上，熊軾猶便再落南。", "報政不須入郎選，上方濡筆與公簪。"]'),
('f3e6bf34-5f22-4681-b0d1-25bd1cf50e97','從北流入鬰林望月巖','曾丰','宋','宋诗','song-poetry','','[]','青山罅外見青天，翡翠屏間一鏡懸。',64,'全唐诗/poet.song.163000.json','["青山罅外見青天，翡翠屏間一鏡懸。", "表裏集虛生至白，初終持滿得長圓。", "光明照處人心足，混沌開時物理全。", "它義多慳茲獨否，天無偏意有時偏。"]'),
('a86a02cf-2cde-4346-9a97-1ce591c386e7','題貴州南山巖','曾丰','宋','宋诗','song-poetry','','[]','崒嵂窮頭與漢齊，谽谺深處著招提。',64,'全唐诗/poet.song.163000.json','["崒嵂窮頭與漢齊，谽谺深處著招提。", "居焉若寢瓊爲室，登者如仙玉作梯。", "雲竅旁通吞日月，烟蘿倒拔挂虹蜺。", "我來已落葛翁後，姑拾其餘細品題。"]'),
('818c6cfb-4c77-4ef3-ad0a-d369503f68e5','長韻示阿柄杓在韶遣行','曾丰','宋','宋诗','song-poetry','','[]','遭罹意外罷微官，更被歸途瘴見奸。',64,'全唐诗/poet.song.163000.json','["遭罹意外罷微官，更被歸途瘴見奸。", "僕從阽危諳遣鬼，妻孥瀕死謝還丹。", "回頭海表山如許，屈指江西路若干。", "先遣一書報兒輩，吾其老矣幸平安。"]'),
('0bef5363-bf91-4234-a851-f9b44f20d754','丁未遊碧落洞庚申舟行欲再遊不果','曾丰','宋','宋诗','song-poetry','','[]','奇觀曾邀我命車，回車人問景何如。',64,'全唐诗/poet.song.163000.json','["奇觀曾邀我命車，回車人問景何如。", "山經盤古穿窬後，水據玄冥漏泄初。", "勝跡遺留名利輩，塵心昭雪市朝餘。", "重來雲霧不容入，魚烏相嗔太闊疏。"]'),
('037fb4e5-a04e-4b4a-8581-49d313ca0ea3','渡海謁兩伏波將軍祠','曾丰','宋','宋诗','song-poetry','','[]','長安百二漢山河，更遣南征兩伏波。',64,'全唐诗/poet.song.163000.json','["長安百二漢山河，更遣南征兩伏波。", "自計有何饒社稷，相尋無已枉干戈。", "一時夸大心難制，千載英雄跡未磨。", "逐客乞靈幾前輩，豐碑費我小摩挲。"]'),
('9d0db457-8335-4c77-b6a0-f57fe2a1c404','北歸見攝徐聞邑大夫乃舊同官邵雩都之子予詩敘契','曾丰','宋','宋诗','song-poetry','','[]','贛邑交遊十大夫，忘情詩酒邵雩都。',64,'全唐诗/poet.song.163000.json','["贛邑交遊十大夫，忘情詩酒邵雩都。", "籋雲矯矯新龍友，栖竹亭亭舊鳳雛。", "燕馬北歸休晚念，海鵬南運壯初圖。", "雲來後好今分付，車笠重盟幸勿渝。"]'),
('2de99949-855c-4225-a435-6e447cf8c51f','四月解官渡海陸出北流置舟在南雄又陸出擬小春到家','曾丰','宋','宋诗','song-poetry','','[]','歸心如矢路如弓，坐兀輕車又短篷。',64,'全唐诗/poet.song.163000.json','["歸心如矢路如弓，坐兀輕車又短篷。", "百爾動摇山特立，千斯窒礙水旁通。", "往哉火倒西流影，行矣霜迴北至風。", "細數離官到家日，一年强半在途中。"]'),
('bbf0a323-87db-4177-b385-de554cbedb06','北歸舟次清遠縣上遊欲入硤','曾丰','宋','宋诗','song-poetry','','[]','舟行所至與清逢，殊覺今清又不同。',64,'全唐诗/poet.song.163000.json','["舟行所至與清逢，殊覺今清又不同。", "山到江湄窮則變，水歸峻口窒斯通。", "秋風鏖葉地頻顣，夜月鑠雲天屢空。", "兀坐篷窗閑四顧，太虛還似我胸中。"]'),
('b9e13477-44d8-4fc5-8059-345936eca5cb','思堂詩','曾丰','宋','宋诗','song-poetry','','[]','新築謀爲老者安，落成誰料莫近軒。',64,'全唐诗/poet.song.163000.json','["新築謀爲老者安，落成誰料莫近軒。", "月窺窗牖如顔色，風戰簾帷若笑言。", "懷裏寂寥霜後橘，階前蕭瑟雨餘萱。", "榮途他日饒榮報，亡矣吾知不啻存。"]'),
('c5f6105a-3b1d-4047-9cb5-e7e0a069d4a5','項堯章惠二長韻姑賡前篇敬復','曾丰','宋','宋诗','song-poetry','','[]','飄然逸思發于天，三百年間一謫仙。',64,'全唐诗/poet.song.163000.json','["飄然逸思發于天，三百年間一謫仙。", "歌調誰歟追白雪，頌聲行矣擅甘泉。", "山林新築夢歸處，學校舊遊愁到邊。", "回首不堪更開口，相過聊復茗甌傳。"]'),
('90ccccde-716f-4def-8350-845235ebd10f','欲入脩門未果且留妙山逆旅書所見呈富陽大夫陳晃國','曾丰','宋','宋诗','song-poetry','','[]','詩肩重與轂塵摩，旁縣孤村邀我過。',64,'全唐诗/poet.song.163000.json','["詩肩重與轂塵摩，旁縣孤村邀我過。", "晏晝江山開調遠，晴宵星月照臨多。", "眼爲幻使不由我，心與空俱無復它。", "百里一輪大圓鏡，發匳開幭鑑如何。"]'),
('46273dbc-1c14-4955-bdff-b2f390b92676','富陽陳大夫遣二吏抄俚文用寫道寓于文之意還以請益','曾丰','宋','宋诗','song-poetry','','[]','道固無方實以書，要于書悟道之虛。',64,'全唐诗/poet.song.163000.json','["道固無方實以書，要于書悟道之虛。", "雷風水火易經始，草木魚蟲詩緒餘。", "萬理所歸爲寶藏，一真之外是蘧廬。", "俚編道欲相磋切，不道亡筌自得魚。"]'),
('aa71b0f7-a873-4409-bd8e-68d323769738','前仁和鄭宰僑富陽與陳宰往還以詩余寓妙山得其所和詩後復寄一篇','曾丰','宋','宋诗','song-poetry','','[]','宣化承流退自公，優柔厭飫有新功。',64,'全唐诗/poet.song.163000.json','["宣化承流退自公，優柔厭飫有新功。", "先天勘破道玄牝，後社推爲詩長雄。", "情性唐虞三代上，篇章韶濩六䪫中。", "河汾所續吾其再，首錄東吳兩國風。"]'),
('5ccdfda5-eff1-4b23-a38f-a6b66b6cbcf7','前仁和鄭大夫載酒携文過我妙山逆旅中','曾丰','宋','宋诗','song-poetry','','[]','過我跫然驚見君，無容膝處接殷勤。',64,'全唐诗/poet.song.163000.json','["過我跫然驚見君，無容膝處接殷勤。", "火乘雲氣下爲祟，風挾水聲來解紛。", "酒榼自隨酣盛德，茶甌相繼醒新聞。", "黄扉青瑣從今去，大策清時翰墨勳。"]'),
('13a78ed9-be03-4646-afa7-9efb0bc90867','和富陽陳大夫禱雨有感韻  其一','曾丰','宋','宋诗','song-poetry','','[]','千里羈懷那更秋，一陪行樂一忘憂。',64,'全唐诗/poet.song.163000.json','["千里羈懷那更秋，一陪行樂一忘憂。", "看君俶儻足誰柅，顧我輪囷枝一虯。", "卓令下車宣漢詔，周王前籍訪箕疇。", "拔茅切不須連茹，吾自胸中有一丘。"]'),
('ce8c389b-28d2-48a3-8923-766c6e61f3ca','和富陽陳大夫禱雨有感韻  其二','曾丰','宋','宋诗','song-poetry','','[]','刑鵝甕蜥敬祈秋，要解宵衣旰食憂。',64,'全唐诗/poet.song.163000.json','["刑鵝甕蜥敬祈秋，要解宵衣旰食憂。", "天上大方張掣電，地中雷已起蟠虯。", "霧雹黄長堯天水，䆉䅉青連鄭非蠻。", "告違只上加餐祝，更祝俸餘歸買山。"]'),
('2b545da9-cdbf-4813-ba74-f514a26bb656','贈姚季安','曾丰','宋','宋诗','song-poetry','','[]','七年三度奉從容，今見吾驚大不同。',64,'全唐诗/poet.song.163000.json','["七年三度奉從容，今見吾驚大不同。", "雲霧蟠胸蒸疾雨，雷霆挾筆駕長風。", "懸知文與意俱到，政要眼隨心併空。", "度嶺重參過庭學，歸歟容更驗新功。"]'),
('171470a9-e000-4c35-ae7a-7ce3b308c71e','題南海神祠前觀瀾亭','曾丰','宋','宋诗','song-poetry','','[]','巨靈開闢遺遐觀，沙界之瀕碧水環。',64,'全唐诗/poet.song.163000.json','["巨靈開闢遺遐觀，沙界之瀕碧水環。", "外國連天疑信裏，前山點地有無間。", "眼前群有自起滅，心與太空相往還。", "至止歸歟何所得，心猶有剩覺空慳。"]'),
('46e0113e-422c-41da-a467-70ea0b4a11e7','舟行赴廣倅書所見示阿槿','曾丰','宋','宋诗','song-poetry','','[]','南景所陳詩所須，彼無盡藏入吾儲。',64,'全唐诗/poet.song.163000.json','["南景所陳詩所須，彼無盡藏入吾儲。", "百川送海成其大，萬竅迎風受以虛。", "敏則有功鷹得兔，勞而無怨獺求魚。", "物華切莫遺毫末，兒輩還猶要緒餘。"]'),
('136c964c-a4ec-47d9-ba0b-798831f9fba9','道旁有松爲人所刳伐因自弔且慰焉','曾丰','宋','宋诗','song-poetry','','[]','稚時蔚蔚老椮椮，羞與其他木作林。',64,'全唐诗/poet.song.163000.json','["稚時蔚蔚老椮椮，羞與其他木作林。", "獨以高風資衆望，終爲明德累初心。", "不容節抗皇天峻，猶幸根盤后土深。", "自有茯苓堪自壽，願言黄帝勿幽尋。"]'),
('dffc5b93-d5c2-4591-8f71-a624420a098c','題朱虞卿自懶','曾丰','宋','宋诗','song-poetry','','[]','天不與吾山水幽，却于何處小藏脩。',64,'全唐诗/poet.song.163000.json','["天不與吾山水幽，却于何處小藏脩。", "清風吾有術堪召，俗物自無機可投。", "朝市眼爲方冊制，利名心與曲國疇。", "令尹功成民所祝，雙鳬歸路在三丘。"]'),
('e8c494fb-4042-441b-9e3e-9d4f177fd188','淳熙丙午與閤皂化士彭正夫道人五羊相別開禧乙丑復會于五羊贈二長韻  其一','曾丰','宋','宋诗','song-poetry','','[]','自視其身不繫秋，片心寧被白雲留。',64,'全唐诗/poet.song.163000.json','["自視其身不繫秋，片心寧被白雲留。", "發蹤江右山青處，游睇海南天盡頭。", "勾漏砂星光燦夜，羅浮竈爐冷含愁。", "鼎新革故丹成後，乘興逍遥汗漫遊。"]'),
('29a191f0-65f1-493c-8364-5ad57916e78c','淳熙丙午與閤皂化士彭正夫道人五羊相別開禧乙丑復會于五羊贈二長韻  其二','曾丰','宋','宋诗','song-poetry','','[]','抗塵騎氣兩虛舟，久別重逢幸小留。',64,'全唐诗/poet.song.163000.json','["抗塵騎氣兩虛舟，久別重逢幸小留。", "自分末留輕著脚，相期初度急回頭。", "我嘗黄嬭真無味，若種丹田乃有秋。", "所向殊途所歸一，他遊無以易天遊。"]'),
('9ffd7cd8-8883-4342-8d0f-0115e6be9505','辛酉冬罷歸至家自省','曾丰','宋','宋诗','song-poetry','','[]','彼哉言者固云云，老矣歸歟敢自文。',64,'全唐诗/poet.song.163000.json','["彼哉言者固云云，老矣歸歟敢自文。", "不可以風霜後葉，何傷于月雨餘雲。", "性情與物常爲一，鷗鷺容吾便入羣。", "古道從來得今笑，天相知外任紛紛。"]'),
('a161f089-67d3-40cf-a224-93255ec4e950','送段文子之桂陽','曾丰','宋','宋诗','song-poetry','','[]','瘦筇輕撥火雲開，前若相招後若推。',64,'全唐诗/poet.song.163000.json','["瘦筇輕撥火雲開，前若相招後若推。", "康樂蒼梧充史具，祝融彭蠡效詩材。", "况餘湘水故人在，曾爲阮家青眼來。", "囊正自枵我輒癭，好音聽與雁俱回。"]'),
('8977bd3a-d295-4c4b-948d-8fc7ef876070','贈郭雄李','曾丰','宋','宋诗','song-poetry','','[]','八載交盟尚未寒，相逢何處再開顔。',64,'全唐诗/poet.song.163000.json','["八載交盟尚未寒，相逢何處再開顔。", "互隨宦牒往來次，俱在梅關南北間。", "臧若諱忘誰是穀，觸如爭勝孰肱謀。", "高軒有叩北窗問，人在羲皇上一頭。"]'),
('17e9b84e-f281-46bb-a3c4-24d1648cec22','廣州登蓋海樓','曾丰','宋','宋诗','song-poetry','','[]','他求無可洗塵勞，蓋海樓餘百尺高。',64,'全唐诗/poet.song.163000.json','["他求無可洗塵勞，蓋海樓餘百尺高。", "十萬人烟城繚繞，三千世界水週遭。", "偏于物外有雙眼，正以胸中無一毫。", "非與海鷗强相入，海鷗元自是吾曹。"]'),
('ae9f207f-0b33-493e-bb5b-326e6737b3c8','五羊七月閑賦','曾丰','宋','宋诗','song-poetry','','[]','二十年前到已曾，今雖重到眼猶生。',64,'全唐诗/poet.song.163000.json','["二十年前到已曾，今雖重到眼猶生。", "海無棄水歸斯受，山不留雲用則行。", "去雁來鴻如互避，稚金老火若交爭。", "天機養至相忘處，物意天心兩太平。"]'),
('67bdc69f-7987-4690-a47b-251746cd1dbf','赴晉康有感','曾丰','宋','宋诗','song-poetry','','[]','辟書未上意躊躇，蠻障無望車騎都。',64,'全唐诗/poet.song.163000.json','["辟書未上意躊躇，蠻障無望車騎都。", "允矣曲從人慫惥，往哉聊避鬼揶揄。", "來鴻告至其欺我，去雁辭行蓋啟予。", "南驥厭嘶自懷土，東思初不待蓴鱸。"]'),
('cff7c1e2-7d95-4af9-a72a-2ef5f89a1653','答厲季平投詩有懷歸鄉之意','曾丰','宋','宋诗','song-poetry','','[]','詞場凡馬洗之空，學海波中得老龍。',64,'全唐诗/poet.song.163000.json','["詞場凡馬洗之空，學海波中得老龍。", "尚韻許人賡白雪，正聲惟我識黄鐘。", "素王不作無明主，賤子何之可附庸。", "烏鵲正茲徒遶樹，鷦鷯還更乞相容。"]'),
('ae044ad9-8c84-474c-93ec-7bc682c19f1e','續演雅','曾丰','宋','宋诗','song-poetry','','[]','徐行竢命退風鷁，决起乘時遷木鶑。',64,'全唐诗/poet.song.163000.json','["徐行竢命退風鷁，决起乘時遷木鶑。", "秋隼巧爲非義取，夜蛩工作不平鳴。", "行歸寡悔蟻知雨，言至數窮鳩喚晴。", "惟有冥鴻自高上，茲其不可得而名。"]'),
('736933ef-5f39-4c40-97e0-95292a8aaf61','贈陳養廉居士','曾丰','宋','宋诗','song-poetry','','[]','身後相多清議同，大歸何者是家風。',64,'全唐诗/poet.song.163000.json','["身後相多清議同，大歸何者是家風。", "輕財笑餽三千客，重道爭祠六一公。", "門未生苔車跡滿，館無廢帚榻塵空。", "有人能繼碑中美，不與石相爲始終。"]'),
('4858c203-9fd5-426f-a24f-058f03733966','挽王撫幹','曾丰','宋','宋诗','song-poetry','','[]','江左風流跡已陳，故家餘韻更何人。',64,'全唐诗/poet.song.163000.json','["江左風流跡已陳，故家餘韻更何人。", "雲霄浩蕩開雛鳳，歲月崢嶸逼老椿。", "三釜未終身大暮，九泉無憾意長春。", "北邙山下重回首，片玉空懷萬古塵。"]'),
('24aad490-bc31-42d1-b80f-997f47453657','挽林益之母','曾丰','宋','宋诗','song-poetry','','[]','所天之托半途蹉，剛把初心與歲磨。',64,'全唐诗/poet.song.163000.json','["所天之托半途蹉，剛把初心與歲磨。", "家法子孫多令器，門風文武兩殊科。", "猶餘三釜似榮矣，未拜五花如命何。", "自有彤編爲不朽，斷機那枉費工夫。"]'),
('6bc7791f-7972-400f-ac51-e34a11f2f4ba','代人挽王待制','曾丰','宋','宋诗','song-poetry','','[]','盤盤胸次五車書，凜凜朝端烈丈夫。',64,'全唐诗/poet.song.163000.json','["盤盤胸次五車書，凜凜朝端烈丈夫。", "詭道至前無肯可，危言及上有都俞。", "熊羆聲撼據關虎，鷹隼氣吞憑社狐。", "遺直莫容遺愛在，王公名字與湖俱。"]'),
('9b802710-a535-4b69-a3d5-8e1eff73207f','二月三日至薌山寺劉薰卿在焉','曾丰','宋','宋诗','song-poetry','','[]','置身松下莫忘塵，况在松之上置身。',64,'全唐诗/poet.song.163000.json','["置身松下莫忘塵，况在松之上置身。", "荒壘中盤平卧斗，澄江外抱曲拖紳。", "春熙天色如初醉，烟肅山容若半顰。", "晉郡猶餘晉時事，幽人疑是避秦人。"]'),
('4189e6dd-b884-4c9d-9e68-8abf144f6464','送劉薰卿','曾丰','宋','宋诗','song-poetry','','[]','未曾得雋利名場，猶敢犯危烟瘴鄉。',64,'全唐诗/poet.song.163000.json','["未曾得雋利名場，猶敢犯危烟瘴鄉。", "大庾嶺高梅挺拔，東莞天遠海汪洋。", "其凡飽以史收拾，所異剛于詩主張。", "歸數群雄可雌視，麒麟誰得礙康莊。"]'),
('65c42b41-5060-44c5-a8a9-4555aee8f126','假守晉康出郊勸農  其一','曾丰','宋','宋诗','song-poetry','','[]','笑下籃輿上畫船，百千詩具已遮前。',64,'全唐诗/poet.song.163000.json','["笑下籃輿上畫船，百千詩具已遮前。", "川通諸海滔滔是，魚躍于淵圉圉然。", "雲出山頭猶閣雨，風行水面不停烟。", "囊中隨意亂收拾，容了勸農歸細編。"]'),
('397eec1d-2229-4e8e-a422-71ef11e1e5a9','假守晉康出郊勸農  其二','曾丰','宋','宋诗','song-poetry','','[]','小隊近郊初省春，杯盤綿蕝意殷勤。',64,'全唐诗/poet.song.163000.json','["小隊近郊初省春，杯盤綿蕝意殷勤。", "叮嚀通國老和少，黽勉及時耕且耘。", "賣劍爾行移爾俗，買山吾退了吾文。", "試于農圃相尋認，果是康州舊使君。"]'),
('4e22f65c-7933-4a62-ac45-146d80981692','郡齋與龔濟叔劉薰卿談詩','曾丰','宋','宋诗','song-poetry','','[]','其奈魚蟲草木何，詩之機械也無多。',64,'全唐诗/poet.song.163000.json','["其奈魚蟲草木何，詩之機械也無多。", "氣猶動志平心養，聲可成文泛口哦。", "玄酒太羹君子淡，蕢桴土鼓聖人和。", "鬼神天地與吾一，相感相通豈在他。"]'),
('30e850ef-519f-469f-adbe-32085c62f084','郡齋與濟叔薰卿論文','曾丰','宋','宋诗','song-poetry','','[]','著書夫豈易乎云，不自鞭心不策勳。',64,'全唐诗/poet.song.163000.json','["著書夫豈易乎云，不自鞭心不策勳。", "望道初猶未之見，言天終可得而聞。", "囿于有極非皇極，概以無文是至文。", "萬一未能全免俗，寧爲八卦易三墳。"]'),
('af172bcf-9fd6-4d3c-b410-40b0473151ea','題豁然亭','曾丰','宋','宋诗','song-poetry','','[]','恍如仙去忘來蹤，意者騎鯨否馭風。',64,'全唐诗/poet.song.163000.json','["恍如仙去忘來蹤，意者騎鯨否馭風。", "從使一身群有外，委蛇雙眼太虛中。", "從教寶藏空華蓋，自與河沙色界融。", "道是豁然猶未是，豁然無色也無空。"]'),
('245d0466-9403-4bcb-b715-27279520ff97','續演雅','曾丰','宋','宋诗','song-poetry','','[]','臨川戰戰渴飲水，行道遲遲飽食牛。',64,'全唐诗/poet.song.163000.json','["臨川戰戰渴飲水，行道遲遲飽食牛。", "促織貪爲先具計，提壺欠作豫防謀。", "知風鵲備全無患，報雨鳩言半不酬。", "惟有海鷗忘物我，何思何慮任沉浮。"]'),
('9f3d4d60-415e-4f35-ab0e-d06d9d4fa3a8','戊辰閏月晉康久不雨上弦日禱于聖妃諸祠拜罷雨作連日沾洽倅車陳賦詩次韻謝答','曾丰','宋','宋诗','song-poetry','','[]','兩鬢閑時爲國蒼，况乘五馬小騰驤。',64,'全唐诗/poet.song.163000.json','["兩鬢閑時爲國蒼，况乘五馬小騰驤。", "方當赤地頞皆顣，據爾黄堂心獨凉。", "雷雨影從千里快，犁鋤忽起一時忙。", "少寬郡守漢丞責，幸不空餐粟一囊。"]'),
('361ad784-295b-4165-919f-e7e8e64e0277','歲在己未與南康宰周丈君可相別至戊辰復會于晉康次所惠韻謝之','曾丰','宋','宋诗','song-poetry','','[]','君詩他莫與同年，絕岸孤峯自一邊。',64,'全唐诗/poet.song.163000.json','["君詩他莫與同年，絕岸孤峯自一邊。", "氣質乾坤方判後，規模風雅未刪前。", "相思鑑裏縻旬歲，自稔囊中擘一篇。", "留與江西爲後社，子孫不敢作私傳。"]'),
('969d5013-1a3d-4988-a72f-ba159e0bf8a5','公餘出晉康亭小憩','曾丰','宋','宋诗','song-poetry','','[]','客來非與景相期，萬象殷勤自四圍。',64,'全唐诗/poet.song.163000.json','["客來非與景相期，萬象殷勤自四圍。", "山以出雲爲顯設，江于朝海得依歸。", "沙嵐昏墊雨湔祓，烟水汩陳風發揮。", "公退云胡不私省，潜魚幽鳥也知機。"]'),
('058a69ec-d494-466a-b0be-046ddf52df11','敬簡堂觀蓮','曾丰','宋','宋诗','song-poetry','','[]','冰壺湧出水仙粧，鏡裏風生凈土香。',64,'全唐诗/poet.song.163000.json','["冰壺湧出水仙粧，鏡裏風生凈土香。", "白表質成花受彩，黄鐘理具蕊含章。", "翩翩仰面枝分蓋，𧥄𧥄齋頭子共房。", "見說濂溪愛之酷，色塵于我自相忘。"]'),
('c198e10f-b20a-44ae-876d-89206289d968','德慶府城遶以荷池葉楙花繁時環望之紅綠無間斷號爲荷城記以唐律遺後來使君','曾丰','宋','宋诗','song-poetry','','[]','中置金城外玉池，池荷挺拔效芳菲。',64,'全唐诗/poet.song.163000.json','["中置金城外玉池，池荷挺拔效芳菲。", "葉爭以綠環三匝，花逞其紅曳四圍。", "龍國繢人供佛座，蛟宮縫氏獻仙衣。", "使君未佛且仙去，紫橐朝真紅炬歸。"]'),
('bec10af2-7f99-41f9-ba16-7f6fccaada07','龜山之孫楊子順肇慶一見相投隨至德慶謀館寓跡過從年餘辭歸鄉賦詩送行  其一','曾丰','宋','宋诗','song-poetry','','[]','誰續寂寥洙泗弦，濂溪一轉至伊川。',64,'全唐诗/poet.song.163000.json','["誰續寂寥洙泗弦，濂溪一轉至伊川。", "只今洛派從頭數，之子龜山第二傳。", "他道已融歸正道，後天猶辦入先天。", "十年二廣參皆遍，不以支離易混全。"]'),
('d738bb98-738a-4ef8-be9f-23ba4a1d5a27','龜山之孫楊子順肇慶一見相投隨至德慶謀館寓跡過從年餘辭歸鄉賦詩送行  其二','曾丰','宋','宋诗','song-poetry','','[]','吾教落南無祖師，問誰傳得祖師衣。',64,'全唐诗/poet.song.163000.json','["吾教落南無祖師，問誰傳得祖師衣。", "淵明抵掌今誠是，伯玉摇頭昨似非。", "相謝十州風月去，自擔千古聖賢歸。", "歸囊道價重于利，未必轑羹不下機。"]'),
('b663ce81-62ba-4250-ab37-a3256064ad68','呈羅叔異  其一','曾丰','宋','宋诗','song-poetry','','[]','浪把柴扉爲客開，揖餘茶速又湯催。',32,'全唐诗/poet.song.163000.json','["浪把柴扉爲客開，揖餘茶速又湯催。", "應門老走忽解意，放入江西風月來。"]'),
('4ef5d8fc-37cf-4d57-9773-fd6508451fe0','呈羅叔異  其二','曾丰','宋','宋诗','song-poetry','','[]','崆峒不合識東坡，驕氣百年猶未磨。',32,'全唐诗/poet.song.163000.json','["崆峒不合識東坡，驕氣百年猶未磨。", "今放晴烟弄寒影，安知非喜子相過。"]'),
('d3c71c48-d9d6-40ee-ba59-09c6b0be25a0','呈羅叔異  其三','曾丰','宋','宋诗','song-poetry','','[]','吾疑子亦慣乘機，乃枉華軒扣竹扉。',32,'全唐诗/poet.song.163000.json','["吾疑子亦慣乘機，乃枉華軒扣竹扉。", "不是梅花不相外，囊猶未癭若爲歸。"]'),
('ec296a77-22f3-409f-a9ad-26f1cbd30980','遣興','曾丰','宋','宋诗','song-poetry','','[]','開窗攬鏡岸烏紗，歲月崢嶸任物華。',32,'全唐诗/poet.song.163000.json','["開窗攬鏡岸烏紗，歲月崢嶸任物華。", "觸事輒灰心裏火，看書徒盎眼中花。"]'),
('8734b0bf-007a-4c3d-be67-441ee37de3c8','豫章上遊江中有道觀蓋尸堅吾遊仙之地 湧月','曾丰','宋','宋诗','song-poetry','','[]','水色月華俱受清，藏中各自有光明。',32,'全唐诗/poet.song.163000.json','["水色月華俱受清，藏中各自有光明。", "夜來相遇影相射，幻我黄冠老眼晴。"]'),
('61acf7d1-df1d-482b-af74-a553c8e66d90','豫章上遊江中有道觀蓋尸堅吾遊仙之地 濯風','曾丰','宋','宋诗','song-poetry','','[]','凈蛻凡身一羽輕，安排兩脚踏長鯨。',32,'全唐诗/poet.song.163000.json','["凈蛻凡身一羽輕，安排兩脚踏長鯨。", "忽逢一陣風吹送，直溯紫虛凌太清。"]'),
('217b0ffd-afb7-499a-a874-bb40b513c489','豫章上遊江中有道觀蓋尸堅吾遊仙之地 僊州','曾丰','宋','宋诗','song-poetry','','[]','弱水空傳三萬里，瀛洲只隔一重關。',32,'全唐诗/poet.song.163000.json','["弱水空傳三萬里，瀛洲只隔一重關。", "渡船莫傍梅花岸，岸上吾疑是世間。"]'),
('d9078df7-c61b-4c30-8270-469a82bace6c','立春','曾丰','宋','宋诗','song-poetry','','[]','羯鼓催春春尚回，况公夜擁軟紅灰。',32,'全唐诗/poet.song.163000.json','["羯鼓催春春尚回，况公夜擁軟紅灰。", "五更溫厚東南氣，煦煦妓圍深處來。"]'),
('1ec08ec2-32fc-4e17-8ef0-4d5a2e62ac30','題楊補之梅  其一','曾丰','宋','宋诗','song-poetry','','[]','風流青帝欲回春，先遣玉妃清路塵。',32,'全唐诗/poet.song.163000.json','["風流青帝欲回春，先遣玉妃清路塵。", "過眼被渠偷筆寫，雖忙猶得九分真。"]'),
('a7365e8c-5086-403f-bac7-c4cc68b0a9ef','題楊補之梅  其二','曾丰','宋','宋诗','song-poetry','','[]','竹籬茅舍養吾清，正恐人間識姓名。',32,'全唐诗/poet.song.163000.json','["竹籬茅舍養吾清，正恐人間識姓名。", "毛穎傳神偶相似，爭先快覩輒傾城。"]'),
('aacc07d3-42aa-42fd-b52c-97879b413872','陳伯紀列岫  其一','曾丰','宋','宋诗','song-poetry','','[]','一塔數椽崖半腰，工夫草草意翛翛。',32,'全唐诗/poet.song.163000.json','["一塔數椽崖半腰，工夫草草意翛翛。", "青山雖老猶兒態，邂逅吾人喜飲醪。"]'),
('fe2412b2-1e2c-4fd8-89e3-af371a1b074c','陳伯紀列岫  其二','曾丰','宋','宋诗','song-poetry','','[]','江瀕湱湱不容暑，竹杪騷騷那攬塵。',32,'全唐诗/poet.song.163000.json','["江瀕湱湱不容暑，竹杪騷騷那攬塵。", "只隔一重窗紙影，蚤分俗客與幽人。"]'),
('3bcc1b05-81a6-45ee-9dfc-84ca7d33346b','陳伯紀列岫  其三','曾丰','宋','宋诗','song-poetry','','[]','文書倥傯汗模糊，問有清凉世界無。',32,'全唐诗/poet.song.163000.json','["文書倥傯汗模糊，問有清凉世界無。", "走借主人烟雨觀，幻吾身眼入冰壺。"]'),
('ba73f654-83c9-4818-8f2b-efa903e13fd2','隨牒至南康軍呈李宰  其一','曾丰','宋','宋诗','song-poetry','','[]','蹀躞騏騮去路寬，西清太冷北門寒。',32,'全唐诗/poet.song.163000.json','["蹀躞騏騮去路寬，西清太冷北門寒。", "且將東觀編摩手，來作南康拊字官。"]'),
('e973c357-1656-4557-8d30-6f70e5fd9158','隨牒至南康軍呈李宰  其二','曾丰','宋','宋诗','song-poetry','','[]','善刀初不露鋒芒，五柳圍門琴卧堂。',32,'全唐诗/poet.song.163000.json','["善刀初不露鋒芒，五柳圍門琴卧堂。", "百里桑麻春塞眼，四時風月夜搜腸。"]'),
